func buildAgentSecurityReport(maxAge time.Duration) (agentSecurityReport, error) {
	storedReports, err := nodestate.List(maxAge)
	if err != nil {
		return agentSecurityReport{}, err
	}
	storedReports = latestStoredReportsByNode(storedReports)
	report := agentSecurityReport{
		Kind:      "meshclaw_agent_security",
		Generated: time.Now().UTC(),
	}
	now := time.Now()
	for _, stored := range storedReports {
		node := summarizeAgentSecurityNode(stored, now)
		report.Nodes = append(report.Nodes, node)
		report.Totals.Nodes++
		report.Totals.PublicListeners += len(node.PublicListeners)
		report.Totals.PublicDockerPorts += len(node.PublicDockerPorts)
		report.Totals.CronEntries += node.Schedules.CronEntries
		report.Totals.SystemdTimers += len(node.Schedules.SystemdTimers)
		report.Totals.FailedUnits += len(node.FailedUnits)
		for _, finding := range node.SecurityFindings {
			switch finding.Severity {
			case "high":
				report.Totals.HighFindings++
			case "medium":
				report.Totals.MediumFindings++
			}
			if finding.Severity == "high" || finding.Severity == "medium" {
				report.Risks = append(report.Risks, agentSecurityRisk{
					Node:     node.Node,
					Severity: finding.Severity,
					Category: finding.Category,
					Title:    finding.Title,
					Detail:   finding.Detail,
				})
			}
		}
	}
	sort.SliceStable(report.Nodes, func(i, j int) bool {
		return report.Nodes[i].Node < report.Nodes[j].Node
	})
	sort.SliceStable(report.Risks, func(i, j int) bool {
		if report.Risks[i].Severity == report.Risks[j].Severity {
			if report.Risks[i].Node == report.Risks[j].Node {
				return report.Risks[i].Title < report.Risks[j].Title
			}
			return report.Risks[i].Node < report.Risks[j].Node
		}
		return severityRank(report.Risks[i].Severity) > severityRank(report.Risks[j].Severity)
	})
	report.NextActions = agentSecurityNextActions(report)
	return report, nil
}

func summarizeAgentSecurityNode(stored nodestate.StoredReport, now time.Time) agentSecurityNode {
	report := stored.Report
	node := agentSecurityNode{
		Node:             firstNonEmpty(report.NodeName, report.Hostname),
		StoredAt:         stored.StoredAt,
		OS:               report.System.OS,
		Firewall:         report.Firewall,
		Fail2Ban:         report.Fail2Ban,
		Schedules:        report.Schedules,
		FailedUnits:      report.Health.FailedUnits,
		SecurityFindings: report.Security,
	}
	if node.Node == "" {
		node.Node = "unknown"
	}
	if !stored.StoredAt.IsZero() {
		node.AgeSeconds = int64(now.Sub(stored.StoredAt).Seconds())
	}
	for _, listener := range report.Network.Listeners {
		if listener.Public {
			node.PublicListeners = append(node.PublicListeners, listener)
		}
	}
	for _, port := range report.Docker.Ports {
		if port.Public {
			node.PublicDockerPorts = append(node.PublicDockerPorts, port)
		}
	}
	node.Summary = agentSecurityNodeSummary(node)
	return node
}

func agentSecurityNodeSummary(node agentSecurityNode) string {
	parts := []string{
		fmt.Sprintf("public listeners=%d", len(node.PublicListeners)),
		fmt.Sprintf("public Docker ports=%d", len(node.PublicDockerPorts)),
	}
	switch {
	case node.Fail2Ban.Available && node.Fail2Ban.Running:
		parts = append(parts, fmt.Sprintf("fail2ban running jails=%d", len(node.Fail2Ban.Jails)))
	case node.Fail2Ban.Available:
		parts = append(parts, "fail2ban installed but not confirmed running")
	case node.OS == "linux":
		parts = append(parts, "fail2ban unavailable")
	}
	if len(node.Firewall.Warnings) > 0 {
		parts = append(parts, fmt.Sprintf("firewall warnings=%d", len(node.Firewall.Warnings)))
	}
	if node.Schedules.CronEntries > 0 || len(node.Schedules.SystemdTimers) > 0 || len(node.Schedules.LaunchdAgents) > 0 {
		parts = append(parts, fmt.Sprintf("scheduled jobs=%d cron, %d timers, %d launchd", node.Schedules.CronEntries, len(node.Schedules.SystemdTimers), len(node.Schedules.LaunchdAgents)+len(node.Schedules.LaunchdDaemons)))
	}
	if len(node.FailedUnits) > 0 {
		parts = append(parts, fmt.Sprintf("failed units=%d", len(node.FailedUnits)))
	}
	high, medium := 0, 0
	for _, finding := range node.SecurityFindings {
		if finding.Severity == "high" {
			high++
		}
		if finding.Severity == "medium" {
			medium++
		}
	}
	if high > 0 || medium > 0 {
		parts = append(parts, fmt.Sprintf("findings=%d high, %d medium", high, medium))
	}
	return strings.Join(parts, "; ")
}

func agentSecurityNextActions(report agentSecurityReport) []string {
	var actions []string
	for _, risk := range report.Risks {
		switch risk.Category {
		case "security":
			actions = append(actions, fmt.Sprintf("Check SSH/fail2ban posture on %s before exposing more services.", risk.Node))
		case "firewall", "network", "docker":
			actions = append(actions, fmt.Sprintf("Review public listeners and firewall intent on %s.", risk.Node))
		case "systemd":
			actions = append(actions, fmt.Sprintf("Run meshclaw service-triage --hosts %s --json for failed units.", risk.Node))
		case "time":
			actions = append(actions, fmt.Sprintf("Fix time synchronization on %s before trusting schedules.", risk.Node))
		default:
			if risk.Severity == "high" {
				actions = append(actions, fmt.Sprintf("Investigate high risk on %s: %s.", risk.Node, risk.Title))
			}
		}
		if len(actions) >= 12 {
			break
		}
	}
	return appendUniqueStrings(nil, actions...)
}

func firstNSecurityFindings(values []nodestate.SecurityFinding, n int) []nodestate.SecurityFinding {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func agentInventoryPlan(args []string) error {
	jsonOut := wantsJSON(args)
	apply := false
	for _, arg := range withoutJSONFlag(args) {
		switch arg {
		case "--apply":
			apply = true
		default:
			return fmt.Errorf("usage: meshclaw agent inventory-plan [--apply] [--json]")
		}
	}
	report, err := buildAgentInventoryPlan(apply)
	if err != nil {
		return err
	}
	if jsonOut {
		return printJSON(report)
	}
	fmt.Printf("agent-inventory-plan proposals=%d apply=%t\n", len(report.Proposals), report.Apply)
	for _, proposal := range report.Proposals {
		status := "no-change"
		if proposal.Changed {
			status = "change"
		}
		fmt.Printf("- %s role=%s tags=%s confidence=%s %s\n", proposal.Node, proposal.Role, strings.Join(proposal.Tags, ","), proposal.Confidence, status)
		fmt.Printf("  reason: %s\n", proposal.Reason)
		if proposal.Command != "" {
			fmt.Printf("  command: %s\n", proposal.Command)
		}
	}
	if len(report.Applied) > 0 {
		fmt.Printf("applied overrides=%d path=%s\n", len(report.Applied), inventory.OverridesPath())
	}
	if len(report.NextActions) > 0 {
		fmt.Println("next actions:")
		for _, action := range report.NextActions {
			fmt.Println("- " + action)
		}
	}
	return nil
}

func buildAgentInventoryPlan(apply bool) (agentInventoryPlanReport, error) {
	workloads, err := buildAgentWorkloadsReport(24*time.Hour, 3)
	if err != nil {
		return agentInventoryPlanReport{}, err
	}
	current := inventory.DefaultNodes()
	currentByName := map[string]inventory.Node{}
	for _, node := range current {
		currentByName[strings.ToLower(node.Name)] = node
	}
	report := agentInventoryPlanReport{
		Kind:      "meshclaw_agent_inventory_plan",
		Generated: time.Now().UTC(),
		Apply:     apply,
	}
	for _, node := range workloads.Nodes {
		proposal := proposeInventoryFromWorkload(node, currentByName[strings.ToLower(node.Node)])
		if proposal.Node == "" {
			continue
		}
		report.Proposals = append(report.Proposals, proposal)
	}
	sort.SliceStable(report.Proposals, func(i, j int) bool {
		if report.Proposals[i].Changed == report.Proposals[j].Changed {
			return report.Proposals[i].Node < report.Proposals[j].Node
		}
		return report.Proposals[i].Changed && !report.Proposals[j].Changed
	})
	if apply {
		for _, proposal := range report.Proposals {
			if !proposal.Changed {
				continue
			}
			nodes, err := inventory.SetOverride(inventory.Node{
				Name: proposal.Node,
				Role: proposal.Role,
				Tags: proposal.Tags,
			})
			if err != nil {
				return report, err
			}
			report.Applied = nodes
		}
	}
	report.NextActions = []string{
		"Review proposals before applying on shared fleets.",
		"After applying, run meshclaw inventory-diff --json and meshclaw capability-recommend for workload placement.",
	}
	return report, nil
}

func proposeInventoryFromWorkload(node agentWorkloadNodeSummary, current inventory.Node) agentInventoryProposal {
	role, tags, reason, confidence := inferInventoryRoleTags(node)
	if role == "" {
		return agentInventoryProposal{}
	}
	tags = normalizeTagList(tags)
	currentTags := normalizeTagList(current.Tags)
	changed := current.Role != role || !sameStringSet(currentTags, tags)
	return agentInventoryProposal{
		Node:        node.Node,
		Role:        role,
		Tags:        tags,
		Reason:      reason,
		Confidence:  confidence,
		Command:     inventoryPlanCommand(node.Node, role, tags),
		Changed:     changed,
		CurrentRole: current.Role,
		CurrentTags: currentTags,
	}
}

func inferInventoryRoleTags(node agentWorkloadNodeSummary) (string, []string, string, string) {
	purposes := map[string]nodestate.WorkloadState{}
	for _, workload := range node.Workloads {
		purposes[workload.Purpose] = workload
	}
	tags := []string{node.OS}
	if node.GPUs > 0 {
		tags = append(tags, "gpu")
	}
	hasOpenWebUIContainer := workloadHasContainer(purposes["containerized_app"], "open-webui")
	switch {
	case node.OS == "darwin" && hasPurpose(purposes, "desktop_ai_or_browser"):
		tags = append(tags, "desktop", "controller")
		if hasPurpose(purposes, "file_sync") {
			tags = append(tags, "file-sync")
		}
		return "desktop-controller", tags, "macOS desktop/browser/AI app workload was observed; this node is better treated as a controller/workspace machine than a transient sync worker.", "high"
	case hasPurpose(purposes, "llm_inference") && (hasPurpose(purposes, "ai_chat_ui") || hasOpenWebUIContainer):
		tags = append(tags, "llm", "ollama", "openwebui")
		return "llm-chat-worker", tags, "LLM inference and AI chat UI were both observed in node-local workload state.", "high"
	case hasPurpose(purposes, "llm_inference"):
		tags = append(tags, "llm", "ollama")
		return "ollama-worker", tags, "Ollama/vLLM-style LLM inference was observed in node-local workload state.", "high"
	case hasPurpose(purposes, "ai_chat_ui"):
		tags = append(tags, "openwebui", "assistant-ui")
		return "assistant-ui", tags, "Open WebUI or an AI chat UI was observed in node-local workload state.", "high"
	case hasPurpose(purposes, "containerized_app") && hasPurpose(purposes, "public_network_service"):
		tags = append(tags, "docker", "public-service")
		return "app-host", tags, "Containerized apps and public listeners were observed.", "medium"
	case hasPurpose(purposes, "containerized_app"):
		tags = append(tags, "docker")
		return "container-host", tags, "Containerized apps were observed.", "medium"
	case hasPurpose(purposes, "file_sync"):
		tags = append(tags, "file-sync")
		return "sync-worker", tags, "File synchronization processes were observed.", "medium"
	case hasPurpose(purposes, "meshclaw_memory") || hasPurpose(purposes, "meshclaw_runtime"):
		tags = append(tags, "meshclaw")
		return "meshclaw-node", tags, "MeshClaw runtime or meshdb processes were observed.", "medium"
	case hasPurpose(purposes, "public_network_service"):
		tags = append(tags, "public-service")
		return "service-host", tags, "Public listeners were observed.", "low"
	default:
		return "observed-node", tags, "Node-local agent state exists but no specific product role dominated.", "low"
	}
}

func workloadHasContainer(workload nodestate.WorkloadState, name string) bool {
	name = strings.ToLower(strings.TrimSpace(name))
	for _, container := range workload.Containers {
		if strings.Contains(strings.ToLower(container), name) {
			return true
		}
	}
	for _, example := range workload.Examples {
		if strings.Contains(strings.ToLower(example), name) {
			return true
		}
	}
	return false
}

func hasPurpose(values map[string]nodestate.WorkloadState, purpose string) bool {
	_, ok := values[purpose]
	return ok
}

func inventoryPlanCommand(node, role string, tags []string) string {
	parts := []string{"meshclaw", "inventory-override", "set", shellQuote(node), "--role", shellQuote(role)}
	for _, tag := range tags {
		parts = append(parts, "--tag", shellQuote(tag))
	}
	return strings.Join(parts, " ")
}

func normalizeTagList(tags []string) []string {
	seen := map[string]bool{}
	var out []string
	for _, tag := range tags {
		tag = strings.ToLower(strings.TrimSpace(tag))
		if tag == "" || seen[tag] {
			continue
		}
		seen[tag] = true
		out = append(out, tag)
	}
	sort.Strings(out)
	return out
}

func sameStringSet(a, b []string) bool {
	a = normalizeTagList(a)
	b = normalizeTagList(b)
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

func buildAgentChangesReport(node string) (agentChangesReport, error) {
	nodes, err := agentChangeNodes(node)
	if err != nil {
		return agentChangesReport{}, err
	}
	report := agentChangesReport{Kind: "meshclaw_agent_changes", Generated: time.Now().UTC()}
	for _, name := range nodes {
		history, err := nodestate.TailHistory(name, 2)
		if err != nil {
			return agentChangesReport{}, err
		}
		if len(history) < 2 {
			continue
		}
		change := compareAgentReports(history[0], history[1])
		if change.Node != "" {
			report.Nodes = append(report.Nodes, change)
		}
	}
	sort.SliceStable(report.Nodes, func(i, j int) bool {
		return report.Nodes[i].Node < report.Nodes[j].Node
	})
	return report, nil
}

func agentChangeNodes(node string) ([]string, error) {
	node = strings.TrimSpace(node)
	if node != "" && !strings.EqualFold(node, "all") {
		return []string{node}, nil
	}
	reports, err := nodestate.List(0)
	if err != nil {
		return nil, err
	}
	var nodes []string
	seen := map[string]bool{}
	for _, stored := range reports {
		name := firstNonEmpty(stored.Report.NodeName, stored.Report.Hostname)
		if name == "" || seen[name] {
			continue
		}
		seen[name] = true
		nodes = append(nodes, name)
	}
	sort.Strings(nodes)
	return nodes, nil
}

func compareAgentReports(before, after nodestate.StoredReport) agentNodeChange {
	node := firstNonEmpty(after.Report.NodeName, after.Report.Hostname, before.Report.NodeName, before.Report.Hostname)
	change := agentNodeChange{
		Node:                    node,
		From:                    before.StoredAt,
		To:                      after.StoredAt,
		Load1Delta:              roundFloat1(after.Report.System.Load1 - before.Report.System.Load1),
		MemoryPctDelta:          roundFloat1(after.Report.System.MemoryPct - before.Report.System.MemoryPct),
		DiskPctDelta:            roundFloat1(after.Report.System.DiskPct - before.Report.System.DiskPct),
		AddedWorkloads:          sortedSetDifference(workloadPurposeSet(after.Report.Workloads), workloadPurposeSet(before.Report.Workloads)),
		RemovedWorkloads:        sortedSetDifference(workloadPurposeSet(before.Report.Workloads), workloadPurposeSet(after.Report.Workloads)),
		NewSecurityFindings:     sortedSetDifference(securityFindingSet(after.Report.Security), securityFindingSet(before.Report.Security)),
		ClearedSecurityFindings: sortedSetDifference(securityFindingSet(before.Report.Security), securityFindingSet(after.Report.Security)),
	}
	change.Summary = agentChangeSummary(change)
	return change
}

func workloadPurposeSet(values []nodestate.WorkloadState) map[string]bool {
	out := map[string]bool{}
	for _, value := range values {
		if value.Purpose != "" {
			out[value.Purpose] = true
		}
	}
	return out
}

func securityFindingSet(values []nodestate.SecurityFinding) map[string]bool {
	out := map[string]bool{}
	for _, value := range values {
		key := strings.TrimSpace(value.Severity + ":" + value.Category + ":" + value.Title)
		if key != "::" {
			out[key] = true
		}
	}
	return out
}

func sortedSetDifference(left, right map[string]bool) []string {
	var out []string
	for value := range left {
		if !right[value] {
			out = append(out, value)
		}
	}
	sort.Strings(out)
	return out
}

func agentChangeSummary(change agentNodeChange) string {
	var parts []string
	if change.Load1Delta != 0 {
		parts = append(parts, fmt.Sprintf("load %.1f", change.Load1Delta))
	}
	if change.MemoryPctDelta != 0 {
		parts = append(parts, fmt.Sprintf("memory %.1f%%", change.MemoryPctDelta))
	}
	if change.DiskPctDelta != 0 {
		parts = append(parts, fmt.Sprintf("disk %.1f%%", change.DiskPctDelta))
	}
	if len(change.AddedWorkloads) > 0 {
		parts = append(parts, "new workloads "+strings.Join(change.AddedWorkloads, ","))
	}
	if len(change.NewSecurityFindings) > 0 {
		parts = append(parts, fmt.Sprintf("%d new risks", len(change.NewSecurityFindings)))
	}
	if len(parts) == 0 {
		return "No material change in the last two samples."
	}
	return "Change: " + strings.Join(parts, "; ") + "."
}

func agentWorkloadNextActions(report agentWorkloadsReport) []string {
	var actions []string
	add := func(action string) {
		action = strings.TrimSpace(action)
		if action == "" {
			return
		}
		for _, existing := range actions {
			if existing == action {
				return
			}
		}
		actions = append(actions, action)
	}
	for _, risk := range report.Risks {
		lower := strings.ToLower(risk.Title + " " + risk.Detail)
		switch {
		case strings.Contains(lower, "fail2ban"):
			add("Check SSH exposure and fail2ban posture on " + risk.Node + ": run meshclaw service-check " + risk.Node + " fail2ban, then decide whether to install/enable fail2ban or confirm another protection layer.")
		case strings.Contains(lower, "system clock"):
			add("Fix or verify time synchronization on " + risk.Node + ": inspect timedatectl/chrony/systemd-timesyncd before trusting scheduled automation.")
		case strings.Contains(lower, "failed systemd"):
			add("Triage failed systemd units on " + risk.Node + ": run meshclaw service-triage --hosts " + risk.Node + " --json.")
		case strings.Contains(lower, "docker ports"):
			add("Review public Docker port exposure on " + risk.Node + ": compare open ports with intended services before exposing to users.")
		case strings.Contains(lower, "public listening"):
			add("Review public listeners on " + risk.Node + ": confirm each public port is intentional or restrict it behind Tailscale/firewall.")
		case strings.Contains(lower, "unknown high-resource"):
			add("Classify the high-resource unknown process on " + risk.Node + " and add a workload rule if it is legitimate.")
		case strings.Contains(lower, "updates available"):
			add("Schedule package update review for " + risk.Node + "; do not auto-upgrade without maintenance window approval.")
		}
	}
	for _, node := range report.Nodes {
		if node.MemoryPct >= 90 {
			add("Investigate memory pressure on " + node.Node + ": check top processes and decide whether to restart or move workload.")
		}
		if node.DiskPct >= 80 {
			add("Investigate disk usage on " + node.Node + ": run meshclaw disk-investigate " + node.Node + " before cleanup.")
		}
	}
	if len(actions) == 0 {
		add("No immediate action from cached workload state. Refresh with meshclaw agent pull <hosts> or meshclaw monitor-check before making changes.")
	}
	if len(actions) > 12 {
		actions = actions[:12]
	}
	return actions
}

func naturalWorkloadSummary(node agentWorkloadNodeSummary) string {
	var parts []string
	for _, workload := range firstNWorkloads(node.Workloads, 4) {
		label := workloadPurposeLabel(workload.Purpose)
		if label == "" {
			continue
		}
		detail := label
		if workload.CPUPct > 0 || workload.MemPct > 0 {
			detail += fmt.Sprintf("(cpu %.1f%%, mem %.1f%%)", workload.CPUPct, workload.MemPct)
		} else if len(workload.Containers) > 0 {
			detail += fmt.Sprintf("(%d containers)", len(workload.Containers))
		} else if len(workload.Ports) > 0 {
			detail += fmt.Sprintf("(%d public ports)", len(workload.Ports))
		}
		parts = append(parts, detail)
	}
	if len(parts) == 0 {
		return "No clear workload classification yet; inspect top processes and listeners."
	}
	return "Current use: " + strings.Join(parts, ", ") + "."
}

func workloadPurposeLabel(purpose string) string {
	switch purpose {
	case "llm_inference":
		return "LLM inference"
	case "ai_chat_ui":
		return "AI chat UI"
	case "meshclaw_monitoring":
		return "MeshClaw monitoring"
	case "meshclaw_runtime":
		return "MeshClaw runtime"
	case "meshclaw_memory":
		return "MeshClaw memory"
	case "remote_execution":
		return "remote execution"
	case "file_sync":
		return "file sync"
	case "containerized_app":
		return "containerized apps"
	case "container_runtime":
		return "container runtime"
	case "public_network_service":
		return "public network services"
	case "database":
		return "database"
	case "web_proxy":
		return "web proxy"
	case "app_runtime":
		return "application runtime"
	case "network_remote_access":
		return "remote access/networking"
	case "ssh_access":
		return "SSH access"
	case "system_service":
		return "system services"
	case "system_observer":
		return "system observation"
	default:
		return purpose
	}
}

func topResourceProcesses(processes []nodestate.ProcessState, limit int) []nodestate.ProcessState {
	if limit <= 0 || len(processes) == 0 {
		return nil
	}
	out := make([]nodestate.ProcessState, 0, len(processes))
	for _, process := range processes {
		if isAgentCollectionProcess(process) {
			continue
		}
		out = append(out, process)
	}
	sort.SliceStable(out, func(i, j int) bool {
		left := out[i].CPUPct + out[i].MemPct
		right := out[j].CPUPct + out[j].MemPct
		return left > right
	})
	if len(out) > limit {
		out = out[:limit]
	}
	return out
}

func operatorVisibleWorkloads(workloads []nodestate.WorkloadState) []nodestate.WorkloadState {
	if len(workloads) == 0 {
		return nil
	}
	out := make([]nodestate.WorkloadState, 0, len(workloads))
	for _, workload := range workloads {
		if workload.Purpose == "system_observer" {
			continue
		}
		if workload.Purpose == "meshclaw_runtime" && len(workload.Examples) == 1 && strings.Contains(strings.ToLower(workload.Examples[0]), "agent collect") {
			continue
		}
		out = append(out, workload)
	}
	if len(out) == 0 {
		return workloads
	}
	return out
}

func isAgentCollectionProcess(process nodestate.ProcessState) bool {
	command := strings.ToLower(strings.TrimSpace(process.Command))
	if command == "" {
		return false
	}
	return strings.Contains(command, "meshclaw agent collect") ||
		strings.HasPrefix(command, "ps -eo ") ||
		strings.Contains(command, " ps -eo ") ||
		strings.HasPrefix(command, "pgrep ") ||
		strings.Contains(command, " pgrep ") ||
		strings.Contains(command, "journalctl -") ||
		strings.Contains(command, "systemctl is-") ||
		strings.Contains(command, "docker exec argos-openwebui-proxy")
}

func latestStoredReportsByNode(reports []nodestate.StoredReport) []nodestate.StoredReport {
	if len(reports) <= 1 {
		return reports
	}
	byNode := map[string]nodestate.StoredReport{}
	for _, stored := range reports {
		name := firstNonEmpty(stored.Report.NodeName, stored.Report.Hostname)
		if strings.TrimSpace(name) == "" {
			continue
		}
		existing, ok := byNode[name]
		if !ok || stored.StoredAt.After(existing.StoredAt) {
			byNode[name] = stored
		}
	}
	out := make([]nodestate.StoredReport, 0, len(byNode))
	for _, stored := range byNode {
		out = append(out, stored)
	}
	sort.SliceStable(out, func(i, j int) bool {
		left := firstNonEmpty(out[i].Report.NodeName, out[i].Report.Hostname)
		right := firstNonEmpty(out[j].Report.NodeName, out[j].Report.Hostname)
		return left < right
	})
	return out
}

func firstNWorkloads(values []nodestate.WorkloadState, limit int) []nodestate.WorkloadState {
	if limit <= 0 || len(values) <= limit {
		return values
	}
	return values[:limit]
}

func firstNAgentWorkloadRisks(values []agentWorkloadFleetRisk, limit int) []agentWorkloadFleetRisk {
	if limit <= 0 || len(values) <= limit {
		return values
	}
	return values[:limit]
}

func severityRank(severity string) int {
	switch strings.ToLower(severity) {
	case "critical":
		return 4
	case "high":
		return 3
	case "medium":
		return 2
	case "low":
		return 1
	default:
		return 0
	}
}

func roundFloat1(value float64) float64 {
	if value == 0 {
		return 0
	}
	if value < 0 {
		return float64(int(value*10-0.5)) / 10
	}
	return float64(int(value*10+0.5)) / 10
}

func defaultAgentMaxHistory() int {
	value := strings.TrimSpace(os.Getenv("MESHCLAW_AGENT_MAX_HISTORY"))
	if value == "" {
		return 1440
	}
	n, err := strconv.Atoi(value)
	if err != nil || n < 1 {
		return 1440
	}
	return n
}

func remoteAgentCollectCommand(opts nodestate.Options) string {
	parts := []string{"agent", "collect", "--json", "--top", strconv.Itoa(opts.TopProcesses)}
	if len(opts.Services) > 0 {
		parts = append(parts, "--services", strings.Join(opts.Services, ","))
	}
	if opts.Timeout > 0 {
		parts = append(parts, "--timeout", opts.Timeout.String())
	}
	quoted := make([]string, 0, len(parts))
	for _, part := range parts {
		quoted = append(quoted, shellQuote(part))
	}
	args := strings.Join(quoted, " ")
	return `if [ -n "$HOME" ] && [ -x "$HOME/.local/bin/meshclaw" ]; then "$HOME/.local/bin/meshclaw" ` + args + `; elif [ -n "$HOME" ] && [ -x "$HOME/bin/meshclaw" ]; then "$HOME/bin/meshclaw" ` + args + `; elif [ -x /home/meshclaw/.local/bin/meshclaw ]; then /home/meshclaw/.local/bin/meshclaw ` + args + `; elif [ -x /home/meshclaw/bin/meshclaw ]; then /home/meshclaw/bin/meshclaw ` + args + `; elif [ -x /tmp/meshclaw-agent-test ]; then /tmp/meshclaw-agent-test ` + args + `; elif command -v meshclaw >/dev/null 2>&1; then meshclaw ` + args + `; else echo '{"error":"meshclaw not found"}'; exit 127; fi`
}

func parseRemoteAgentCollect(stdout string) (nodestate.Report, error) {
	stdout = strings.TrimSpace(stdout)
	var wrapped agentCollectOutput
	if err := json.Unmarshal([]byte(stdout), &wrapped); err == nil && wrapped.Report.Kind == nodestate.ReportKind {
		return wrapped.Report, nil
	}
	var report nodestate.Report
	if err := json.Unmarshal([]byte(stdout), &report); err == nil && report.Kind == nodestate.ReportKind {
		return report, nil
	}
	return nodestate.Report{}, fmt.Errorf("remote output did not contain a node report")
}

func parseAgentCLIOptions(args []string, allowRun bool) (agentCLIOptions, error) {
	opts := agentCLIOptions{
		JSON: wantsJSON(args),
		Collect: nodestate.Options{
			TopProcesses: 8,
			Timeout:      3 * time.Second,
		},
	}
	for i := 0; i < len(args); i++ {
		switch args[i] {
		case "--json", "-json":
		case "--store":
			opts.StoreState = true
		case "--evidence":
			opts.StoreEvidence = true
		case "--history":
			opts.AppendHistory = true
		case "--no-history":
			opts.AppendHistory = false
		case "--max-history":
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--max-history requires a value")
			}
			n, err := parsePositiveInt(args[i], "--max-history")
			if err != nil {
				return opts, err
			}
			opts.MaxHistory = n
		case "--once":
			if !allowRun {
				return opts, fmt.Errorf("--once is only valid for agent run")
			}
			opts.Once = true
		case "--interval":
			if !allowRun {
				return opts, fmt.Errorf("--interval is only valid for agent run")
			}
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--interval requires a duration")
			}
			interval, err := time.ParseDuration(args[i])
			if err != nil {
				if seconds, convErr := strconv.Atoi(args[i]); convErr == nil && seconds > 0 {
					interval = time.Duration(seconds) * time.Second
				} else {
					return opts, fmt.Errorf("invalid --interval: %s", args[i])
				}
			}
			opts.Interval = interval
		case "--top":
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--top requires a value")
			}
			n, err := parsePositiveInt(args[i], "--top")
			if err != nil {
				return opts, err
			}
			opts.Collect.TopProcesses = n
		case "--services":
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--services requires a comma-separated value")
			}
			opts.Collect.Services = splitCSV(args[i])
		case "--timeout":
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--timeout requires a duration")
			}
			timeout, err := time.ParseDuration(args[i])
			if err != nil {
				return opts, fmt.Errorf("invalid --timeout: %s", args[i])
			}
			if timeout < time.Second {
				return opts, fmt.Errorf("--timeout must be at least 1s")
			}
			opts.Collect.Timeout = timeout
		default:
			return opts, fmt.Errorf("unknown agent option %q", args[i])
		}
	}
	return opts, nil
}

func runAgentCollectOnce(opts agentCLIOptions) error {
	if opts.AppendHistory && opts.MaxHistory == 0 {
		opts.MaxHistory = defaultAgentMaxHistory()
	}
	report := nodestate.Collect(context.Background(), opts.Collect)
	var stored nodestate.StoredReport
	var storeErr error
	if opts.StoreState {
		stored, storeErr = nodestate.StoreWithOptions(report, nodestate.StoreOptions{AppendHistory: opts.AppendHistory, MaxHistory: opts.MaxHistory})
	}
	var record evidence.Record
	var evidenceErr error
	if opts.StoreEvidence {
		record, evidenceErr = evidence.Store("agent-collect", report.NodeName, fmt.Sprintf("cpu=%d mem=%.1f disk=%.1f findings=%d", report.System.CPUCount, report.System.MemoryPct, report.System.DiskPct, len(report.Security)), report)
	}
	if opts.JSON {
		output := agentCollectOutput{
			Report:        report,
			StoreError:    errString(storeErr),
			EvidenceError: errString(evidenceErr),
		}
		if opts.StoreState && storeErr == nil {
			output.Stored = &stored
		}
		if opts.StoreEvidence && evidenceErr == nil {
			output.Evidence = &record
		}
		return printJSON(output)
	}
	fmt.Printf("node=%s os=%s/%s cpu=%d mem=%.1f%% disk=%.1f%% docker=%t errors=%d findings=%d\n",
		report.NodeName,
		report.System.OS,
		report.System.Arch,
		report.System.CPUCount,
		report.System.MemoryPct,
		report.System.DiskPct,
		report.Docker.Available,
		len(report.Errors),
		len(report.Security),
	)
	if len(report.GPUs) > 0 {
		fmt.Printf("gpus=%d\n", len(report.GPUs))
	}
	if len(report.Services) > 0 {
		for _, service := range report.Services {
			fmt.Printf("service=%s active=%s state=%s error=%s\n", service.Name, service.Active, service.State, service.Error)
		}
	}
	if opts.StoreState {
		if storeErr != nil {
			fmt.Printf("state_store_error=%v\n", storeErr)
		} else {
			fmt.Printf("state=%s\n", stored.StatePath)
		}
	}
	if opts.StoreEvidence {
		printEvidenceStoreStatus(record, evidenceErr)
	}
	return nil
}

func monitorAgent(args []string) error {
	interval := 5 * time.Minute
	hygieneEnabled := false
	filteredArgs := make([]string, 0, len(args))
	for _, arg := range args {
		if arg == "--hygiene" {
			hygieneEnabled = true
			continue
		}
		filteredArgs = append(filteredArgs, arg)
	}
	if len(filteredArgs) > 1 {
		return fmt.Errorf("usage: meshclaw monitor-agent [interval] [--hygiene]")
	}
	if len(filteredArgs) == 1 {
		parsed, err := time.ParseDuration(filteredArgs[0])
		if err != nil {
			return fmt.Errorf("invalid interval: %s", filteredArgs[0])
		}
		if parsed < 10*time.Second {
			return fmt.Errorf("interval must be at least 10s")
		}
		interval = parsed
	}

	cfg := monitor.DefaultConfig()
	cfg.CheckInterval = interval
	m, err := monitor.New(cfg)
	if err != nil {
		return err
	}

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, os.Interrupt, syscall.SIGTERM)
	fmt.Printf("meshclaw monitor-agent interval=%s hygiene=%t\n", interval, hygieneEnabled)

	runOnce := func() {
		states := m.CheckAll()
		alerts := m.DetectAlerts()
		var hygieneReports []hygiene.Report
		if hygieneEnabled {
			for name, state := range states {
				if state == nil || !state.Online {
					continue
				}
				report := hygiene.ScanHost(name)
				if report.Status == "findings" || report.Status == "failed" {
					hygieneReports = append(hygieneReports, report)
				}
			}
		}
		record, storeErr := evidence.Store("monitor-agent", "fleet", fmt.Sprintf("alerts=%d hygiene_findings=%d", len(alerts), len(hygieneReports)), monitorAgentOutput{States: states, Alerts: alerts, Hygiene: hygieneReports})
		fmt.Printf("monitor-agent check nodes=%d alerts=%d", len(states), len(alerts))
		if hygieneEnabled {
			fmt.Printf(" hygiene_findings=%d", len(hygieneReports))
		}
		if storeErr != nil {
			fmt.Printf(" evidence_error=%v", storeErr)
		} else {
			fmt.Printf(" evidence=%s", record.StoredAt)
		}
		fmt.Println()
		for _, alert := range alerts {
			fmt.Printf("- [%s] %s %s: %s\n", alert.Level, alert.Node, alert.Type, alert.Message)
		}
	}

	runOnce()
	ticker := time.NewTicker(interval)
	defer ticker.Stop()
	for {
		select {
		case <-ticker.C:
			runOnce()
		case <-stop:
			fmt.Println("meshclaw monitor-agent stopped")
			return nil
		}
	}
}

