func architecture(args []string) error {
	jsonOut := wantsJSON(args)
	args = withoutJSONFlag(args)
	if len(args) != 0 {
		return fmt.Errorf("usage: meshclaw architecture [--json]")
	}
	report := productArchitectureReport()
	if jsonOut {
		return printJSON(report)
	}
	fmt.Println(report["one_sentence"])
	fmt.Println()
	fmt.Println("Layers:")
	for _, layer := range report["layers"].([]map[string]interface{}) {
		fmt.Printf("- %s: %s\n", layer["name"], layer["owns"])
	}
	fmt.Println()
	fmt.Println("Modes:")
	for _, mode := range report["modes"].([]map[string]interface{}) {
		fmt.Printf("- %s: %s\n", mode["purpose"], mode["surface"])
	}
	fmt.Println()
	fmt.Println("Next build order:")
	for _, item := range report["next_build_order"].([]string) {
		fmt.Println("- " + item)
	}
	fmt.Println()
	fmt.Println("See: docs/ARCHITECTURE_2026-05-23.md")
	return nil
}

