func metricsCommand(args []string) error {
	if len(args) == 0 {
		fmt.Println("Usage: meshclaw metrics <subcommand>")
		fmt.Println("")
		fmt.Println("Subcommands:")
		fmt.Println("  cpu       Query CPU usage across fleet")
		fmt.Println("  memory    Query memory usage across fleet")
		fmt.Println("  disk      Query disk usage across fleet")
		fmt.Println("  load      Query load average across fleet")
		fmt.Println("  all       Query all metrics")
		fmt.Println("  query     Run custom PromQL query")
		fmt.Println("  servers   List configured Prometheus servers")
		fmt.Println("  add       Add a Prometheus server")
		fmt.Println("  remove    Remove a Prometheus server")
		fmt.Println("")
		fmt.Println("Flags:")
		fmt.Println("  --server <name>  Use specific Prometheus server")
		fmt.Println("  --json           Output as JSON")
		return nil
	}

	client, err := prometheus.NewClient()
	if err != nil {
		return fmt.Errorf("failed to create prometheus client: %w", err)
	}

	var server string
	jsonOutput := false
	subArgs := []string{}
	for i := 0; i < len(args); i++ {
		if args[i] == "--server" && i+1 < len(args) {
			server = args[i+1]
			i++
		} else if args[i] == "--json" {
			jsonOutput = true
		} else {
			subArgs = append(subArgs, args[i])
		}
	}

	if len(subArgs) == 0 {
		return fmt.Errorf("missing subcommand")
	}

	switch subArgs[0] {
	case "cpu":
		resp, err := client.CPU(server)
		if err != nil {
			return err
		}
		return metricsQueryPrint(resp, jsonOutput)
	case "memory", "mem":
		resp, err := client.Memory(server)
		if err != nil {
			return err
		}
		return metricsQueryPrint(resp, jsonOutput)
	case "disk":
		resp, err := client.Disk(server)
		if err != nil {
			return err
		}
		return metricsQueryPrint(resp, jsonOutput)
	case "load":
		resp, err := client.Load(server)
		if err != nil {
			return err
		}
		return metricsQueryPrint(resp, jsonOutput)
	case "all":
		return metricsAllPrint(client, server, jsonOutput)
	case "query":
		if len(subArgs) < 2 {
			return fmt.Errorf("usage: meshclaw metrics query <promql>")
		}
		query := strings.Join(subArgs[1:], " ")
		resp, err := client.CustomQuery(query, server, 0)
		if err != nil {
			return err
		}
		return metricsQueryPrint(resp, jsonOutput)
	case "servers":
		return metricsServersList(client, jsonOutput)
	case "add":
		if len(subArgs) < 3 {
			return fmt.Errorf("usage: meshclaw metrics add <name> <url> [label] [--default]")
		}
		name := subArgs[1]
		url := subArgs[2]
		label := name
		if len(subArgs) > 3 && !strings.HasPrefix(subArgs[3], "--") {
			label = subArgs[3]
		}
		setDefault := false
		for _, a := range subArgs {
			if a == "--default" {
				setDefault = true
			}
		}
		if err := client.AddServer(name, url, label, setDefault); err != nil {
			return err
		}
		fmt.Printf("Added Prometheus server '%s' (%s)\n", name, url)
		return nil
	case "remove":
		if len(subArgs) < 2 {
			return fmt.Errorf("usage: meshclaw metrics remove <name>")
		}
		if err := client.RemoveServer(subArgs[1]); err != nil {
			return err
		}
		fmt.Printf("Removed Prometheus server '%s'\n", subArgs[1])
		return nil
	case "default":
		if len(subArgs) < 2 {
			return fmt.Errorf("usage: meshclaw metrics default <name>")
		}
		if err := client.SetDefault(subArgs[1]); err != nil {
			return err
		}
		fmt.Printf("Set default Prometheus server to '%s'\n", subArgs[1])
		return nil
	default:
		return fmt.Errorf("unknown subcommand: %s", subArgs[0])
	}
}

func metricsQueryPrint(resp *prometheus.MetricsResponse, jsonOutput bool) error {
	if jsonOutput {
		return printJSON(resp)
	}
	fmt.Printf("=== %s ===\n", strings.ToUpper(resp.Metric))
	for _, n := range resp.Nodes {
		status := ""
		if n.Status == "high" {
			status = " ⚠️"
		}
		fmt.Printf("%-12s %8.2f%%%s\n", n.Node, n.Value, status)
	}
	if len(resp.Alerts) > 0 {
		fmt.Println("\nAlerts:")
		for _, a := range resp.Alerts {
			fmt.Printf("  - %s\n", a)
		}
	}
	return nil
}

func metricsAllPrint(client *prometheus.Client, server string, jsonOutput bool) error {
	results, err := client.All(server)
	if err != nil {
		return err
	}
	if jsonOutput {
		return printJSON(results)
	}
	for metric, resp := range results {
		fmt.Printf("\n=== %s ===\n", strings.ToUpper(metric))
		for _, n := range resp.Nodes {
			status := ""
			if n.Status == "high" {
				status = " ⚠️"
			}
			fmt.Printf("%-12s %8.2f%%%s\n", n.Node, n.Value, status)
		}
	}
	return nil
}

func metricsServersList(client *prometheus.Client, jsonOutput bool) error {
	servers := client.ListServers()
	if jsonOutput {
		return printJSON(servers)
	}
	fmt.Println("Prometheus Servers:")
	for _, s := range servers {
		def := ""
		if s.IsDefault {
			def = " (default)"
		}
		fmt.Printf("  %-10s %s [%s]%s\n", s.Name, s.URL, s.Label, def)
	}
	return nil
}

func monitorCheck(args []string) error {
	output, record, storeErr, err := collectMonitorCheckFresh()
	if err != nil {
		return err
	}
	_ = writeMonitorCheckCache(output, record, storeErr)
	if wantsJSON(args) {
		return printJSON(map[string]interface{}{"states": output.States, "alerts": output.Alerts, "evidence": record, "store_error": errString(storeErr)})
	}
	printMonitorCheckText(output.States, output.Alerts)
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

func collectMonitorCheckFresh() (monitorCheckOutput, evidence.Record, error, error) {
	m, err := monitor.New(monitor.DefaultConfig())
	if err != nil {
		return monitorCheckOutput{}, evidence.Record{}, nil, err
	}
	states := m.CheckAll()
	mergeAgentStateReports(states, agentStateTTL())
	alerts := m.DetectAlerts()
	output := monitorCheckOutput{States: states, Alerts: alerts}
	record, storeErr := evidence.Store("monitor-check", "fleet", fmt.Sprintf("alerts=%d", len(alerts)), output)
	return output, record, storeErr, nil
}

func agentStateTTL() time.Duration {
	value := strings.TrimSpace(os.Getenv("MESHCLAW_AGENT_STATE_TTL"))
	if value == "" {
		return 15 * time.Minute
	}
	if duration, err := time.ParseDuration(value); err == nil && duration > 0 {
		return duration
	}
	if seconds, err := strconv.ParseFloat(value, 64); err == nil && seconds > 0 {
		return time.Duration(seconds * float64(time.Second))
	}
	return 15 * time.Minute
}

func mergeAgentStateReports(states map[string]*monitor.NodeState, maxAge time.Duration) {
	reports, err := nodestate.List(maxAge)
	if err != nil {
		return
	}
	for _, stored := range reports {
		state := monitorStateFromNodeReport(stored.Report, stored.StoredAt)
		if state == nil {
			continue
		}
		existing := states[state.Name]
		if existing == nil || !existing.Online || existing.Error != "" || existing.LastCheck.Before(state.LastCheck) {
			states[state.Name] = state
		}
	}
}

func monitorStateFromNodeReport(report nodestate.Report, storedAt time.Time) *monitor.NodeState {
	name := strings.TrimSpace(firstNonEmpty(report.NodeName, report.Hostname))
	if name == "" {
		return nil
	}
	if storedAt.IsZero() {
		storedAt = report.CollectedAt
	}
	gpuUsage, gpuMemory := aggregateGPUState(report.GPUs)
	var services []string
	for _, service := range report.Services {
		status := strings.TrimSpace(service.Active)
		if service.State != "" {
			status = strings.TrimSpace(status + "/" + service.State)
		}
		if status == "" && service.Error != "" {
			status = "error"
		}
		if status != "" {
			services = append(services, service.Name+"="+status)
		}
	}
	return &monitor.NodeState{
		Name:      name,
		Online:    true,
		Memory:    report.System.MemoryPct,
		Disk:      report.System.DiskPct,
		LastCheck: storedAt,
		GPUUsage:  gpuUsage,
		GPUMemory: gpuMemory,
		Services:  services,
	}
}

func aggregateGPUState(gpus []nodestate.GPUState) (float64, float64) {
	if len(gpus) == 0 {
		return 0, 0
	}
	var usage float64
	var totalMem, usedMem int64
	for _, gpu := range gpus {
		usage += gpu.Utilization
		totalMem += gpu.MemoryTotalMB
		usedMem += gpu.MemoryUsedMB
	}
	memPct := 0.0
	if totalMem > 0 {
		memPct = float64(usedMem) / float64(totalMem) * 100
	}
	return usage / float64(len(gpus)), memPct
}

func printMonitorCheckText(states map[string]*monitor.NodeState, alerts []monitor.Alert) {
	fmt.Printf("%-10s %-7s %-15s %6s %6s %s\n", "NODE", "ONLINE", "IP", "DISK", "MEM", "ERROR")
	for _, node := range inventory.DefaultNodes() {
		state := states[node.Name]
		if state == nil {
			continue
		}
		fmt.Printf("%-10s %-7t %-15s %5.1f%% %5.1f%% %s\n", state.Name, state.Online, state.IP, state.Disk, state.Memory, state.Error)
	}
	if len(alerts) > 0 {
		fmt.Println("alerts:")
		for _, alert := range alerts {
			fmt.Printf("- [%s] %s %s: %s\n", alert.Level, alert.Node, alert.Type, alert.Message)
		}
	}
}

func monitorCheckCachePath() string {
	home, err := os.UserHomeDir()
	if err != nil || strings.TrimSpace(home) == "" {
		return filepath.Join(".meshclaw", "cache", "monitor-check.json")
	}
	return filepath.Join(home, ".meshclaw", "cache", "monitor-check.json")
}

func writeMonitorCheckCache(output monitorCheckOutput, record evidence.Record, storeErr error) error {
	path := monitorCheckCachePath()
	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
		return err
	}
	payload := monitorCheckCache{
		Kind:       "meshclaw_monitor_check_cache",
		CreatedAt:  time.Now(),
		Output:     output,
		Evidence:   record,
		StoreError: errString(storeErr),
	}
	data, err := json.MarshalIndent(payload, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o600)
}

func readMonitorCheckCache() (monitorCheckCache, error) {
	data, err := os.ReadFile(monitorCheckCachePath())
	if err != nil {
		return monitorCheckCache{}, err
	}
	var payload monitorCheckCache
	if err := json.Unmarshal(data, &payload); err != nil {
		return monitorCheckCache{}, err
	}
	if payload.Output.States == nil {
		return monitorCheckCache{}, fmt.Errorf("monitor cache has no states")
	}
	return payload, nil
}

func routerMonitorCacheTTL() time.Duration {
	value := strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_MONITOR_CACHE_TTL"))
	if value == "" {
		return 30 * time.Minute
	}
	if seconds, err := strconv.ParseFloat(value, 64); err == nil {
		if seconds <= 0 {
			return 0
		}
		return time.Duration(seconds * float64(time.Second))
	}
	if duration, err := time.ParseDuration(value); err == nil && duration > 0 {
		return duration
	}
	return 30 * time.Minute
}

func monitorCheckFromCacheOrFresh(ttl time.Duration, forceFresh bool) (monitorCheckOutput, evidence.Record, string, bool, error) {
	if !forceFresh {
		if cached, err := readMonitorCheckCache(); err == nil {
			return cached.Output, cached.Evidence, cached.StoreError, true, nil
		}
	}
	output, record, storeErr, err := collectMonitorCheckFresh()
	if err != nil {
		if cached, cacheErr := readMonitorCheckCache(); cacheErr == nil {
			return cached.Output, cached.Evidence, firstNonEmpty(cached.StoreError, errString(storeErr)), true, nil
		}
		return monitorCheckOutput{}, evidence.Record{}, errString(storeErr), false, err
	}
	_ = writeMonitorCheckCache(output, record, storeErr)
	return output, record, errString(storeErr), false, nil
}

func monitorCheckForRouter(target string, ttl time.Duration, forceFresh bool) (monitorCheckOutput, evidence.Record, string, bool, bool, error) {
	if strings.TrimSpace(target) != "" && !forceFresh {
		if cached, err := readMonitorCheckCache(); err == nil && cached.Output.States[target] != nil {
			freshEnough := !cached.CreatedAt.IsZero() && ttl > 0 && time.Since(cached.CreatedAt) <= ttl
			return cached.Output, cached.Evidence, cached.StoreError, true, !freshEnough, nil
		}
	}
	output, record, storeErr, fromCache, err := monitorCheckFromCacheOrFresh(ttl, forceFresh)
	return output, record, storeErr, fromCache, false, err
}

func wantsFreshMonitorStatus(message string) bool {
	lower := strings.ToLower(message)
	return containsAny(lower, "fresh", "refresh", "live", "rescan", "force", "새로 스캔", "새로 확인", "갱신", "강제로", "실시간")
}

func wantsFreshAgentReport(message string) bool {
	lower := strings.ToLower(message)
	return containsAny(lower,
		"fresh agent", "refresh agent", "pull agent", "collect now", "rescan agents",
		"agent 새로", "에이전트 새로", "새로 수집", "다시 수집", "전체 재수집", "실시간 수집",
	)
}

func shouldRefreshAgentReportForRouter(message string) bool {
	if isRouterChangeOnlyRequest(message) {
		return wantsFreshAgentReport(message)
	}
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_AGENT_AUTO_REFRESH")))
	if value == "1" || value == "true" || value == "yes" || value == "on" {
		return true
	}
	if value == "0" || value == "false" || value == "no" || value == "off" {
		return wantsFreshAgentReport(message)
	}
	return wantsFreshAgentReport(message)
}

func isRouterAlertExplanationRequest(message string) bool {
	lower := strings.ToLower(strings.TrimSpace(message))
	if lower == "" {
		return false
	}
	hasAlertWord := containsAny(lower, "알림", "경고", "alert", "alerts", "warning", "warnings")
	hasQuestionWord := containsAny(lower, "뭐", "무슨", "뜻", "의미", "설명", "what", "meaning", "explain")
	hasStatusWord := containsAny(lower, "서버", "노드", "상태", "점검", "보고", "status", "health", "fleet", "node", "server")
	return hasAlertWord && hasQuestionWord && !hasStatusWord
}

func isRouterDeepFleetReport(message string) bool {
	lower := strings.ToLower(strings.TrimSpace(message))
	return containsAny(lower,
		"종합 보고", "전체 보고", "상세 보고", "운영 보고", "서버 보고", "운영자", "운영자 관점", "바로 볼 위험", "다음 조치", "깊게", "자세히", "워크로드", "프로세스", "보안까지", "히스토리", "변화",
		"침입", "침입 징후", "열린 포트", "공개 포트", "방화벽", "fail2ban", "크론", "크론잡", "도커 포트", "docker port", "docker ports",
		"deep report", "full report", "detailed report", "comprehensive", "workload", "workloads", "process", "processes", "history", "changes",
		"intrusion", "open ports", "public ports", "firewall", "cron", "crontab",
	)
}

func isRouterChangeOnlyRequest(message string) bool {
	lower := strings.ToLower(strings.TrimSpace(message))
	if lower == "" {
		return false
	}
	hasChange := containsAny(lower,
		"어제", "비교", "변화", "달라", "달라졌", "지난", "최근 변화", "히스토리",
		"yesterday", "compare", "compared", "change", "changes", "changed", "history",
	)
	if !hasChange {
		return false
	}
	hasHeavyReport := containsAny(lower,
		"종합", "전체", "상세", "운영자", "운영 보고", "침입", "침입 징후", "열린 포트", "공개 포트",
		"fail2ban", "방화벽", "크론", "cron", "docker", "도커", "프로세스", "process", "보안 전체",
		"comprehensive", "full report", "detailed", "intrusion", "open ports", "public ports", "firewall",
	)
	return !hasHeavyReport
}

func routerMonitorFreshDefault() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_MONITOR_FRESH_DEFAULT")))
	return value == "1" || value == "true" || value == "yes" || value == "on"
}

func filterMonitorCheckOutput(output monitorCheckOutput, target string) monitorCheckOutput {
	target = strings.TrimSpace(target)
	if target == "" {
		return output
	}
	filteredStates := map[string]*monitor.NodeState{}
	if state := output.States[target]; state != nil {
		filteredStates[target] = state
	}
	filteredAlerts := make([]monitor.Alert, 0)
	for _, alert := range output.Alerts {
		if alert.Node == target {
			filteredAlerts = append(filteredAlerts, alert)
		}
	}
	return monitorCheckOutput{States: filteredStates, Alerts: filteredAlerts}
}

func routerAgentRefreshEnabled() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_AGENT_REFRESH")))
	return value == "" || value == "1" || value == "true" || value == "yes" || value == "on"
}

func routerAgentRefreshTimeout() time.Duration {
	value := strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_AGENT_REFRESH_TIMEOUT"))
	if value == "" {
		return 30 * time.Second
	}
	if duration, err := time.ParseDuration(value); err == nil && duration > 0 {
		return duration
	}
	if seconds, err := strconv.ParseFloat(value, 64); err == nil && seconds > 0 {
		return time.Duration(seconds * float64(time.Second))
	}
	return 30 * time.Second
}

func routerAgentRefreshHosts(target string) []string {
	target = strings.TrimSpace(target)
	if target != "" {
		return []string{target}
	}
	seen := map[string]bool{}
	var hosts []string
	for _, node := range inventory.DefaultNodes() {
		name := strings.TrimSpace(node.Name)
		if name == "" || seen[name] || nodeHasTag(node, "client") {
			continue
		}
		seen[name] = true
		hosts = append(hosts, name)
	}
	return hosts
}

func refreshAgentReportsForRouter(target string) (agentPullReport, error) {
	report := agentPullReport{
		Kind:      "meshclaw_agent_pull",
		Generated: time.Now().UTC(),
	}
	if !routerAgentRefreshEnabled() {
		report.Error = "router agent refresh disabled"
		return report, nil
	}
	hosts := routerAgentRefreshHosts(target)
	if len(hosts) == 0 {
		report.Error = "no refresh hosts"
		return report, nil
	}
	collect := nodestate.Options{
		TopProcesses: 10,
		Services:     []string{"ollama", "open-webui", "meshclaw", "vsshd", "docker"},
		Timeout:      3 * time.Second,
	}
	return pullAgentReportsFromHosts(hosts, collect, defaultAgentMaxHistory(), routerAgentRefreshTimeout())
}

func summarizeAgentPullReport(report agentPullReport) agentPullReport {
	out := report
	out.Hosts = make([]agentPullHost, 0, len(report.Hosts))
	for _, host := range report.Hosts {
		item := host
		item.Report = nil
		item.Stored = nil
		item.Error = humanAgentRefreshError(item.Error)
		out.Hosts = append(out.Hosts, item)
	}
	out.Error = humanAgentRefreshError(out.Error)
	return out
}

func humanAgentRefreshError(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	lower := strings.ToLower(value)
	switch {
	case strings.Contains(lower, "unknown flag: --top") && strings.Contains(lower, "meshclaw agent"):
		return "remote meshclaw is too old for node-local agent collection; upgrade meshclaw on this host"
	case strings.Contains(lower, "permission denied"):
		return "vssh/SSH authentication failed for this host"
	case strings.Contains(lower, "operation timed out"), strings.Contains(lower, "timed out"):
		return "connection timed out while collecting fresh node state"
	case strings.Contains(lower, "remote output did not contain a node report"):
		return "remote command did not return a MeshClaw node report; check installed meshclaw path/version"
	default:
		return compactErrorText(value, 220)
	}
}

const defaultAutohealPlanTimeout = 45 * time.Second

// autohealPlanTimeout returns the overall deadline for collecting live fleet
// state during an autoheal plan. Overridable via MESHCLAW_AUTOHEAL_PLAN_TIMEOUT.
func autohealPlanTimeout() time.Duration {
	if v := os.Getenv("MESHCLAW_AUTOHEAL_PLAN_TIMEOUT"); v != "" {
		if d, err := time.ParseDuration(v); err == nil && d > 0 {
			return d
		}
	}
	return defaultAutohealPlanTimeout
}

type autohealPlanInputs struct {
	monitor         *monitor.Monitor
	serviceTriage   serviceTriageReport
	serviceStoreErr error
	err             error
}

// collectAutohealPlanInputs runs the live fleet scan (monitor.CheckAll and
// service triage) under an overall deadline. monitor.CheckAll and the service
// audit reach every inventory node over Tailscale/vssh with no per-call
// deadline, so a single unreachable node could block the caller (and the MCP
// request) indefinitely. When the deadline is exceeded we return timedOut=true
// and let the caller produce a partial plan instead of hanging.
func collectAutohealPlanInputs(timeout time.Duration) (autohealPlanInputs, bool) {
	done := make(chan autohealPlanInputs, 1)
	go func() {
		var in autohealPlanInputs
		m, err := monitor.New(monitor.DefaultConfig())
		if err != nil {
			in.err = err
			done <- in
			return
		}
		m.CheckAll()
		in.monitor = m
		st, _, serr := buildServiceTriage(nil, 5, 4)
		in.serviceTriage = st
		in.serviceStoreErr = serr
		done <- in
	}()
	select {
	case in := <-done:
		return in, false
	case <-time.After(timeout):
		return autohealPlanInputs{}, true
	}
}

// degradedAutohealPlanReport is returned when the live fleet scan exceeds the
// deadline. It is a valid, empty-candidate plan marked status=partial so
// callers and downstream tools can tell the plan is incomplete.
func degradedAutohealPlanReport(timeout time.Duration) autohealPlanReport {
	report := buildAutohealPlanReport(nil)
	if report.Actions == nil {
		report.Actions = []monitor.HealPlanAction{}
	}
	report.Status = "partial"
	report.Notes = append(report.Notes,
		fmt.Sprintf("autoheal plan timed out after %s collecting live fleet state; returning partial plan instead of blocking", timeout),
		"an inventory node is likely unreachable; rerun when the fleet is reachable, or use cached autoheal_sweep")
	return report
}

func autohealPlan(args []string) error {
	timeout := autohealPlanTimeout()
	in, timedOut := collectAutohealPlanInputs(timeout)
	if timedOut {
		report := degradedAutohealPlanReport(timeout)
		record, storeErr := evidence.Store("autoheal-plan", "fleet", fmt.Sprintf("status=partial timeout=%s", timeout), report)
		if wantsJSON(args) {
			return printJSON(map[string]interface{}{"actions": report.Actions, "recommended_mcp": report.RecommendedMCP, "report": report, "status": report.Status, "evidence": record, "store_error": errString(storeErr)})
		}
		fmt.Println(autohealPlanSummaryLine(report))
		for _, note := range report.Notes {
			fmt.Printf("- note: %s\n", note)
		}
		printEvidenceStoreStatus(record, storeErr)
		return nil
	}
	if in.err != nil {
		return in.err
	}
	serviceStoreErr := in.serviceStoreErr
	actions := buildAutohealPlan(in.monitor, in.serviceTriage)
	report := buildAutohealPlanReport(actions)
	record, storeErr := evidence.Store("autoheal-plan", "fleet", fmt.Sprintf("actions=%d", len(actions)), report)
	if storeErr == nil {
		storeErr = serviceStoreErr
	}
	if wantsJSON(args) {
		return printJSON(map[string]interface{}{"actions": actions, "recommended_mcp": report.RecommendedMCP, "report": report, "evidence": record, "store_error": errString(storeErr)})
	}
	fmt.Println(autohealPlanSummaryLine(report))
	if len(actions) == 0 {
		printEvidenceStoreStatus(record, storeErr)
		return nil
	}
	for _, action := range actions {
		fmt.Printf("- [%s/%s] %s %s=%.1f mode=%s\n  command: %s\n  reason: %s\n  verify: %s\n",
			action.Severity, action.Type, action.Node, action.Metric, action.Value, action.Mode, action.Command, action.Reason, action.Verify)
	}
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

func autohealContainerApplyPlan(args []string) error {
	if hasFlag(args, "--apply") || hasFlag(args, "--execute") {
		return fmt.Errorf("autoheal-container-apply-plan builds a plan only; execution is not implemented")
	}
	planPath := autohealPlanEvidencePath(args)
	if planPath == "" {
		return fmt.Errorf("usage: meshclaw autoheal-container-apply-plan --plan-evidence evidence.json --approved-by operator [--json]")
	}
	record, err := evidence.Load(planPath)
	if err != nil {
		return err
	}
	plan, err := autohealPlanFromEvidence(record)
	if err != nil {
		return err
	}
	report := buildContainerApplyPlanReport(planPath, record, plan, reconcileApprovedBy(args))
	applyRecord, storeErr := evidence.Store("container-apply-plan", "fleet", fmt.Sprintf("ready=%t steps=%d", report.Ready, len(report.Steps)), report)
	if wantsJSON(args) {
		return printJSON(map[string]interface{}{"container_apply_plan": report, "evidence": applyRecord, "store_error": errString(storeErr)})
	}
	fmt.Println(containerApplyPlanSummaryLine(report))
	for _, reason := range report.Reasons {
		fmt.Printf("- %s\n", reason)
	}
	for _, step := range report.Steps {
		fmt.Printf("- step=%d node=%s container=%s operation=%s\n  template=%s\n", step.Step, step.NodeID, step.Container, step.Operation, step.CommandTemplate)
	}
	printEvidenceStoreStatus(applyRecord, storeErr)
	return nil
}

