func reconcileCommand(args []string) error {
	if len(args) == 0 {
		return fmt.Errorf("usage: meshclaw reconcile <validate-desired|plan|approval-request|apply-gate|apply-plan|execution-preview|verification-plan|runbook|runbook-check|rollback-plan|completion-plan|readiness-summary|run-once> --desired desired-state.yaml [--dry-run] [--json]")
	}
	switch args[0] {
	case "validate-desired":
		return reconcileValidateDesiredCommand(args[1:])
	case "plan":
		return reconcilePlan(args[1:])
	case "approval-request":
		return reconcileApprovalRequestCommand(args[1:])
	case "apply-gate":
		return reconcileApplyGateCommand(args[1:])
	case "apply-plan":
		return reconcileApplyPlanCommand(args[1:])
	case "execution-preview":
		return reconcileExecutionPreviewCommand(args[1:])
	case "verification-plan":
		return reconcileVerificationPlanCommand(args[1:])
	case "runbook":
		return reconcileRunbookCommand(args[1:])
	case "runbook-check":
		return reconcileRunbookCheckCommand(args[1:])
	case "rollback-plan":
		return reconcileRollbackPlanCommand(args[1:])
	case "completion-plan":
		return reconcileCompletionPlanCommand(args[1:])
	case "readiness-summary":
		return reconcileReadinessSummaryCommand(args[1:])
	case "run-once":
		return reconcileRunOnce(args[1:])
	default:
		return fmt.Errorf("unknown reconcile subcommand %q", args[0])
	}
}

