func reconcileRunOnce(args []string) error {
	if hasFlag(args, "--apply") || hasFlag(args, "--execute") {
		return fmt.Errorf("reconcile run-once execute/apply is intentionally not implemented")
	}
	if !hasFlag(args, "--dry-run") {
		return fmt.Errorf("reconcile run-once currently requires --dry-run")
	}
	return runReconcilePlan(args, "meshclaw_reconcile_run_once", "reconcile-run-once")
}

func runReconcilePlan(args []string, reportKind, evidenceKind string) error {
	report, err := loadReconcilePlanReport(args, reportKind)
	if err != nil {
		return err
	}
	record, storeErr := evidence.Store(evidenceKind, "fleet", reconcilePlanCountsLine(report.Counts), report)
	if wantsJSON(args) {
		return printJSON(map[string]interface{}{"report": report, "evidence": record, "store_error": errString(storeErr)})
	}
	fmt.Println(reconcilePlanSummaryLine(report))
	fmt.Println(reconcilePlanCountsLine(report.Counts))
	for _, result := range report.Results {
		fmt.Printf("- node=%s matched=%t actions=%d\n", result.NodeID, result.Matched, len(result.Actions))
		for _, action := range result.Actions {
			fmt.Printf("  [%s] %s policy=%s approval=%t\n", action.Severity, action.Summary, action.PolicyAction, action.ApprovalRequired)
		}
	}
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

func loadReconcilePlanReport(args []string, reportKind string) (reconcilePlanReport, error) {
	desiredPath := reconcileDesiredPath(args)
	if desiredPath == "" {
		return reconcilePlanReport{}, fmt.Errorf("usage: meshclaw reconcile plan --desired desired-state.yaml [--json]")
	}
	desired, err := reconciler.LoadDesiredState(desiredPath)
	if err != nil {
		return reconcilePlanReport{}, err
	}
	actuals, actualPaths, err := reconcileActualReports(args)
	if err != nil {
		return reconcilePlanReport{}, err
	}
	report := buildReconcilePlanReport(desiredPath, desired, actuals, actualPaths)
	report.Kind = reportKind
	return report, nil
}

func reconcileDesiredValidationSummaryLine(report reconcileDesiredValidationReport) string {
	return fmt.Sprintf("reconcile validate-desired ready=%t status=%s desired=%s schema_version=%s findings=%d",
		report.Ready,
		report.Status,
		report.DesiredPath,
		readinessEvidenceID(report.SchemaVersion),
		len(report.Findings),
	)
}

func reconcileDesiredValidationHandoffLine(report reconcileDesiredValidationReport) string {
	return fmt.Sprintf("validation_handoff decision=%s allowed=%s blocked=%d required_evidence=%d stop_before=%d refresh_triggers=%d",
		readinessEvidenceID(report.Handoff.Decision),
		readinessListOrNone(report.Handoff.AllowedNextTools),
		len(report.Handoff.BlockedNextTools),
		len(report.Handoff.RequiredEvidence),
		len(report.Handoff.StopBefore),
		len(report.Handoff.RefreshTriggers),
	)
}

func readinessListOrNone(values []string) string {
	if len(values) == 0 {
		return "<none>"
	}
	return strings.Join(values, ",")
}

