func buildReconcileDesiredValidationReport(desiredPath string, desired reconciler.DesiredState) reconcileDesiredValidationReport {
	report := reconcileDesiredValidationReport{
		Kind:          "meshclaw_reconcile_desired_validation",
		Mode:          "validation_only",
		Status:        "ready",
		Ready:         true,
		DesiredPath:   desiredPath,
		SchemaVersion: strings.TrimSpace(desired.SchemaVersion),
		Desired:       desired,
		Findings:      reconciler.ValidateDesiredState(desired),
		Counts:        map[string]int{},
		GeneratedAt:   time.Now().UTC(),
		Next: []string{
			"Use this validation evidence before reconcile plan, approval, or future apply loops.",
			"Fix critical findings before generating approval or apply evidence.",
			"Refresh validation when desired-state YAML changes.",
		},
		Safety: map[string]string{
			"mutation":   "disabled; desired-state validation only",
			"execute":    "not implemented",
			"validation": "critical findings block future apply readiness",
		},
	}
	report.Counts["nodes"] = len(desired.Nodes)
	if report.SchemaVersion != "" {
		report.Counts["schema_version_present"] = 1
	}
	for _, finding := range report.Findings {
		report.Counts["findings"]++
		report.Counts[finding.Severity]++
		if isIgnoredDesiredApplyFinding(finding) {
			report.Counts["ignored_apply_keys"]++
		}
		if finding.Severity == "critical" {
			report.Ready = false
			report.Status = "blocked"
		}
	}
	if report.Ready && report.Counts["warning"] > 0 {
		report.Status = "ready_with_warnings"
	}
	report.Handoff = reconcileDesiredValidationHandoff(report)
	return report
}

func reconcileDesiredValidationHandoff(report reconcileDesiredValidationReport) reconcileValidationHandoff {
	handoff := reconcileValidationHandoff{
		Decision: "validate_before_reconcile",
		RequiredEvidence: []string{
			"stored desired-validation evidence path",
			"schema_version and validation finding counts",
			"fresh validation after desired-state YAML changes",
		},
		StopBefore: []string{
			"running reconcile plan against unvalidated YAML",
			"generating approval or apply-gate evidence with critical validation findings",
			"treating validation as apply approval",
		},
		RefreshTriggers: []string{
			"desired-state YAML changed",
			"schema_version changed",
			"critical or warning validation finding changed",
		},
	}
	if report.Counts["ignored_apply_keys"] > 0 {
		handoff.StopBefore = append(handoff.StopBefore, "treating ignored YAML apply/execute keys as approval")
		handoff.RefreshTriggers = append(handoff.RefreshTriggers, "ignored apply/execute YAML key changed")
	}
	if report.Ready {
		handoff.Decision = "validated_for_dry_run_reconcile"
		handoff.AllowedNextTools = []string{
			"meshclaw_reconcile_plan",
			"meshclaw_reconcile_approval_request",
		}
		handoff.BlockedNextTools = []string{
			"meshclaw_reconcile_apply_gate without approval-request evidence",
			"meshclaw_reconcile_apply_plan without apply-gate evidence",
		}
		return handoff
	}
	handoff.Decision = "blocked_until_desired_yaml_fixed"
	handoff.AllowedNextTools = []string{"meshclaw_reconcile_validate_desired"}
	handoff.BlockedNextTools = []string{
		"meshclaw_reconcile_plan",
		"meshclaw_reconcile_approval_request",
		"meshclaw_reconcile_apply_gate",
		"meshclaw_reconcile_apply_plan",
	}
	return handoff
}

func isIgnoredDesiredApplyFinding(finding reconciler.DesiredValidationFinding) bool {
	return finding.Severity == "warning" && strings.Contains(finding.Message, "does not grant apply, execute, or approval")
}

func buildReconcilePlanReport(desiredPath string, desired reconciler.DesiredState, actuals map[string]reconciler.ActualNode, actualPaths []string) reconcilePlanReport {
	results := make([]reconciler.Result, 0, len(desired.Nodes))
	for _, node := range desired.Nodes {
		actual, ok := actuals[node.ID]
		if !ok {
			actual = reconciler.ActualNode{ID: node.ID, Online: false}
		}
		result := reconciler.DiffNode(node, actual, reconciler.DiffOptions{})
		annotateReconcileResultPolicy(&result)
		results = append(results, result)
	}
	report := reconcilePlanReport{
		Kind:          "meshclaw_reconcile_plan",
		Mode:          "dry_run",
		DesiredPath:   desiredPath,
		SchemaVersion: strings.TrimSpace(desired.SchemaVersion),
		ActualPaths:   actualPaths,
		Desired:       desired,
		Results:       results,
		Counts:        summarizeReconcilePlanResults(results, len(desired.Nodes), len(actualPaths)),
		GeneratedAt:   time.Now().UTC(),
		Next: []string{
			"Refresh node-local snapshots with `meshclaw agent pull <hosts> --json`.",
			"Bind actual node state to the reconciler before any apply loop.",
			"Use policy decisions and evidence refs before executing any mutating action.",
		},
		Safety: map[string]string{
			"mutation": "disabled in this command",
			"apply":    "future apply/run-once must require policy gate and evidence",
			"scope":    "desired-state parsing and dry reconcile plan only",
		},
	}
	if report.SchemaVersion != "" {
		report.Counts["schema_version_present"] = 1
	}
	return report
}

func summarizeReconcilePlanResults(results []reconciler.Result, desiredNodes, actualReports int) map[string]int {
	counts := map[string]int{
		"nodes":          desiredNodes,
		"results":        len(results),
		"actual_reports": actualReports,
	}
	for _, result := range results {
		if result.Matched {
			counts["matched"]++
		} else {
			counts["unmatched"]++
		}
		for _, action := range result.Actions {
			counts["actions"]++
			if action.Kind != "" {
				counts["kind_"+action.Kind]++
			}
			if action.Severity != "" {
				counts["severity_"+action.Severity]++
			}
			if action.PolicyDecision != "" {
				counts["policy_"+action.PolicyDecision]++
			}
			if action.ApprovalRequired {
				counts["approval_required"]++
			}
			if isReconcileContainerAction(action) {
				counts["container_actions"]++
			}
		}
	}
	return counts
}

func reconcilePlanCountsLine(counts map[string]int) string {
	return fmt.Sprintf("nodes=%d results=%d matched=%d unmatched=%d actions=%d approval_required=%d container_actions=%d",
		counts["nodes"],
		counts["results"],
		counts["matched"],
		counts["unmatched"],
		counts["actions"],
		counts["approval_required"],
		counts["container_actions"],
	)
}

func buildReconcileApprovalRequest(plan reconcilePlanReport) reconcileApprovalRequest {
	request := reconcileApprovalRequest{
		Kind:          "meshclaw_reconcile_approval_request",
		Mode:          "approval_gate",
		Status:        "no_approval_required",
		DesiredPath:   plan.DesiredPath,
		SchemaVersion: strings.TrimSpace(plan.SchemaVersion),
		ActualPaths:   plan.ActualPaths,
		Counts:        map[string]int{},
		GeneratedAt:   time.Now().UTC(),
		Next: []string{
			"Review each approval action against desired-state intent and latest node evidence.",
			"Do not execute blocked actions; update policy or desired state first.",
			"Future apply loops must attach this approval evidence before mutating servers.",
		},
		Safety: map[string]string{
			"mutation": "disabled; this command only creates an approval request",
			"approval": "required actions are queued for human/operator review",
			"blocked":  "deny actions are separated and must not be executed",
		},
	}
	if request.SchemaVersion != "" {
		request.Counts["schema_version_present"] = 1
	}
	for _, result := range plan.Results {
		for _, action := range result.Actions {
			request.Counts["total"]++
			containerAction := isReconcileContainerAction(action)
			if containerAction {
				request.Counts["container_total"]++
			}
			switch action.PolicyDecision {
			case string(policy.Deny):
				request.BlockedActions = append(request.BlockedActions, action)
				request.Counts["blocked"]++
				if containerAction {
					request.Counts["container_blocked"]++
				}
			case string(policy.RequireApproval):
				request.Actions = append(request.Actions, action)
				request.Counts["approval_required"]++
				if containerAction {
					request.Counts["container_approval_required"]++
				}
			default:
				if action.ApprovalRequired {
					request.Actions = append(request.Actions, action)
					request.Counts["approval_required"]++
					if containerAction {
						request.Counts["container_approval_required"]++
					}
				} else {
					request.Counts["allowed"]++
					if containerAction {
						request.Counts["container_allowed"]++
					}
				}
			}
		}
	}
	if len(request.BlockedActions) > 0 {
		request.Status = "blocked"
	} else if len(request.Actions) > 0 {
		request.Status = "approval_required"
	}
	request.ApprovalRequired = len(request.Actions) > 0
	return request
}

func isReconcileContainerAction(action reconciler.Action) bool {
	if action.Kind == "container_drift" {
		return true
	}
	switch action.PolicyAction {
	case "container_restart", "container_recreate", "container_pull_redeploy":
		return true
	}
	return strings.TrimSpace(action.Metadata["container"]) != ""
}

func approvalRequestFromEvidence(record evidence.Record) (reconcileApprovalRequest, error) {
	if record.Kind != "reconcile-approval-request" {
		return reconcileApprovalRequest{}, fmt.Errorf("evidence kind %q is not reconcile-approval-request", record.Kind)
	}
	data, err := json.Marshal(record.Payload)
	if err != nil {
		return reconcileApprovalRequest{}, err
	}
	var request reconcileApprovalRequest
	if err := json.Unmarshal(data, &request); err != nil {
		return reconcileApprovalRequest{}, err
	}
	if request.Kind != "meshclaw_reconcile_approval_request" {
		return reconcileApprovalRequest{}, fmt.Errorf("evidence payload kind %q is not meshclaw_reconcile_approval_request", request.Kind)
	}
	return request, nil
}

