func buildReconcileApplyGateReport(desiredPath, evidencePath string, record evidence.Record, request reconcileApprovalRequest, approvedBy string) reconcileApplyGateReport {
	report := reconcileApplyGateReport{
		Kind:                 "meshclaw_reconcile_apply_gate",
		Mode:                 "gate_only",
		Status:               "ready",
		DesiredPath:          desiredPath,
		SchemaVersion:        strings.TrimSpace(request.SchemaVersion),
		ApprovalEvidencePath: evidencePath,
		ApprovalEvidenceID:   record.ID,
		ApprovedBy:           strings.TrimSpace(approvedBy),
		ApprovalRequest:      request,
		Counts:               copyIntMap(request.Counts),
		GeneratedAt:          time.Now().UTC(),
		Next: []string{
			"Attach this gate evidence to any future reconcile apply attempt.",
			"Run verification evidence after any future mutating action.",
			"Stop if desired state or approval request evidence changes.",
		},
		Safety: map[string]string{
			"mutation": "disabled; this command validates gates only",
			"execute":  "future apply must require this gate plus post-action verification",
			"blocked":  "policy-denied actions keep the gate not ready",
		},
	}
	if strings.TrimSpace(request.DesiredPath) != strings.TrimSpace(desiredPath) {
		report.Reasons = append(report.Reasons, "desired path does not match approval request evidence")
	}
	if len(request.BlockedActions) > 0 {
		report.Reasons = append(report.Reasons, "approval request contains policy-denied blocked actions")
	}
	if len(request.Actions) > 0 && report.ApprovedBy == "" {
		report.Reasons = append(report.Reasons, "approval-required actions need approved_by before apply can proceed")
	}
	if len(report.Reasons) > 0 {
		report.Ready = false
		report.Status = "not_ready"
		report.Counts["gate_blocked"] = 1
	} else {
		report.Ready = true
		report.Counts["gate_ready"] = 1
	}
	return report
}

func copyIntMap(values map[string]int) map[string]int {
	out := make(map[string]int, len(values))
	for key, value := range values {
		if strings.TrimSpace(key) != "" {
			out[key] = value
		}
	}
	if len(out) == 0 {
		return map[string]int{}
	}
	return out
}

func buildReconcileApplyPlanReport(gatePath string, record evidence.Record, gate reconcileApplyGateReport) reconcileApplyPlanReport {
	report := reconcileApplyPlanReport{
		Kind:             "meshclaw_reconcile_apply_plan",
		Mode:             "plan_only",
		Status:           "ready",
		Ready:            true,
		SchemaVersion:    strings.TrimSpace(gate.SchemaVersion),
		GateEvidencePath: gatePath,
		GateEvidenceID:   record.ID,
		Gate:             gate,
		Counts:           copyIntMap(gate.Counts),
		GeneratedAt:      time.Now().UTC(),
		Next: []string{
			"Review planned steps before implementing any future executor.",
			"Future executor must require this apply-plan evidence plus post-action verification.",
			"Keep server mutation disabled until an explicit apply implementation is reviewed.",
		},
		Safety: map[string]string{
			"mutation": "disabled; this command emits structured apply steps only",
			"execute":  "not implemented",
			"gate":     "requires ready reconcile-apply-gate evidence",
		},
	}
	if !gate.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "apply gate is not ready")
		report.Reasons = append(report.Reasons, gate.Reasons...)
		report.Counts["apply_plan_blocked"] = 1
		return report
	}
	for _, action := range gate.ApprovalRequest.Actions {
		metadata := copyStringMap(action.Metadata)
		if metadata == nil {
			metadata = map[string]string{}
		}
		metadata["policy_decision"] = action.PolicyDecision
		metadata["policy_resource"] = action.PolicyResource
		metadata["approved_by"] = gate.ApprovedBy
		if container := firstNonEmpty(metadata["container"], reconcileContainerNameForAction(action)); container != "" {
			metadata["container"] = container
		}
		report.Steps = append(report.Steps, reconcileApplyStep{
			Step:         len(report.Steps) + 1,
			NodeID:       action.NodeID,
			ActionID:     action.ID,
			Kind:         action.Kind,
			Severity:     action.Severity,
			Summary:      action.Summary,
			Operation:    reconcileOperationForAction(action),
			PolicyAction: action.PolicyAction,
			EvidenceRefs: action.EvidenceRefs,
			Metadata:     metadata,
		})
	}
	report.Counts["apply_steps"] = len(report.Steps)
	report.Counts["container_apply_steps"] = countContainerApplySteps(report.Steps)
	report.Counts["apply_plan_ready"] = 1
	return report
}

func reconcileOperationForAction(action reconciler.Action) string {
	switch action.Kind {
	case "container_drift":
		return "container_reconcile"
	case "service_drift":
		return "service_reconcile"
	case "capacity_drift":
		return "capacity_remediation"
	case "diagnose_offline_node":
		return "offline_node_diagnosis"
	case "inventory_drift":
		return "inventory_review"
	default:
		return firstNonEmpty(action.PolicyAction, action.Kind, "review")
	}
}

func reconcileContainerNameForAction(action reconciler.Action) string {
	if action.Kind != "container_drift" {
		return ""
	}
	_, container, ok := strings.Cut(action.ID, ":container:")
	if !ok {
		return ""
	}
	return strings.TrimSpace(container)
}

func buildReconcileExecutionPreviewReport(planPath string, record evidence.Record, plan reconcileApplyPlanReport) reconcileExecutionPreviewReport {
	report := reconcileExecutionPreviewReport{
		Kind:                  "meshclaw_reconcile_execution_preview",
		Mode:                  "preview_only",
		Status:                "ready",
		Ready:                 true,
		SchemaVersion:         strings.TrimSpace(plan.SchemaVersion),
		ApplyPlanEvidencePath: planPath,
		ApplyPlanEvidenceID:   record.ID,
		ApplyPlan:             plan,
		Counts:                copyIntMap(plan.Counts),
		GeneratedAt:           time.Now().UTC(),
		Next: []string{
			"Review command templates before implementing a real executor.",
			"Future executor must re-check policy, consume apply-plan evidence, and store post-action verification evidence.",
			"Keep command templates inert; do not run them directly.",
		},
		Safety: map[string]string{
			"mutation": "disabled; command templates are inert previews",
			"execute":  "not implemented",
			"verify":   "each future command requires post-action evidence",
		},
	}
	if !plan.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "apply plan is not ready")
		report.Reasons = append(report.Reasons, plan.Reasons...)
		report.Counts["execution_preview_blocked"] = 1
		return report
	}
	for _, step := range plan.Steps {
		metadata := map[string]string{
			"action_id":     step.ActionID,
			"kind":          step.Kind,
			"policy_action": step.PolicyAction,
			"severity":      step.Severity,
		}
		for _, key := range []string{
			"container",
			"desired_state",
			"actual_state",
			"desired_image",
			"actual_image",
			"desired_health",
			"actual_health",
			"desired_restart",
			"actual_restart",
		} {
			if value := strings.TrimSpace(step.Metadata[key]); value != "" {
				metadata[key] = value
			}
		}
		report.Commands = append(report.Commands, reconcileExecutionCommand{
			Step:                 step.Step,
			NodeID:               step.NodeID,
			Operation:            step.Operation,
			Executor:             "meshclaw-agent",
			CommandTemplate:      reconcileCommandTemplateForStep(step),
			RequiresVerification: true,
			VerificationHint:     reconcileVerificationHintForStep(step),
			EvidenceRefs:         step.EvidenceRefs,
			Metadata:             metadata,
		})
	}
	report.Counts["execution_commands"] = len(report.Commands)
	report.Counts["container_execution_commands"] = countContainerExecutionCommands(report.Commands)
	report.Counts["execution_preview_ready"] = 1
	return report
}

func reconcileCommandTemplateForStep(step reconcileApplyStep) string {
	if step.Operation == "container_reconcile" {
		container := shellQuote(step.Metadata["container"])
		if container != "''" {
			var flags []string
			for _, field := range []struct {
				key  string
				flag string
			}{
				{key: "desired_state", flag: "--desired-state"},
				{key: "actual_state", flag: "--actual-state"},
				{key: "desired_image", flag: "--desired-image"},
				{key: "actual_image", flag: "--actual-image"},
				{key: "desired_health", flag: "--desired-health"},
				{key: "actual_health", flag: "--actual-health"},
				{key: "desired_restart", flag: "--desired-restart"},
				{key: "actual_restart", flag: "--actual-restart"},
			} {
				value := shellQuote(step.Metadata[field.key])
				if value != "''" {
					flags = append(flags, field.flag+" "+value)
				}
			}
			if len(flags) > 0 {
				return fmt.Sprintf("meshclaw agent apply-step --node %s --operation %s --container %s %s --action-id %s --require-evidence", step.NodeID, step.Operation, container, strings.Join(flags, " "), step.ActionID)
			}
			return fmt.Sprintf("meshclaw agent apply-step --node %s --operation %s --container %s --action-id %s --require-evidence", step.NodeID, step.Operation, container, step.ActionID)
		}
	}
	return fmt.Sprintf("meshclaw agent apply-step --node %s --operation %s --action-id %s --require-evidence", step.NodeID, step.Operation, step.ActionID)
}

func reconcileVerificationHintForStep(step reconcileApplyStep) string {
	switch step.Operation {
	case "container_reconcile":
		return "collect fresh node report, Docker container state, and focused container-logscan evidence after the container action"
	case "service_reconcile":
		return "collect service-check evidence after the service action"
	case "capacity_remediation":
		return "collect node report and capacity evidence after remediation"
	case "offline_node_diagnosis":
		return "collect fresh agent/node connectivity evidence"
	case "inventory_review":
		return "collect fresh node inventory evidence"
	default:
		return "collect post-action evidence before marking the step complete"
	}
}

func buildReconcileVerificationPlanReport(previewPath string, record evidence.Record, preview reconcileExecutionPreviewReport) reconcileVerificationPlanReport {
	report := reconcileVerificationPlanReport{
		Kind:                         "meshclaw_reconcile_verification_plan",
		Mode:                         "plan_only",
		Status:                       "ready",
		Ready:                        true,
		SchemaVersion:                strings.TrimSpace(preview.SchemaVersion),
		ExecutionPreviewEvidencePath: previewPath,
		ExecutionPreviewEvidenceID:   record.ID,
		ExecutionPreview:             preview,
		Counts:                       copyIntMap(preview.Counts),
		GeneratedAt:                  time.Now().UTC(),
		Next: []string{
			"Require these checks after each future executor step.",
			"Stop the apply loop when a required evidence check fails.",
			"Store verification evidence before marking reconcile complete.",
		},
		Safety: map[string]string{
			"mutation": "disabled; verification requirements only",
			"execute":  "not implemented",
			"rollback": "future executor must stop or rollback on failed checks",
		},
	}
	if !preview.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "execution preview is not ready")
		report.Reasons = append(report.Reasons, preview.Reasons...)
		report.Counts["verification_plan_blocked"] = 1
		return report
	}
	for _, command := range preview.Commands {
		metadata := map[string]string{
			"executor":          command.Executor,
			"verification_hint": command.VerificationHint,
		}
		for _, key := range []string{
			"action_id",
			"kind",
			"policy_action",
			"severity",
			"container",
			"desired_state",
			"actual_state",
			"desired_image",
			"actual_image",
			"desired_health",
			"actual_health",
			"desired_restart",
			"actual_restart",
		} {
			if value := strings.TrimSpace(command.Metadata[key]); value != "" {
				metadata[key] = value
			}
		}
		report.Checks = append(report.Checks, reconcileVerificationCheck{
			Step:             command.Step,
			NodeID:           command.NodeID,
			Operation:        command.Operation,
			RequiredEvidence: reconcileRequiredEvidenceForOperation(command.Operation),
			SuccessCriteria:  reconcileSuccessCriteriaForCommand(command),
			FailureAction:    reconcileFailureActionForOperation(command.Operation),
			Retryable:        reconcileVerificationRetryable(command.Operation),
			Metadata:         metadata,
		})
	}
	report.Counts["verification_checks"] = len(report.Checks)
	report.Counts["container_verification_checks"] = countContainerVerificationChecks(report.Checks)
	report.Counts["verification_plan_ready"] = 1
	return report
}

func reconcileRequiredEvidenceForOperation(operation string) string {
	switch operation {
	case "container_reconcile":
		return "agent-collect+container-logscan"
	case "service_reconcile":
		return "service-check"
	case "capacity_remediation":
		return "node-report"
	case "offline_node_diagnosis":
		return "node-inventory"
	case "inventory_review":
		return "node-inventory"
	default:
		return "post-action-evidence"
	}
}

func reconcileSuccessCriteriaForOperation(operation string) []string {
	return reconcileSuccessCriteriaForCommand(reconcileExecutionCommand{Operation: operation})
}

func reconcileSuccessCriteriaForCommand(command reconcileExecutionCommand) []string {
	operation := command.Operation
	switch operation {
	case "container_reconcile":
		criteria := []string{
			"fresh node report collected after the future container action",
			"Docker container state/image/health matches desired state",
			"no fresh OOM/crash-loop log finding remains for the container",
			"policy result remains approved for the container action",
		}
		for _, field := range []struct {
			key   string
			label string
		}{
			{key: "desired_state", label: "state"},
			{key: "desired_image", label: "image"},
			{key: "desired_health", label: "health"},
			{key: "desired_restart", label: "restart policy"},
		} {
			if value := strings.TrimSpace(command.Metadata[field.key]); value != "" {
				criteria = append(criteria, fmt.Sprintf("Docker container %s equals %s", field.label, value))
			}
		}
		return criteria
	case "service_reconcile":
		return []string{"service exists", "service active/running matches desired state", "no fresh failure evidence"}
	case "capacity_remediation":
		return []string{"node report collected", "capacity metric moved toward desired threshold", "no denied cleanup action was used"}
	case "offline_node_diagnosis":
		return []string{"node connectivity or failure evidence collected", "next repair action is policy annotated"}
	case "inventory_review":
		return []string{"fresh inventory evidence collected", "desired role/tag drift is confirmed or cleared"}
	default:
		return []string{"post-action evidence stored", "policy result remains allow or approved", "no blocked action was executed"}
	}
}

func reconcileFailureActionForOperation(operation string) string {
	switch operation {
	case "container_reconcile":
		return "stop loop and create container rollback or manual triage approval"
	case "service_reconcile":
		return "stop loop and create service rollback/triage approval"
	case "capacity_remediation":
		return "stop loop and create capacity rollback/cleanup approval"
	default:
		return "stop loop and create follow-up approval evidence"
	}
}

func reconcileVerificationRetryable(operation string) bool {
	switch operation {
	case "offline_node_diagnosis", "inventory_review":
		return true
	default:
		return false
	}
}

func copyStringMap(values map[string]string) map[string]string {
	if len(values) == 0 {
		return nil
	}
	out := make(map[string]string, len(values))
	for key, value := range values {
		if strings.TrimSpace(key) != "" && strings.TrimSpace(value) != "" {
			out[key] = value
		}
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

func buildReconcileRunbookReport(verifyPath string, record evidence.Record, verification reconcileVerificationPlanReport) reconcileRunbookReport {
	report := reconcileRunbookReport{
		Kind:                         "meshclaw_reconcile_runbook",
		Mode:                         "review_only",
		Status:                       "ready",
		Ready:                        true,
		SchemaVersion:                strings.TrimSpace(verification.SchemaVersion),
		VerificationPlanEvidencePath: verifyPath,
		VerificationPlanEvidenceID:   record.ID,
		VerificationPlan:             verification,
		Counts:                       copyIntMap(verification.Counts),
		GeneratedAt:                  time.Now().UTC(),
		Next: []string{
			"Review the runbook before any future executor is implemented.",
			"Use the required evidence checks as hard gates after each future step.",
			"Store final reconcile completion evidence only after all checks pass.",
		},
		Safety: map[string]string{
			"mutation": "disabled; runbook is review-only",
			"execute":  "not implemented",
			"rollback": "failure actions are planning guidance, not automatic execution",
		},
	}
	if !verification.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "verification plan is not ready")
		report.Reasons = append(report.Reasons, verification.Reasons...)
		report.Counts["runbook_blocked"] = 1
		return report
	}
	commands := map[int]reconcileExecutionCommand{}
	for _, command := range verification.ExecutionPreview.Commands {
		commands[command.Step] = command
	}
	for _, check := range verification.Checks {
		command := commands[check.Step]
		report.Counts["total"]++
		if check.Retryable {
			report.Counts["retryable"]++
		}
		report.Steps = append(report.Steps, reconcileRunbookStep{
			Step:                 check.Step,
			NodeID:               check.NodeID,
			Operation:            check.Operation,
			CommandTemplate:      command.CommandTemplate,
			RequiredEvidence:     check.RequiredEvidence,
			SuccessCriteria:      check.SuccessCriteria,
			FailureAction:        check.FailureAction,
			RequiresVerification: true,
			Retryable:            check.Retryable,
			Metadata:             copyStringMap(check.Metadata),
		})
	}
	report.Counts["runbook_steps"] = len(report.Steps)
	report.Counts["container_runbook_steps"] = countContainerRunbookSteps(report.Steps)
	report.Counts["runbook_ready"] = 1
	return report
}

func buildReconcileRunbookCheckReport(runbookPath string, record evidence.Record, runbook reconcileRunbookReport) reconcileRunbookCheckReport {
	report := reconcileRunbookCheckReport{
		Kind:                "meshclaw_reconcile_runbook_check",
		Mode:                "gate_only",
		Status:              "ready",
		Ready:               true,
		SchemaVersion:       strings.TrimSpace(runbook.SchemaVersion),
		RunbookEvidencePath: runbookPath,
		RunbookEvidenceID:   record.ID,
		Runbook:             runbook,
		Counts:              copyIntMap(runbook.Counts),
		GeneratedAt:         time.Now().UTC(),
		Next: []string{
			"Only feed ready runbooks with zero critical findings into a future executor.",
			"Fix missing command templates or verification evidence requirements before apply.",
			"Keep execution disabled until runbook check evidence is ready.",
		},
		Safety: map[string]string{
			"mutation": "disabled; runbook quality gate only",
			"execute":  "not implemented",
			"gate":     "critical findings block future executor readiness",
		},
	}
	if !runbook.Ready {
		report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Field: "runbook_ready", Message: "runbook is not ready"})
	}
	if len(runbook.Steps) == 0 {
		report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Field: "steps", Message: "runbook has no steps"})
	}
	for _, step := range runbook.Steps {
		if strings.TrimSpace(step.NodeID) == "" {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "node_id", Message: "step has no node id"})
		}
		if strings.TrimSpace(step.CommandTemplate) == "" {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step has no command template"})
		} else {
			if !strings.Contains(step.CommandTemplate, "--require-evidence") {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template does not require evidence"})
			}
			if !strings.Contains(step.CommandTemplate, "--action-id") {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template has no action id"})
			}
			if actionID := strings.TrimSpace(step.Metadata["action_id"]); actionID != "" && !reconcileCommandHasFlagValue(step.CommandTemplate, "--action-id", actionID) {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template action id does not match action metadata"})
			}
			if nodeID := strings.TrimSpace(step.NodeID); nodeID != "" && !reconcileCommandHasFlagValue(step.CommandTemplate, "--node", nodeID) {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template node does not match step node id"})
			}
			if operation := strings.TrimSpace(step.Operation); operation != "" && !reconcileCommandHasFlagValue(step.CommandTemplate, "--operation", operation) {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template operation does not match step operation"})
			}
		}
		if !step.RequiresVerification {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "requires_verification", Message: "step does not require verification"})
		}
		if strings.TrimSpace(step.RequiredEvidence) == "" {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "required_evidence", Message: "step has no required evidence"})
		}
		if len(step.SuccessCriteria) == 0 {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "warning", Step: step.Step, Field: "success_criteria", Message: "step has no success criteria"})
		}
		if strings.TrimSpace(step.FailureAction) == "" {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "warning", Step: step.Step, Field: "failure_action", Message: "step has no failure action"})
		}
		if step.Operation == "container_reconcile" && strings.TrimSpace(step.Metadata["container"]) == "" {
			report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "metadata.container", Message: "container reconcile step has no container metadata"})
		}
		if step.Operation == "container_reconcile" {
			if container := strings.TrimSpace(step.Metadata["container"]); container != "" && !reconcileCommandHasFlagValue(step.CommandTemplate, "--container", container) {
				report.Findings = append(report.Findings, reconcileCheckFinding{Severity: "critical", Step: step.Step, Field: "command_template", Message: "step command template container does not match container metadata"})
			}
			report.Findings = append(report.Findings, reconcileContainerEvidenceFindings(step)...)
			report.Findings = append(report.Findings, reconcileContainerCriteriaFindings(step)...)
		}
	}
	containerSteps := reconcileContainerRunbookStepSet(runbook.Steps)
	for _, finding := range report.Findings {
		report.Counts["findings"]++
		report.Counts["runbook_findings"]++
		report.Counts[finding.Severity]++
		if containerSteps[finding.Step] {
			report.Counts["container_runbook_findings"]++
		}
		if finding.Field == "runbook_ready" {
			report.Counts["runbook_ready_findings"]++
		}
		if finding.Field == "steps" {
			report.Counts["steps_findings"]++
		}
		if finding.Field == "node_id" {
			report.Counts["node_id_findings"]++
		}
		if finding.Field == "metadata.container" {
			report.Counts["metadata_container_findings"]++
		}
		if finding.Field == "command_template" {
			report.Counts["command_template_findings"]++
		}
		if finding.Field == "required_evidence" {
			report.Counts["required_evidence_findings"]++
		}
		if finding.Field == "success_criteria" {
			report.Counts["success_criteria_findings"]++
		}
		if finding.Field == "failure_action" {
			report.Counts["failure_action_findings"]++
		}
		if finding.Field == "requires_verification" {
			report.Counts["requires_verification_findings"]++
		}
		if finding.Severity == "critical" {
			report.Ready = false
			report.Status = "blocked"
		}
	}
	if report.Ready {
		report.Counts["runbook_check_ready"] = 1
	} else {
		report.Counts["runbook_check_blocked"] = 1
	}
	return report
}

func reconcileContainerRunbookStepSet(steps []reconcileRunbookStep) map[int]bool {
	out := make(map[int]bool)
	for _, step := range steps {
		if step.Operation == "container_reconcile" {
			out[step.Step] = true
		}
	}
	return out
}

func reconcileCommandHasFlagValue(command string, flag string, value string) bool {
	command = strings.TrimSpace(command)
	flag = strings.TrimSpace(flag)
	value = strings.TrimSpace(value)
	if command == "" || flag == "" || value == "" {
		return false
	}
	for _, candidate := range []string{flag + " " + value, flag + " '" + value + "'", flag + " \"" + value + "\""} {
		if reconcileCommandContainsToken(command, candidate) {
			return true
		}
	}
	return false
}

func reconcileCommandContainsToken(command string, candidate string) bool {
	index := strings.Index(command, candidate)
	for index >= 0 {
		end := index + len(candidate)
		if end == len(command) || command[end] == ' ' || command[end] == '\t' {
			return true
		}
		next := strings.Index(command[index+1:], candidate)
		if next < 0 {
			return false
		}
		index += next + 1
	}
	return false
}

func reconcileCommandReferencesValue(command string, value string) bool {
	value = strings.TrimSpace(value)
	if value == "" {
		return false
	}
	for _, candidate := range []string{value, "'" + value + "'", "\"" + value + "\""} {
		if reconcileCommandContainsToken(command, candidate) {
			return true
		}
	}
	return false
}

func reconcileContainerEvidenceFindings(step reconcileRunbookStep) []reconcileCheckFinding {
	required := strings.ToLower(step.RequiredEvidence)
	var findings []reconcileCheckFinding
	for _, want := range []string{"agent-collect", "container-logscan"} {
		if !strings.Contains(required, want) {
			findings = append(findings, reconcileCheckFinding{
				Severity: "critical",
				Step:     step.Step,
				Field:    "required_evidence",
				Message:  fmt.Sprintf("container reconcile step must require %s evidence", want),
			})
		}
	}
	return findings
}

func reconcileContainerCriteriaFindings(step reconcileRunbookStep) []reconcileCheckFinding {
	var findings []reconcileCheckFinding
	criteria := strings.Join(step.SuccessCriteria, " ")
	for _, field := range []struct {
		key   string
		label string
	}{
		{key: "desired_state", label: "state"},
		{key: "desired_image", label: "image"},
		{key: "desired_health", label: "health"},
		{key: "desired_restart", label: "restart policy"},
	} {
		value := strings.TrimSpace(step.Metadata[field.key])
		if value == "" {
			continue
		}
		want := fmt.Sprintf("Docker container %s equals %s", field.label, value)
		if !strings.Contains(criteria, want) {
			findings = append(findings, reconcileCheckFinding{
				Severity: "critical",
				Step:     step.Step,
				Field:    "success_criteria",
				Message:  fmt.Sprintf("container desired %s metadata has no matching success criteria", field.label),
			})
		}
	}
	return findings
}

func buildReconcileRollbackPlanReport(checkPath string, record evidence.Record, check reconcileRunbookCheckReport) reconcileRollbackPlanReport {
	report := reconcileRollbackPlanReport{
		Kind:                     "meshclaw_reconcile_rollback_plan",
		Mode:                     "plan_only",
		Status:                   "ready",
		Ready:                    true,
		SchemaVersion:            strings.TrimSpace(check.SchemaVersion),
		RunbookCheckEvidencePath: checkPath,
		RunbookCheckEvidenceID:   record.ID,
		RunbookCheck:             check,
		Counts:                   copyIntMap(check.Counts),
		GeneratedAt:              time.Now().UTC(),
		Next: []string{
			"Review rollback guidance before any future executor is implemented.",
			"Future executor must attach rollback-plan evidence before mutating servers.",
			"Rollback actions remain guidance until explicit approval-gated execution exists.",
		},
		Safety: map[string]string{
			"mutation": "disabled; rollback guidance only",
			"execute":  "not implemented",
			"approval": "future rollback execution must pass policy and evidence gates",
		},
	}
	if !check.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "runbook check is not ready")
		for _, finding := range check.Findings {
			if finding.Severity == "critical" {
				report.Reasons = append(report.Reasons, finding.Message)
			}
		}
		report.Counts["rollback_plan_blocked"] = 1
		return report
	}
	for _, step := range check.Runbook.Steps {
		report.Steps = append(report.Steps, reconcileRollbackStep{
			Step:             step.Step,
			NodeID:           step.NodeID,
			Operation:        step.Operation,
			Trigger:          "verification failure or operator abort after step",
			RollbackAction:   reconcileRollbackActionForOperation(step.Operation),
			RequiredEvidence: step.RequiredEvidence,
			SuccessCriteria:  step.SuccessCriteria,
			Metadata:         copyStringMap(step.Metadata),
		})
	}
	report.Counts["rollback_steps"] = len(report.Steps)
	report.Counts["container_rollback_steps"] = countContainerRollbackSteps(report.Steps)
	report.Counts["rollback_plan_ready"] = 1
	return report
}

func reconcileRollbackActionForOperation(operation string) string {
	switch operation {
	case "container_reconcile":
		return "stop container reconcile loop and restore previous container state from approved rollback evidence"
	case "service_reconcile":
		return "restore previous service state or escalate service rollback approval"
	case "capacity_remediation":
		return "stop cleanup/remediation and restore archived data when available"
	case "offline_node_diagnosis":
		return "stop automated repair and request manual connectivity review"
	case "inventory_review":
		return "revert desired inventory change or refresh node inventory evidence"
	default:
		return "stop reconcile loop and create rollback approval evidence"
	}
}

func buildReconcileCompletionPlanReport(rollbackPath string, record evidence.Record, rollback reconcileRollbackPlanReport) reconcileCompletionPlanReport {
	report := reconcileCompletionPlanReport{
		Kind:                     "meshclaw_reconcile_completion_plan",
		Mode:                     "plan_only",
		Status:                   "ready",
		Ready:                    true,
		SchemaVersion:            strings.TrimSpace(rollback.SchemaVersion),
		RollbackPlanEvidencePath: rollbackPath,
		RollbackPlanEvidenceID:   record.ID,
		RollbackPlan:             rollback,
		Counts:                   copyIntMap(rollback.Counts),
		GeneratedAt:              time.Now().UTC(),
		Next: []string{
			"Do not mark reconcile complete until all completion requirements are satisfied.",
			"Attach final node evidence and rollback-plan evidence to completion records.",
			"Future executor must store reconcile-complete evidence only after verification passes.",
		},
		Safety: map[string]string{
			"mutation":   "disabled; completion requirements only",
			"execute":    "not implemented",
			"completion": "future completion requires final evidence for every planned step",
		},
	}
	if !rollback.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "rollback plan is not ready")
		report.Reasons = append(report.Reasons, rollback.Reasons...)
		report.Counts["completion_plan_blocked"] = 1
		return report
	}
	report.Requirements = append(report.Requirements, reconcileCompletionRequirement{
		RequiredEvidence: "reconcile-rollback-plan",
		Criteria: []string{
			"rollback guidance evidence is stored",
			"rollback plan is ready",
		},
	})
	for _, step := range rollback.Steps {
		report.Requirements = append(report.Requirements, reconcileCompletionRequirement{
			Step:             step.Step,
			NodeID:           step.NodeID,
			RequiredEvidence: step.RequiredEvidence,
			Metadata:         copyStringMap(step.Metadata),
			Criteria: []string{
				"post-action evidence exists for the step",
				"success criteria are satisfied or rollback guidance is followed",
				"no critical runbook-check finding remains open",
			},
		})
	}
	report.Requirements = append(report.Requirements, reconcileCompletionRequirement{
		RequiredEvidence: "reconcile-complete",
		Criteria: []string{
			"all step requirements passed",
			"final operator-visible evidence summary is stored",
		},
	})
	report.Counts["completion_requirements"] = len(report.Requirements)
	report.Counts["container_completion_requirements"] = countContainerCompletionRequirements(report.Requirements)
	report.Counts["completion_plan_ready"] = 1
	return report
}

func buildReconcileReadinessSummaryReport(completionPath string, record evidence.Record, completion reconcileCompletionPlanReport) reconcileReadinessSummaryReport {
	report := reconcileReadinessSummaryReport{
		Kind:                       "meshclaw_reconcile_readiness_summary",
		Mode:                       "summary_only",
		Status:                     "ready",
		Ready:                      true,
		SchemaVersion:              strings.TrimSpace(completion.SchemaVersion),
		CompletionPlanEvidencePath: completionPath,
		CompletionPlanEvidenceID:   record.ID,
		CompletionPlan:             completion,
		Counts:                     copyIntMap(completion.Counts),
		ExecutorGateContract:       reconcileExecutorGateContract(),
		GeneratedAt:                time.Now().UTC(),
		Next: []string{
			"Use this summary as the operator-visible readiness checkpoint before any future apply implementation.",
			"Keep apply disabled until every listed stage remains ready with matching evidence.",
			"Refresh the reconcile chain if desired state, node state, approval, or policy evidence changes.",
		},
		StopBefore: []string{
			"treating readiness summary as operator approval",
			"starting an executor without ready completion-plan evidence",
			"skipping approval-request, apply-gate, or verification evidence review",
			"closing desired-state reconciliation without rollback and audit evidence",
		},
		Safety: map[string]string{
			"mutation":  "disabled; readiness summary only",
			"execute":   "not implemented",
			"readiness": "future executor must require ready completion-plan evidence and final verification",
		},
	}
	ensureIntCount(report.Counts, "completion_requirements", len(completion.Requirements))
	ensureIntCount(report.Counts, "rollback_steps", len(completion.RollbackPlan.Steps))
	ensureIntCount(report.Counts, "runbook_steps", len(completion.RollbackPlan.RunbookCheck.Runbook.Steps))
	ensureIntCount(report.Counts, "runbook_findings", len(completion.RollbackPlan.RunbookCheck.Findings))
	ensureIntCount(report.Counts, "runbook_ready_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "runbook_ready"))
	ensureIntCount(report.Counts, "steps_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "steps"))
	ensureIntCount(report.Counts, "node_id_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "node_id"))
	ensureIntCount(report.Counts, "metadata_container_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "metadata.container"))
	ensureIntCount(report.Counts, "command_template_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "command_template"))
	ensureIntCount(report.Counts, "required_evidence_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "required_evidence"))
	ensureIntCount(report.Counts, "success_criteria_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "success_criteria"))
	ensureIntCount(report.Counts, "failure_action_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "failure_action"))
	ensureIntCount(report.Counts, "requires_verification_findings", countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "requires_verification"))
	ensureIntCount(report.Counts, "verification_checks", len(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.Checks))
	ensureIntCount(report.Counts, "execution_commands", len(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.ExecutionPreview.Commands))
	ensureIntCount(report.Counts, "apply_steps", len(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.ExecutionPreview.ApplyPlan.Steps))
	ensureIntCount(report.Counts, "container_apply_steps", countContainerApplySteps(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.ExecutionPreview.ApplyPlan.Steps))
	ensureIntCount(report.Counts, "container_execution_commands", countContainerExecutionCommands(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.ExecutionPreview.Commands))
	ensureIntCount(report.Counts, "container_verification_checks", countContainerVerificationChecks(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.Checks))
	ensureIntCount(report.Counts, "container_runbook_steps", countContainerRunbookSteps(completion.RollbackPlan.RunbookCheck.Runbook.Steps))
	ensureIntCount(report.Counts, "container_runbook_findings", countContainerRunbookFindings(completion.RollbackPlan.RunbookCheck.Runbook.Steps, completion.RollbackPlan.RunbookCheck.Findings))
	ensureIntCount(report.Counts, "container_rollback_steps", countContainerRollbackSteps(completion.RollbackPlan.Steps))
	ensureIntCount(report.Counts, "container_completion_requirements", countContainerCompletionRequirements(completion.Requirements))
	ensureIntCount(report.Counts, "executor_contract_must_have", len(report.ExecutorGateContract.MustHave))
	ensureIntCount(report.Counts, "executor_contract_must_not", len(report.ExecutorGateContract.MustNot))
	ensureIntCount(report.Counts, "executor_contract_refresh_triggers", len(report.ExecutorGateContract.RefreshTriggers))
	if !completion.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Blockers = append(report.Blockers, "completion plan is not ready")
		report.Blockers = append(report.Blockers, completion.Reasons...)
		report.Counts["completion_plan_blockers"] = 1
		report.Counts["readiness_summary_blocked"] = 1
		report.Counts["readiness_blockers"] = len(report.Blockers)
		return report
	}
	report.ReadyStages = []string{
		"approval_request",
		"apply_gate",
		"apply_plan",
		"execution_preview",
		"verification_plan",
		"runbook",
		"runbook_check",
		"rollback_plan",
		"completion_plan",
	}
	if len(completion.Requirements) == 0 {
		report.Ready = false
		report.Status = "blocked"
		report.Blockers = append(report.Blockers, "completion plan has no requirements")
		report.Counts["completion_requirements_blockers"] = 1
	}
	if report.Ready {
		report.Counts["readiness_summary_ready"] = 1
	} else {
		report.Counts["readiness_summary_blocked"] = 1
	}
	report.Counts["readiness_stages"] = len(report.ReadyStages)
	report.Counts["readiness_blockers"] = len(report.Blockers)
	return report
}

