func ensureIntCount(counts map[string]int, key string, value int) {
	if _, ok := counts[key]; !ok {
		counts[key] = value
	}
}

func countContainerApplySteps(steps []reconcileApplyStep) int {
	count := 0
	for _, step := range steps {
		if step.Operation == "container_reconcile" || strings.TrimSpace(step.Metadata["container"]) != "" {
			count++
		}
	}
	return count
}

func countContainerExecutionCommands(commands []reconcileExecutionCommand) int {
	count := 0
	for _, command := range commands {
		if command.Operation == "container_reconcile" || strings.TrimSpace(command.Metadata["container"]) != "" {
			count++
		}
	}
	return count
}

