func annotateReconcileResultPolicy(result *reconciler.Result) {
	for i := range result.Actions {
		action := &result.Actions[i]
		resource := reconcilePolicyResource(*action)
		decision := policy.Evaluate(policy.Request{
			Subject:  "meshclaw-reconciler",
			Action:   action.PolicyAction,
			Resource: resource,
			Context:  action.Summary,
		})
		action.PolicyResource = resource
		action.PolicyDecision = string(decision.Decision)
		action.PolicyReason = decision.Reason
		if decision.Decision == policy.RequireApproval || decision.Decision == policy.Deny {
			action.ApprovalRequired = true
		}
	}
}

func reconcilePolicyResource(action reconciler.Action) string {
	switch action.PolicyAction {
	case "deny":
		return "server"
	case "plan_only":
		return "reconcile_plan"
	default:
		return "server"
	}
}

func reconcileActualReports(args []string) (map[string]reconciler.ActualNode, []string, error) {
	paths := reconcileActualReportPaths(args)
	actuals := map[string]reconciler.ActualNode{}
	for _, path := range paths {
		actual, err := reconciler.LoadActualNodeReport(path)
		if err != nil {
			return nil, nil, err
		}
		if actual.ID != "" {
			actuals[actual.ID] = actual
		}
	}
	return actuals, paths, nil
}

func reconcileActualReportPaths(args []string) []string {
	filtered := withoutJSONFlag(args)
	var paths []string
	for i := 0; i < len(filtered); i++ {
		switch filtered[i] {
		case "--actual-report", "--actual", "--node-report":
			if i+1 < len(filtered) {
				for _, path := range splitCSV(filtered[i+1]) {
					if strings.TrimSpace(path) != "" {
						paths = append(paths, path)
					}
				}
				i++
			}
		}
	}
	return paths
}

func reconcileDesiredPath(args []string) string {
	filtered := withoutJSONFlag(args)
	for i := 0; i < len(filtered); i++ {
		switch filtered[i] {
		case "--desired", "-desired", "--file", "-f":
			if i+1 < len(filtered) {
				return filtered[i+1]
			}
		default:
			if !strings.HasPrefix(filtered[i], "-") {
				return filtered[i]
			}
		}
	}
	return ""
}

