func buildAutohealPlan(m *monitor.Monitor, serviceTriage serviceTriageReport) []monitor.HealPlanAction {
	actions := monitor.NewAutoHealer(m).Plan()
	actions = append(actions, serviceTriagePlanActions(serviceTriage)...)
	actions = append(actions, containerHealthPlanActionsFromStoredReports(24*time.Hour)...)
	annotateHealPlanPolicies(actions)
	return actions
}

func containerHealthPlanActionsFromStoredReports(maxAge time.Duration) []monitor.HealPlanAction {
	storedReports, err := nodestate.List(maxAge)
	if err != nil {
		return nil
	}
	return containerHealthPlanActions(latestStoredReportsByNode(storedReports))
}

func containerHealthPlanActions(storedReports []nodestate.StoredReport) []monitor.HealPlanAction {
	var actions []monitor.HealPlanAction
	for _, stored := range storedReports {
		node := firstNonEmpty(stored.Report.NodeName, stored.Report.Hostname)
		actions = append(actions, monitor.ContainerHealthPlan(node, stored.Report.Docker)...)
	}
	return actions
}

