func buildContainerApplyPlanReport(planPath string, record evidence.Record, plan autohealPlanReport, approvedBy string) containerApplyPlanReport {
	report := containerApplyPlanReport{
		Kind:                           "meshclaw_container_apply_plan",
		Mode:                           "plan_only",
		Status:                         "ready",
		Ready:                          true,
		PlanEvidencePath:               planPath,
		PlanEvidenceID:                 record.ID,
		ApprovedBy:                     strings.TrimSpace(approvedBy),
		DirectRestartAllowed:           false,
		RequiresFocusedRuntimeEvidence: true,
		NextRequiredTool:               "meshclaw_autoheal_container_verification_plan",
		GeneratedAt:                    time.Now().UTC(),
		Next: []string{
			"Review command templates before any executor implementation.",
			"Collect container logs and fresh node report evidence before applying.",
			"Store post-action verification evidence after any future container mutation.",
		},
		StopBefore: []string{
			"executing command templates; this report is plan-only",
			"operator approval if approved_by is empty",
			"container mutation without agent-collect+container-logscan evidence",
			"declaring repair complete before verification and rollback evidence exist",
		},
		Safety: map[string]string{
			"mutation": "disabled; command templates are inert previews",
			"execute":  "not implemented",
			"approval": "requires explicit approved_by before readiness",
		},
	}
	if report.ApprovedBy == "" {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "approved_by is required before container apply planning is ready")
	}
	for _, action := range plan.Actions {
		if action.Type != "container_restart" {
			continue
		}
		if action.PolicyDecision != string(policy.RequireApproval) || !action.ApprovalRequired {
			report.Reasons = append(report.Reasons, fmt.Sprintf("container action %s/%s is missing approval-required policy metadata", action.Node, action.Container))
			report.Ready = false
			report.Status = "blocked"
			continue
		}
		report.Steps = append(report.Steps, containerApplyStep{
			Step:                    len(report.Steps) + 1,
			NodeID:                  action.Node,
			Container:               action.Container,
			Operation:               action.Type,
			CommandTemplate:         action.Command,
			Verify:                  action.Verify,
			RequiredEvidence:        "agent-collect+container-logscan",
			RuntimeEvidenceRequired: "fresh runtime inspect/status evidence with image, status, health, ports, and restart policy",
			SuccessCriteria: []string{
				"fresh node report collected after the future container action",
				"container is running and not unhealthy",
				"no fresh OOM/crash-loop log finding is present",
			},
		})
		if report.Steps[len(report.Steps)-1].RuntimeEvidenceRequired != "" {
			report.RuntimeEvidenceRequiredCount++
		}
	}
	if len(report.Steps) == 0 {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "autoheal plan contains no container restart actions")
	}
	return report
}

func buildContainerCompletionPlanReport(rollbackPath string, record evidence.Record, rollback containerRollbackPlanReport) containerCompletionPlanReport {
	report := containerCompletionPlanReport{
		Kind:                     "meshclaw_container_completion_plan",
		Mode:                     "plan_only",
		Status:                   "ready",
		Ready:                    true,
		RollbackPlanEvidencePath: rollbackPath,
		RollbackPlanEvidenceID:   record.ID,
		RollbackPlan:             rollback,
		GeneratedAt:              time.Now().UTC(),
		Next: []string{
			"Do not mark container remediation complete until all completion requirements are satisfied.",
			"Attach final node report, logscan evidence, and rollback-plan evidence to completion records.",
			"Future executor must store container-complete evidence only after verification passes.",
		},
		Safety: map[string]string{
			"mutation":   "disabled; completion requirements only",
			"execute":    "not implemented",
			"completion": "future completion requires final evidence for every planned container step",
		},
	}
	if !rollback.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Reasons = append(report.Reasons, "container rollback plan is not ready")
		report.Reasons = append(report.Reasons, rollback.Reasons...)
		return report
	}
	report.Requirements = append(report.Requirements, containerCompletionRequirement{
		RequiredEvidence: "container-rollback-plan",
		Criteria: []string{
			"rollback guidance evidence is stored",
			"rollback plan is ready",
		},
	})
	for _, step := range rollback.Steps {
		report.Requirements = append(report.Requirements, containerCompletionRequirement{
			Step:                    step.Step,
			NodeID:                  step.NodeID,
			Container:               step.Container,
			RequiredEvidence:        step.RequiredEvidence,
			RuntimeEvidenceRequired: step.RuntimeEvidenceRequired,
			LogscanPatterns:         copyStrings(step.LogscanPatterns),
			LogscanHints:            copyLogscanHints(step.LogscanHints),
			Criteria: []string{
				"post-action node report evidence exists for the container step",
				"container success criteria are satisfied or rollback guidance is followed",
				"no critical container runbook-check finding remains open",
				"no fresh OOM/crash-loop log finding remains for the container",
			},
		})
	}
	report.Requirements = append(report.Requirements, containerCompletionRequirement{
		RequiredEvidence: "container-complete",
		Criteria: []string{
			"all container step requirements passed",
			"final operator-visible evidence summary is stored",
		},
	})
	return report
}

func buildContainerReadinessSummaryReport(completionPath string, record evidence.Record, completion containerCompletionPlanReport) containerReadinessSummaryReport {
	report := containerReadinessSummaryReport{
		Kind:                       "meshclaw_container_readiness_summary",
		Mode:                       "summary_only",
		Status:                     "ready",
		Ready:                      true,
		CompletionPlanEvidencePath: completionPath,
		CompletionPlanEvidenceID:   record.ID,
		CompletionPlan:             completion,
		Counts:                     map[string]int{},
		LogscanPatterns:            containerCompletionLogscanPatterns(completion.Requirements),
		LogscanHints:               containerCompletionLogscanHints(completion.Requirements),
		ApplyLoopGates:             containerApplyLoopGates(),
		ExecutorGateContract:       containerExecutorGateContract(),
		GeneratedAt:                time.Now().UTC(),
		Next: []string{
			"Use this summary as the operator-visible checkpoint before any future container executor.",
			"Keep container apply disabled until every listed stage remains ready with matching evidence.",
			"Refresh the container self-heal chain if node reports, logs, approval, or policy evidence changes.",
		},
		StopBefore: []string{
			"treating readiness summary as operator approval",
			"starting an executor without ready completion-plan evidence",
			"skipping final container-logscan evidence review",
			"closing the repair without rollback and audit evidence",
		},
		Safety: map[string]string{
			"mutation":  "disabled; readiness summary only",
			"execute":   "not implemented",
			"readiness": "future executor must require ready completion-plan evidence and final verification",
		},
	}
	report.Counts["completion_requirements"] = len(completion.Requirements)
	report.Counts["rollback_steps"] = len(completion.RollbackPlan.Steps)
	report.Counts["runbook_steps"] = len(completion.RollbackPlan.RunbookCheck.Runbook.Steps)
	report.Counts["runbook_findings"] = len(completion.RollbackPlan.RunbookCheck.Findings)
	report.Counts["runbook_ready_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "runbook_ready")
	report.Counts["steps_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "steps")
	report.Counts["node_id_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "node_id")
	report.Counts["container_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "container")
	report.Counts["command_template_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "command_template")
	report.Counts["required_evidence_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "required_evidence")
	report.Counts["runtime_evidence_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "runtime_evidence_required")
	report.Counts["success_criteria_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "success_criteria")
	report.Counts["failure_action_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "failure_action")
	report.Counts["requires_verification_findings"] = countReconcileFindingsByField(completion.RollbackPlan.RunbookCheck.Findings, "requires_verification")
	report.Counts["verification_checks"] = len(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.Checks)
	report.Counts["apply_steps"] = len(completion.RollbackPlan.RunbookCheck.Runbook.VerificationPlan.ApplyPlan.Steps)
	report.Counts["logscan_patterns"] = len(report.LogscanPatterns)
	report.Counts["logscan_hints"] = len(report.LogscanHints)
	report.Counts["apply_loop_gates"] = len(report.ApplyLoopGates)
	report.Counts["executor_contract_must_have"] = len(report.ExecutorGateContract.MustHave)
	report.Counts["executor_contract_must_not"] = len(report.ExecutorGateContract.MustNot)
	report.Counts["executor_contract_refresh_triggers"] = len(report.ExecutorGateContract.RefreshTriggers)
	if !completion.Ready {
		report.Ready = false
		report.Status = "blocked"
		report.Blockers = append(report.Blockers, "container completion plan is not ready")
		report.Blockers = append(report.Blockers, completion.Reasons...)
		report.Counts["completion_plan_blockers"] = 1
		report.Counts["readiness_summary_blocked"] = 1
		report.Counts["readiness_blockers"] = len(report.Blockers)
		return report
	}
	report.ReadyStages = []string{
		"autoheal_plan",
		"container_apply_plan",
		"container_verification_plan",
		"container_runbook",
		"container_runbook_check",
		"container_rollback_plan",
		"container_completion_plan",
	}
	if len(completion.Requirements) == 0 {
		report.Ready = false
		report.Status = "blocked"
		report.Blockers = append(report.Blockers, "container completion plan has no requirements")
		report.Counts["completion_requirements_blockers"] = 1
	}
	if report.Ready {
		report.Counts["readiness_summary_ready"] = 1
	} else {
		report.Counts["readiness_summary_blocked"] = 1
	}
	report.Counts["readiness_stages"] = len(report.ReadyStages)
	report.Counts["readiness_blockers"] = len(report.Blockers)
	return report
}

func buildContainerExecutorGateReport(readinessPath string, record evidence.Record, summary containerReadinessSummaryReport, approvedBy string, dryRun bool, executeRequested bool) containerExecutorGateReport {
	report := containerExecutorGateReport{
		Kind:                         "meshclaw_container_executor_gate",
		Mode:                         "admission_only",
		Status:                       "ready",
		Ready:                        true,
		ReadinessSummaryEvidencePath: readinessPath,
		ReadinessSummaryEvidenceID:   record.ID,
		ApprovedBy:                   strings.TrimSpace(approvedBy),
		DryRun:                       dryRun,
		ExecuteRequested:             executeRequested,
		LiveExecutionAllowed:         false,
		ReadinessSummary:             summary,
		GeneratedAt:                  time.Now().UTC(),
		Next: []string{
			"Run a dry-run container executor preview from this gate evidence.",
			"Require a separate live-executor approval before any docker command is executed.",
			"Refresh readiness evidence if node reports, logs, policy, approval, or rollback evidence changed.",
		},
		StopBefore: []string{
			"executing docker commands from gate evidence",
			"treating executor gate as live execution approval",
			"running without dry-run preview evidence",
			"running when readiness summary has blockers",
		},
		Safety: map[string]string{
			"mutation":       "disabled; executor admission only",
			"execute":        "not implemented in gate",
			"live_execution": "requires a separate approved executor",
		},
	}
	report.addExecutorGateCheck("readiness_summary_ready", summary.Ready, true, summary.Status)
	report.addExecutorGateCheck("operator_approval_present", report.ApprovedBy != "", true, report.ApprovedBy)
	report.addExecutorGateCheck("dry_run_required", dryRun, true, fmt.Sprintf("dry_run=%t", dryRun))
	report.addExecutorGateCheck("execute_not_requested", !executeRequested, true, fmt.Sprintf("execute=%t", executeRequested))
	report.addExecutorGateCheck("completion_plan_present", summary.CompletionPlan.Kind == "meshclaw_container_completion_plan", true, summary.CompletionPlan.Kind)
	report.addExecutorGateCheck("apply_loop_gates_present", len(summary.ApplyLoopGates) > 0, true, fmt.Sprintf("gates=%d", len(summary.ApplyLoopGates)))
	report.addExecutorGateCheck("final_logscan_requirements_present", len(summary.LogscanPatterns) > 0 || len(summary.LogscanHints) > 0, true, fmt.Sprintf("patterns=%d hints=%d", len(summary.LogscanPatterns), len(summary.LogscanHints)))
	if len(summary.Blockers) > 0 {
		report.Blockers = append(report.Blockers, summary.Blockers...)
	}
	for _, check := range report.Checks {
		if check.Required && !check.Passed {
			report.Blockers = append(report.Blockers, check.Name)
		}
	}
	if len(report.Blockers) > 0 {
		report.Ready = false
		report.Status = "blocked"
	}
	return report
}

func (report *containerExecutorGateReport) addExecutorGateCheck(name string, passed bool, required bool, detail string) {
	report.Checks = append(report.Checks, containerExecutorGateCheck{Name: name, Passed: passed, Required: required, Detail: detail})
}

const containerExecutorLiveApprovalPhrase = "execute container self-heal approved"

func buildContainerExecutorReport(gatePath string, record evidence.Record, gate containerExecutorGateReport, approvedBy string, dryRun bool, executeRequested bool, liveApprovalPhrase string) containerExecutorReport {
	report := containerExecutorReport{
		Kind:                     "meshclaw_container_executor",
		Mode:                     "dry_run",
		Status:                   "ready",
		Ready:                    true,
		DryRun:                   dryRun,
		ExecuteRequested:         executeRequested,
		ExecutorGateEvidencePath: gatePath,
		ExecutorGateEvidenceID:   record.ID,
		ApprovedBy:               strings.TrimSpace(approvedBy),
		ExecutorGate:             gate,
		GeneratedAt:              time.Now().UTC(),
		Next: []string{
			"Review dry-run steps before live execution.",
			"Collect post-action agent-collect and container-logscan evidence after every live step.",
			"Stop immediately and follow rollback-plan evidence if any step or verification fails.",
		},
		StopBefore: []string{
			"executing if executor gate is not ready",
			"executing without approved_by matching the executor gate",
			"executing without exact live approval phrase",
			"continuing after any failed container restart",
			"closing remediation without post-action verification evidence",
		},
		Safety: map[string]string{
			"mutation":       "dry-run by default; live mode restarts only validated runbook containers",
			"command_source": "commands are reconstructed from validated runbook node/container fields, not copied from chat",
			"live_approval":  "requires exact phrase: " + containerExecutorLiveApprovalPhrase,
		},
	}
	if executeRequested && !dryRun {
		report.Mode = "live"
	}
	report.LiveApprovalPhraseOK = strings.TrimSpace(liveApprovalPhrase) == containerExecutorLiveApprovalPhrase
	if !gate.Ready {
		report.Blockers = append(report.Blockers, "executor gate is not ready")
		report.Blockers = append(report.Blockers, gate.Blockers...)
	}
	if report.ApprovedBy == "" {
		report.Blockers = append(report.Blockers, "approved_by is required")
	} else if gate.ApprovedBy != "" && report.ApprovedBy != gate.ApprovedBy {
		report.Blockers = append(report.Blockers, "approved_by does not match executor gate approval identity")
	}
	if executeRequested && !dryRun && !report.LiveApprovalPhraseOK {
		report.Blockers = append(report.Blockers, "live_approval_phrase must exactly equal "+containerExecutorLiveApprovalPhrase)
	}
	runbook := gate.ReadinessSummary.CompletionPlan.RollbackPlan.RunbookCheck.Runbook
	for _, step := range runbook.Steps {
		if step.Operation != "container_restart" {
			report.Blockers = append(report.Blockers, fmt.Sprintf("unsupported operation step=%d operation=%s", step.Step, step.Operation))
			continue
		}
		node := strings.TrimSpace(step.NodeID)
		container := strings.TrimSpace(step.Container)
		if node == "" || container == "" {
			report.Blockers = append(report.Blockers, fmt.Sprintf("step=%d has empty node or container", step.Step))
			continue
		}
		report.Steps = append(report.Steps, containerExecutorStep{
			Step:             step.Step,
			NodeID:           node,
			Container:        container,
			Operation:        step.Operation,
			Command:          "docker restart " + shellQuote(container),
			WouldExecute:     executeRequested && !dryRun,
			RequiredEvidence: step.RequiredEvidence,
			VerifyAfter: []string{
				"meshclaw agent collect --json --store --evidence on " + node,
				"meshclaw analyze-logs " + node + " container:" + container,
				"review container completion-plan requirements before closeout",
			},
		})
	}
	if len(report.Steps) == 0 {
		report.Blockers = append(report.Blockers, "executor gate has no validated container restart steps")
	}
	if len(report.Blockers) > 0 {
		report.Ready = false
		report.Status = "blocked"
	} else if executeRequested && !dryRun {
		report.LiveExecutionAllowed = true
		report.Status = "ready_to_execute"
	}
	return report
}

func executeContainerExecutorReport(report containerExecutorReport) containerExecutorReport {
	if !report.LiveExecutionAllowed {
		return report
	}
	runner := runtime.NewRunner()
	report.Executed = true
	report.Status = "completed"
	for i := range report.Steps {
		step := &report.Steps[i]
		result := runner.RunEvidence(step.NodeID, step.Command)
		report.Results = append(report.Results, result)
		step.Executed = true
		step.Success = result.Success
		step.Transport = result.Transport
		step.ExitCode = result.ExitCode
		if !result.Success {
			step.Error = strings.TrimSpace(result.Stderr)
			if step.Error == "" {
				step.Error = fmt.Sprintf("execution failed on %s via %s", step.NodeID, result.Transport)
			}
			report.Status = "failed"
			report.Blockers = append(report.Blockers, fmt.Sprintf("step=%d failed: %s", step.Step, step.Error))
			report.LiveExecutionAllowed = false
			break
		}
	}
	return report
}

func buildContainerExecutorVerificationReport(executorPath string, record evidence.Record, executor containerExecutorReport, agentPaths []string, logscanPaths []string) containerExecutorVerificationReport {
	report := containerExecutorVerificationReport{
		Kind:                  "meshclaw_container_executor_verification",
		Mode:                  "gate_only",
		Status:                "ready",
		Ready:                 true,
		ExecutorEvidencePath:  executorPath,
		ExecutorEvidenceID:    record.ID,
		Executor:              executor,
		AgentEvidencePaths:    compactNonEmptyStrings(agentPaths),
		ContainerLogscanPaths: compactNonEmptyStrings(logscanPaths),
		GeneratedAt:           time.Now().UTC(),
		Next: []string{
			"Attach post-action agent-collect evidence for every executed container step.",
			"Attach focused container-logscan evidence for every executed container step.",
			"Only close container remediation after this verification gate is ready.",
		},
		StopBefore: []string{
			"declaring self-heal complete without post-action agent evidence",
			"declaring self-heal complete without focused container-logscan evidence",
			"continuing after a failed executor step",
			"treating dry-run preview as a completed repair",
		},
		Safety: map[string]string{
			"mutation":     "disabled; post-action verification gate only",
			"evidence":     "requires agent-collect and container-logscan evidence after live execution",
			"closeout":     "completion remains blocked until every executed step has verification evidence",
			"dry_run_note": "dry-run executor output is preview evidence, not repair evidence",
		},
	}
	executedSteps := 0
	successfulSteps := 0
	for _, step := range executor.Steps {
		if step.Executed {
			executedSteps++
			if step.Success {
				successfulSteps++
			}
		}
	}
	report.addContainerExecutorPostCheck("executor_was_live", executor.Executed, true, fmt.Sprintf("executed=%t dry_run=%t", executor.Executed, executor.DryRun))
	report.addContainerExecutorPostCheck("executor_status_completed", executor.Status == "completed", true, executor.Status)
	report.addContainerExecutorPostCheck("all_executed_steps_succeeded", executedSteps > 0 && successfulSteps == executedSteps, true, fmt.Sprintf("executed_steps=%d successful_steps=%d", executedSteps, successfulSteps))
	report.addContainerExecutorPostCheck("agent_evidence_per_step", len(report.AgentEvidencePaths) >= executedSteps && executedSteps > 0, true, fmt.Sprintf("agent_evidence=%d executed_steps=%d", len(report.AgentEvidencePaths), executedSteps))
	report.addContainerExecutorPostCheck("container_logscan_evidence_per_step", len(report.ContainerLogscanPaths) >= executedSteps && executedSteps > 0, true, fmt.Sprintf("logscan_evidence=%d executed_steps=%d", len(report.ContainerLogscanPaths), executedSteps))
	for _, blocker := range executor.Blockers {
		report.Blockers = append(report.Blockers, "executor blocker: "+blocker)
	}
	for _, check := range report.Checks {
		if check.Required && !check.Passed {
			report.Blockers = append(report.Blockers, check.Name)
		}
	}
	if len(report.Blockers) > 0 {
		report.Ready = false
		report.Status = "blocked"
	}
	return report
}

func (report *containerExecutorVerificationReport) addContainerExecutorPostCheck(name string, passed bool, required bool, detail string) {
	report.Checks = append(report.Checks, containerExecutorPostCheck{Name: name, Passed: passed, Required: required, Detail: detail})
}

func compactNonEmptyStrings(values []string) []string {
	result := make([]string, 0, len(values))
	for _, value := range values {
		value = strings.TrimSpace(value)
		if value != "" {
			result = append(result, value)
		}
	}
	return result
}

