func containerSelfHealLogscanPatterns() []string {
	return []string{
		"oom",
		"crash_loop",
		"healthcheck_failure",
		"dependency_connection_failure",
		"disk_full",
		"port_bind_failure",
		"image_pull_failure",
		"permission_failure",
		"gpu_runtime_failure",
	}
}

func containerSelfHealLogscanHints() []logscanHint {
	return []logscanHint{
		{Pattern: "oom", Severity: "critical", LikelyCause: "container exceeded its memory limit or the node is under memory pressure", SuggestedAction: "inspect memory limits, restart count, node memory pressure, and recent workload spikes before approving restart or resize"},
		{Pattern: "crash_loop", Severity: "high", LikelyCause: "container process exits repeatedly after start", SuggestedAction: "inspect exit code, recent config changes, dependency availability, and image architecture before restart loops continue"},
		{Pattern: "healthcheck_failure", Severity: "high", LikelyCause: "container health/readiness probe is failing", SuggestedAction: "compare healthcheck command, exposed port, startup time, and recent app errors before self-heal"},
		{Pattern: "dependency_connection_failure", Severity: "high", LikelyCause: "container cannot reach a required upstream dependency", SuggestedAction: "check target service/container health, DNS, route, credentials, and retry policy before restarting this container"},
		{Pattern: "disk_full", Severity: "critical", LikelyCause: "container or node storage is exhausted", SuggestedAction: "run disk investigation and cleanup planning before restart; restart alone may fail again"},
		{Pattern: "port_bind_failure", Severity: "high", LikelyCause: "container cannot bind its expected port because it is already in use or unavailable", SuggestedAction: "inspect listeners and container port mappings before restart or recreate"},
		{Pattern: "image_pull_failure", Severity: "high", LikelyCause: "container image cannot be pulled or resolved", SuggestedAction: "check image name, tag, registry reachability, credentials, and architecture compatibility"},
		{Pattern: "permission_failure", Severity: "medium", LikelyCause: "container lacks permission for a file, device, socket, or mounted path", SuggestedAction: "inspect UID/GID, mount ownership, device permissions, and security policy before retrying"},
		{Pattern: "gpu_runtime_failure", Severity: "high", LikelyCause: "container cannot access GPU runtime, driver, or CUDA/NVIDIA device", SuggestedAction: "check nvidia-smi, container runtime GPU flags, driver state, and whether a host reboot is pending"},
	}
}

func copyStrings(values []string) []string {
	if len(values) == 0 {
		return nil
	}
	out := make([]string, 0, len(values))
	for _, value := range values {
		if trimmed := strings.TrimSpace(value); trimmed != "" {
			out = append(out, trimmed)
		}
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

func copyLogscanHints(values []logscanHint) []logscanHint {
	if len(values) == 0 {
		return nil
	}
	out := make([]logscanHint, 0, len(values))
	for _, value := range values {
		value.Pattern = strings.TrimSpace(value.Pattern)
		value.Severity = strings.TrimSpace(value.Severity)
		value.LikelyCause = strings.TrimSpace(value.LikelyCause)
		value.SuggestedAction = strings.TrimSpace(value.SuggestedAction)
		if value.Pattern == "" {
			continue
		}
		out = append(out, value)
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

func containerCompletionLogscanPatterns(requirements []containerCompletionRequirement) []string {
	seen := map[string]bool{}
	var out []string
	for _, requirement := range requirements {
		for _, pattern := range requirement.LogscanPatterns {
			pattern = strings.TrimSpace(pattern)
			if pattern == "" || seen[pattern] {
				continue
			}
			seen[pattern] = true
			out = append(out, pattern)
		}
	}
	return out
}

func containerCompletionLogscanHints(requirements []containerCompletionRequirement) []logscanHint {
	seen := map[string]bool{}
	var out []logscanHint
	for _, requirement := range requirements {
		for _, hint := range requirement.LogscanHints {
			hint.Pattern = strings.TrimSpace(hint.Pattern)
			if hint.Pattern == "" || seen[hint.Pattern] {
				continue
			}
			seen[hint.Pattern] = true
			out = append(out, hint)
		}
	}
	return out
}

func buildAutohealPlanReport(actions []monitor.HealPlanAction) autohealPlanReport {
	report := autohealPlanReport{
		Actions:        actions,
		RecommendedMCP: recommendedAutohealPlanMCP(actions),
		Counts:         map[string]int{},
	}
	for _, action := range actions {
		report.Counts["total"]++
		if action.Mode != "" {
			report.Counts["mode_"+action.Mode]++
		}
		if action.ApprovalRequired {
			report.Counts["approval_required"]++
		}
		if action.PolicyDecision != "" {
			report.Counts["policy_"+action.PolicyDecision]++
		}
	}
	return report
}

func annotateHealPlanPolicies(actions []monitor.HealPlanAction) {
	for i := range actions {
		policyAction := policyActionForHealPlan(actions[i])
		result := policy.Evaluate(policy.Request{
			Subject:  "codex",
			Action:   policyAction,
			Resource: "server",
			Context:  actions[i].Command,
		})
		actions[i].PolicyAction = policyAction
		actions[i].PolicyDecision = string(result.Decision)
		actions[i].PolicyReason = result.Reason
		actions[i].ApprovalRequired = result.Decision == policy.RequireApproval || actions[i].Mode == "approval_required" || actions[i].Mode == "requires_approval"
	}
}

func policyActionForHealPlan(action monitor.HealPlanAction) string {
	switch action.Type {
	case "disk_investigate":
		return "disk_investigate"
	case "disk_cleanup", "memory_cleanup":
		return "autoheal_apply_safe"
	case "connectivity":
		return "doctor"
	case "service_triage":
		return "service_check"
	case "service_quarantine_candidate":
		return "service_quarantine"
	case "container_restart":
		return "container_restart"
	default:
		return "run_command"
	}
}

func serviceTriagePlanActions(report serviceTriageReport) []monitor.HealPlanAction {
	actions := make([]monitor.HealPlanAction, 0, len(report.Items))
	for _, item := range report.Items {
		if item.Class == "ignore_candidate" || item.Mode == "ignore_candidate" {
			continue
		}
		mode := item.Mode
		if mode == "" {
			mode = "read_only"
		}
		command := item.Next
		if command == "" && item.Service != "" {
			command = fmt.Sprintf("meshclaw service-check %s %s", item.Host, item.Service)
		}
		if command == "" {
			command = fmt.Sprintf("meshclaw service-audit %s", item.Host)
		}
		service := item.Service
		if service == "" {
			service = "unknown"
		}
		severity := item.Severity
		if severity == "" {
			severity = "warning"
		}
		actionType := "service_triage"
		if item.Class == "stale_or_missing_target" {
			actionType = "service_quarantine_candidate"
		}
		actions = append(actions, monitor.HealPlanAction{
			Node:     item.Host,
			Type:     actionType,
			Severity: severity,
			Metric:   "service:" + service,
			Value:    1,
			Mode:     mode,
			Command:  command,
			Reason:   item.Judgement,
			Verify:   fmt.Sprintf("meshclaw service-check %s %s", item.Host, service),
		})
	}
	return actions
}

func autohealApplySafe() error {
	m, err := monitor.New(monitor.DefaultConfig())
	if err != nil {
		return err
	}
	m.CheckAll()
	serviceTriage, _, serviceStoreErr := buildServiceTriage(nil, 5, 4)
	plan := buildAutohealPlan(m, serviceTriage)
	actions := applyAutohealPlanSafe(plan)
	counts := summarizeAutohealApplySafeActions(actions)
	record, storeErr := evidence.Store("autoheal-apply-safe", "fleet", autohealApplySafeCountsLine(counts), actions)
	if storeErr == nil {
		storeErr = serviceStoreErr
	}
	if len(actions) == 0 {
		fmt.Println("autoheal apply status=ok actions=0")
		printEvidenceStoreStatus(record, storeErr)
		return nil
	}
	fmt.Println("autoheal apply status=done")
	fmt.Println(autohealApplySafeCountsLine(counts))
	for _, action := range actions {
		fmt.Printf("- [%t] %s %s policy=%s approval_required=%t\n  command: %s\n  result: %s\n", action.Success, action.Node, action.Type, action.PolicyDecision, action.ApprovalRequired, action.Command, action.Result)
	}
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

func applyAutohealPlanSafe(plan []monitor.HealPlanAction) []monitor.HealAction {
	actions := make([]monitor.HealAction, 0, len(plan))
	for _, item := range plan {
		action := healActionFromPlan(item)
		if item.PolicyDecision != string(policy.Allow) || item.ApprovalRequired {
			action.Skipped = true
			action.SkipReason = "policy does not allow unattended execution"
			action.Result = action.SkipReason
			actions = append(actions, action)
			continue
		}
		if item.Mode != "auto_safe" {
			action.Skipped = true
			action.SkipReason = "plan action is not auto_safe"
			action.Result = action.SkipReason
			actions = append(actions, action)
			continue
		}
		result := runtime.NewRunner().RunEvidence(item.Node, item.Command)
		applyRuntimeResultToHealAction(&action, result)
		actions = append(actions, action)
	}
	return actions
}

func summarizeAutohealApplySafeActions(actions []monitor.HealAction) map[string]int {
	counts := map[string]int{"total": len(actions)}
	for _, action := range actions {
		if action.Success {
			counts["succeeded"]++
		}
		if !action.Success && !action.Skipped {
			counts["failed"]++
		}
		if action.Skipped {
			counts["skipped"]++
		}
		if action.ApprovalRequired {
			counts["approval_required"]++
		}
		switch action.SkipReason {
		case "policy does not allow unattended execution":
			counts["policy_blocked"]++
		case "plan action is not auto_safe":
			counts["mode_blocked"]++
		}
	}
	return counts
}

func autohealApplySafeCountsLine(counts map[string]int) string {
	return fmt.Sprintf("actions=%d skipped=%d policy_blocked=%d mode_blocked=%d approval_required=%d succeeded=%d failed=%d",
		counts["total"],
		counts["skipped"],
		counts["policy_blocked"],
		counts["mode_blocked"],
		counts["approval_required"],
		counts["succeeded"],
		counts["failed"],
	)
}

func autohealApplySafeMCPPayload(actions []monitor.HealAction, counts map[string]int, record evidence.Record, storeErr error) map[string]interface{} {
	return map[string]interface{}{
		"actions":     actions,
		"counts":      counts,
		"evidence":    record,
		"store_error": errString(storeErr),
	}
}

func healActionFromPlan(item monitor.HealPlanAction) monitor.HealAction {
	return monitor.HealAction{
		Node:             item.Node,
		Type:             item.Type,
		Command:          item.Command,
		PolicyAction:     item.PolicyAction,
		PolicyDecision:   item.PolicyDecision,
		PolicyReason:     item.PolicyReason,
		ApprovalRequired: item.ApprovalRequired,
		Time:             time.Now().UTC(),
	}
}

func applyRuntimeResultToHealAction(action *monitor.HealAction, result runtime.Evidence) {
	action.Success = result.Success
	action.Transport = result.Transport
	action.ExitCode = result.ExitCode
	output := strings.TrimSpace(result.Stdout + result.Stderr)
	if result.Success {
		if output == "" {
			action.Result = fmt.Sprintf("completed via %s", result.Transport)
			return
		}
		action.Result = output
		return
	}
	if output == "" {
		action.Result = fmt.Sprintf("failed via %s exit=%d", result.Transport, result.ExitCode)
		return
	}
	action.Result = fmt.Sprintf("failed via %s exit=%d\n%s", result.Transport, result.ExitCode, output)
}

func annotateHealActionsPolicies(actions []monitor.HealAction) {
	for i := range actions {
		policyAction := policyActionForHealType(actions[i].Type)
		result := policy.Evaluate(policy.Request{
			Subject:  "automation",
			Action:   policyAction,
			Resource: "server",
			Context:  actions[i].Command,
		})
		actions[i].PolicyAction = policyAction
		actions[i].PolicyDecision = string(result.Decision)
		actions[i].PolicyReason = result.Reason
		actions[i].ApprovalRequired = result.Decision == policy.RequireApproval
	}
}

func policyActionForHealType(actionType string) string {
	switch actionType {
	case "disk_cleanup", "memory_cleanup":
		return "autoheal_apply_safe"
	case "restart_service":
		return "restart_service"
	case "container_restart":
		return "container_restart"
	default:
		return "run_command"
	}
}

func diskInvestigate(args []string) error {
	if len(args) < 1 || len(args) > 2 {
		return fmt.Errorf("usage: meshclaw disk-investigate <host> [path]")
	}
	host := args[0]
	path := "/"
	if len(args) == 2 {
		path = args[1]
	}
	if _, ok := inventory.Find(host); !ok {
		return fmt.Errorf("unknown node: %s", host)
	}
	if !strings.HasPrefix(path, "/") {
		return fmt.Errorf("path must be absolute: %s", path)
	}
	quoted := shellQuote(path)
	command := fmt.Sprintf("df -h %s && sudo du -xhd1 %s 2>/dev/null | sort -h | tail -40", quoted, quoted)
	result := runtime.NewRunner().RunEvidence(host, command)
	record, storeErr := evidence.Store("disk-investigate", host, path, result)
	fmt.Printf("disk-investigate host=%s path=%s success=%t transport=%s\n", host, path, result.Success, result.Transport)
	if result.Stdout != "" {
		fmt.Print(result.Stdout)
	}
	if result.Stderr != "" {
		fmt.Fprint(os.Stderr, result.Stderr)
	}
	if storeErr != nil {
		fmt.Fprintf(os.Stderr, "evidence_store_error=%v\n", storeErr)
	} else {
		fmt.Printf("evidence=%s\n", record.StoredAt)
	}
	if !result.Success {
		return fmt.Errorf("disk investigation failed on %s", host)
	}
	return nil
}

