func expectedMatrixMembers() []string {
	if value := strings.TrimSpace(os.Getenv("MESHCLAW_MATRIX_EXPECTED_MEMBERS")); value != "" {
		parts := strings.Split(value, ",")
		out := make([]string, 0, len(parts))
		for _, part := range parts {
			if item := strings.TrimSpace(part); item != "" {
				out = append(out, item)
			}
		}
		if len(out) > 0 {
			return out
		}
	}
	return []string{
		"@operator:matrix.hunmin.ai",
		"@yoon:matrix.hunmin.ai",
		"@dev:matrix.hunmin.ai",
		"@ops-ai:matrix.hunmin.ai",
		"@meshclaw:matrix.hunmin.ai",
	}
}

func matrixRoomDoctor(cfg matrixops.Config, label, roomID string) map[string]interface{} {
	room := map[string]interface{}{
		"label":   label,
		"room_id": roomID,
	}
	if roomID == "" {
		room["status"] = "skipped"
		return room
	}
	ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
	defer cancel()
	var name map[string]interface{}
	if err := matrixAuthedGET(ctx, cfg, "/_matrix/client/v3/rooms/"+url.PathEscape(roomID)+"/state/m.room.name", &name); err == nil {
		room["name"] = name["name"]
	}
	var topic map[string]interface{}
	if err := matrixAuthedGET(ctx, cfg, "/_matrix/client/v3/rooms/"+url.PathEscape(roomID)+"/state/m.room.topic", &topic); err == nil {
		room["topic"] = topic["topic"]
	}
	var joined struct {
		Joined map[string]interface{} `json:"joined"`
	}
	if err := matrixAuthedGET(ctx, cfg, "/_matrix/client/v3/rooms/"+url.PathEscape(roomID)+"/joined_members", &joined); err != nil {
		room["joined_error"] = err.Error()
	} else {
		room["joined_count"] = len(joined.Joined)
		room["joined"] = sortedMapKeys(joined.Joined)
	}
	var members struct {
		Chunk []struct {
			StateKey string `json:"state_key"`
			Content  struct {
				Membership string `json:"membership"`
			} `json:"content"`
		} `json:"chunk"`
	}
	if err := matrixAuthedGET(ctx, cfg, "/_matrix/client/v3/rooms/"+url.PathEscape(roomID)+"/members", &members); err != nil {
		room["members_error"] = err.Error()
	} else {
		membership := map[string]string{}
		counts := map[string]int{}
		for _, event := range members.Chunk {
			state := strings.TrimSpace(event.Content.Membership)
			if state == "" {
				continue
			}
			membership[event.StateKey] = state
			counts[state]++
		}
		room["membership"] = membership
		room["membership_counts"] = counts
	}
	return room
}

func matrixAuthedGET(ctx context.Context, cfg matrixops.Config, path string, out interface{}) error {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, cfg.Homeserver+path, nil)
	if err != nil {
		return err
	}
	req.Header.Set("Authorization", "Bearer "+cfg.AccessToken)
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("%s", resp.Status)
	}
	return json.NewDecoder(resp.Body).Decode(out)
}

func sortedMapKeys[V any](m map[string]V) []string {
	keys := make([]string, 0, len(m))
	for key := range m {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	return keys
}

func isPrivateTailscaleHomeserver(raw string) bool {
	u, err := url.Parse(raw)
	if err != nil {
		return false
	}
	host := u.Hostname()
	return strings.HasPrefix(host, "100.")
}

func matrixClientEndpointChecks(cfg matrixops.Config) map[string]interface{} {
	out := map[string]interface{}{}
	serverName := matrixServerName(cfg)
	if serverName != "" {
		out["https_default"] = matrixEndpointReachable("https://" + serverName + "/_matrix/client/versions")
		out["http_8008"] = matrixEndpointReachable("http://" + serverName + ":8008/_matrix/client/versions")
		out["well_known"] = matrixEndpointReachable("https://" + serverName + "/.well-known/matrix/client")
	}
	if cfg.Homeserver != "" {
		out["configured"] = matrixEndpointReachable(strings.TrimRight(cfg.Homeserver, "/") + "/_matrix/client/versions")
	}
	return out
}

func matrixServerName(cfg matrixops.Config) string {
	for _, value := range []string{cfg.UserID, cfg.RoomID} {
		if idx := strings.LastIndex(value, ":"); idx >= 0 && idx+1 < len(value) {
			return value[idx+1:]
		}
	}
	if u, err := url.Parse(cfg.Homeserver); err == nil {
		return u.Hostname()
	}
	return ""
}

func matrixEndpointReachable(endpoint string) map[string]interface{} {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, endpoint, nil)
	if err != nil {
		return map[string]interface{}{"ok": false, "error": err.Error()}
	}
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return map[string]interface{}{"ok": false, "error": err.Error()}
	}
	defer resp.Body.Close()
	return map[string]interface{}{"ok": resp.StatusCode >= 200 && resp.StatusCode < 300, "status": resp.Status}
}

func matrixAIConfigInit(args []string) error {
	force := false
	for _, arg := range args {
		if arg == "--force" {
			force = true
			continue
		}
		return fmt.Errorf("usage: meshclaw matrix-ai-config-init [--force]")
	}
	path, err := aichat.DefaultConfigPath()
	if err != nil {
		return err
	}
	if !force {
		if _, err := os.Stat(path); err == nil {
			return fmt.Errorf("matrix AI config already exists: %s", path)
		}
	}
	if err := aichat.SaveConfig(path, aichat.DefaultConfig()); err != nil {
		return err
	}
	fmt.Printf("matrix_ai_config=%s\n", path)
	return nil
}

type modelConfigReport struct {
	Kind        string  `json:"kind"`
	Path        string  `json:"path"`
	Exists      bool    `json:"exists"`
	BaseURL     string  `json:"base_url"`
	Model       string  `json:"model"`
	APIKey      string  `json:"api_key,omitempty"`
	MaxTokens   int     `json:"max_tokens"`
	Temperature float64 `json:"temperature"`
}

type modelConfigInput struct {
	BaseURL     string  `json:"base_url"`
	APIKey      string  `json:"api_key"`
	Model       string  `json:"model"`
	MaxTokens   int     `json:"max_tokens"`
	Temperature float64 `json:"temperature"`
}

func modelConfigCommand(args []string) error {
	if len(args) == 0 {
		return fmt.Errorf("usage: meshclaw model-config <status|set|import|test> [--json]")
	}
	cmd := args[0]
	rest := args[1:]
	switch cmd {
	case "status":
		jsonOut := wantsJSON(rest)
		report, err := modelConfigStatus()
		if err != nil {
			return err
		}
		if jsonOut {
			return printJSON(report)
		}
		printModelConfigReport(report)
		return nil
	case "set":
		cfg, err := parseModelConfigSet(rest)
		if err != nil {
			return err
		}
		path, err := aichat.DefaultConfigPath()
		if err != nil {
			return err
		}
		if err := aichat.SaveConfig(path, cfg); err != nil {
			return err
		}
		report, err := modelConfigStatus()
		if err != nil {
			return err
		}
		if wantsJSON(rest) {
			return printJSON(report)
		}
		printModelConfigReport(report)
		return nil
	case "import":
		jsonOut := wantsJSON(rest)
		filtered := withoutJSONFlag(rest)
		if len(filtered) != 0 {
			return fmt.Errorf("usage: meshclaw model-config import [--json] < config.json")
		}
		cfg, err := readModelConfigImport(os.Stdin)
		if err != nil {
			return err
		}
		path, err := aichat.DefaultConfigPath()
		if err != nil {
			return err
		}
		if err := aichat.SaveConfig(path, cfg); err != nil {
			return err
		}
		report, err := modelConfigStatus()
		if err != nil {
			return err
		}
		if jsonOut {
			return printJSON(report)
		}
		printModelConfigReport(report)
		return nil
	case "test":
		jsonOut := wantsJSON(rest)
		filtered := withoutJSONFlag(rest)
		message := strings.TrimSpace(strings.Join(filtered, " "))
		if message == "" {
			message = "간단히 연결 테스트라고 답하세요."
		}
		cfg, path, err := aichat.LoadConfig()
		if err != nil {
			return err
		}
		ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
		defer cancel()
		reply, err := aichat.NewClient(cfg).Chat(ctx, nil, message)
		result := map[string]interface{}{"kind": "meshclaw_model_config_test", "path": path, "base_url": cfg.BaseURL, "model": cfg.Model, "ok": err == nil, "reply": reply, "error": errString(err)}
		if jsonOut {
			return printJSON(result)
		}
		if err != nil {
			return err
		}
		fmt.Printf("model_config_test ok=true model=%s base_url=%s\n\n%s\n", cfg.Model, cfg.BaseURL, reply)
		return nil
	default:
		return fmt.Errorf("usage: meshclaw model-config <status|set|import|test> [--json]")
	}
}

func parseModelConfigSet(args []string) (aichat.Config, error) {
	jsonOut := wantsJSON(args)
	_ = jsonOut
	filtered := withoutJSONFlag(args)
	cfg, _, err := aichat.LoadConfig()
	if err != nil {
		cfg = aichat.DefaultConfig()
	}
	for i := 0; i < len(filtered); i++ {
		switch filtered[i] {
		case "--base-url":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--base-url requires a value")
			}
			cfg.BaseURL = filtered[i]
		case "--model":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--model requires a value")
			}
			cfg.Model = filtered[i]
		case "--api-key":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--api-key requires a value")
			}
			cfg.APIKey = filtered[i]
		case "--api-key-env":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--api-key-env requires a value")
			}
			cfg.APIKey = strings.TrimSpace(os.Getenv(filtered[i]))
			if cfg.APIKey == "" {
				return cfg, fmt.Errorf("environment variable %s is empty", filtered[i])
			}
		case "--api-key-stdin":
			data, err := io.ReadAll(os.Stdin)
			if err != nil {
				return cfg, err
			}
			cfg.APIKey = strings.TrimSpace(string(data))
		case "--max-tokens":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--max-tokens requires a value")
			}
			value, err := strconv.Atoi(filtered[i])
			if err != nil || value <= 0 {
				return cfg, fmt.Errorf("--max-tokens must be a positive integer")
			}
			cfg.MaxTokens = value
		case "--temperature":
			i++
			if i >= len(filtered) {
				return cfg, fmt.Errorf("--temperature requires a value")
			}
			value, err := strconv.ParseFloat(filtered[i], 64)
			if err != nil {
				return cfg, fmt.Errorf("--temperature must be a number")
			}
			cfg.Temperature = value
		default:
			return cfg, fmt.Errorf("unknown model-config set option: %s", filtered[i])
		}
	}
	if strings.TrimSpace(cfg.BaseURL) == "" || strings.TrimSpace(cfg.Model) == "" {
		return cfg, fmt.Errorf("model-config set requires --base-url and --model")
	}
	return cfg, nil
}

func readModelConfigImport(r io.Reader) (aichat.Config, error) {
	data, err := io.ReadAll(r)
	if err != nil {
		return aichat.Config{}, err
	}
	var input modelConfigInput
	if err := json.Unmarshal(data, &input); err != nil {
		return aichat.Config{}, err
	}
	cfg := aichat.DefaultConfig()
	cfg.BaseURL = strings.TrimSpace(input.BaseURL)
	cfg.APIKey = strings.TrimSpace(input.APIKey)
	cfg.Model = strings.TrimSpace(input.Model)
	cfg.MaxTokens = input.MaxTokens
	cfg.Temperature = input.Temperature
	if cfg.BaseURL == "" || cfg.Model == "" {
		return cfg, fmt.Errorf("model-config import requires base_url and model")
	}
	return cfg, nil
}

func modelConfigStatus() (modelConfigReport, error) {
	path, err := aichat.DefaultConfigPath()
	if err != nil {
		return modelConfigReport{}, err
	}
	cfg, _, err := aichat.LoadConfig()
	exists := true
	if err != nil {
		if os.IsNotExist(err) {
			cfg = aichat.DefaultConfig()
			exists = false
		} else {
			return modelConfigReport{}, err
		}
	}
	return modelConfigReport{
		Kind:        "meshclaw_model_config",
		Path:        path,
		Exists:      exists,
		BaseURL:     cfg.BaseURL,
		Model:       cfg.Model,
		APIKey:      maskAPIKey(cfg.APIKey),
		MaxTokens:   cfg.MaxTokens,
		Temperature: cfg.Temperature,
	}, nil
}

func printModelConfigReport(report modelConfigReport) {
	fmt.Printf("model_config exists=%t path=%s\n", report.Exists, report.Path)
	fmt.Printf("base_url=%s\n", report.BaseURL)
	fmt.Printf("model=%s\n", report.Model)
	fmt.Printf("api_key=%s\n", report.APIKey)
	fmt.Printf("max_tokens=%d temperature=%.2f\n", report.MaxTokens, report.Temperature)
	fmt.Println("\nSignal room usage after saving:")
	fmt.Printf("/model %s %s\n", report.Model, report.BaseURL)
}

func maskAPIKey(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	runes := []rune(value)
	if len(runes) <= 8 {
		return "****"
	}
	return string(runes[:4]) + "..." + string(runes[len(runes)-4:])
}

func matrixAIChat(args []string) error {
	if len(args) == 0 {
		return fmt.Errorf("usage: meshclaw matrix-ai-chat <message>")
	}
	cfg, path, err := aichat.LoadConfig()
	if err != nil {
		return err
	}
	ctx, cancel := contextWithSignal()
	defer cancel()
	message := strings.Join(args, " ")
	reply, err := matrixAIReply(ctx, aichat.NewClient(cfg), nil, message)
	if err != nil {
		return err
	}
	fmt.Printf("ai_config=%s model=%s\n\n%s\n", path, cfg.Model, reply)
	return nil
}

func matrixAIBridge(args []string) error {
	if len(args) != 0 {
		return fmt.Errorf("usage: meshclaw matrix-ai-bridge")
	}
	matrixCfg, matrixPath, err := matrixops.LoadConfig()
	if err != nil {
		return err
	}
	aiCfg, aiPath, err := aichat.LoadConfig()
	if err != nil {
		return err
	}
	client := aichat.NewClient(aiCfg)
	history := make([]aichat.Message, 0, 24)
	reply := func(message string) (string, error) {
		out, err := matrixAIReply(context.Background(), client, history, message)
		if err != nil {
			return "", err
		}
		history = append(history, aichat.Message{Role: "user", Content: message}, aichat.Message{Role: "assistant", Content: out})
		if len(history) > 24 {
			history = history[len(history)-24:]
		}
		return out, nil
	}
	fmt.Printf("matrix_ai_bridge=running room=%s matrix_config=%s ai_config=%s model=%s\n", matrixCfg.RoomID, matrixPath, aiPath, aiCfg.Model)
	ctx, cancel := contextWithSignal()
	defer cancel()
	return matrixops.NewClient(matrixCfg).BridgeReply(ctx, reply)
}

func matrixAIReply(ctx context.Context, client *aichat.Client, history []aichat.Message, message string) (string, error) {
	if shouldRouteMatrixAIToTool(message) {
		result, err := dispatchOpsMessage("matrix-ai", message)
		if err != nil {
			return "", err
		}
		return matrixops.FormatExplainedResultForQuery(result, message), nil
	}
	if isDangerousMatrixAIAction(message) {
		return dangerousMatrixAIActionResponse(message), nil
	}
	return client.Chat(ctx, history, message)
}

func isDangerousMatrixAIAction(message string) bool {
	lower := strings.ToLower(strings.TrimSpace(message))
	if lower == "" {
		return false
	}
	hasAction := containsAny(lower,
		"실행", "해줘", "삭제", "지워", "제거", "초기화", "재시작", "중지", "종료", "배포", "적용", "수정", "변경", "임대", "구매", "생성",
		"run", "execute", "delete", "remove", "wipe", "reset", "restart", "stop", "shutdown", "deploy", "apply", "modify", "change", "provision", "create",
	)
	if !hasAction {
		return false
	}
	return containsAny(lower,
		"rm -rf", "sudo", "systemctl", "docker", "kubectl", "iptables", "ufw", "chmod", "chown", "mkfs", "dd ",
		"서버", "노드", "서비스", "디스크", "파일", "폴더", "권한", "방화벽", "vps", "provider", "api key", "secret",
		"nginx", "postgres", "mysql", "redis", "docker", "ollama",
	) || mentionsKnownNode(lower)
}

