func formatRouterDisplay(plan router.Plan, output map[string]interface{}) string {
	status, _ := output["status"].(string)
	lang := routerReplyLanguage(plan.Message)
	switch status {
	case "denied":
		if lang == "en" {
			return fmt.Sprintf("I did not run that request.\n\nPolicy decision: denied\nReason: %s", plan.Decision.Reason)
		}
		return fmt.Sprintf("요청을 실행하지 않았습니다.\n\n정책 판단: 거부\n이유: %s", plan.Decision.Reason)
	case "approval_required":
		if plan.Intent == "guard_secret" {
			return formatRouterGuardApprovalDisplay(plan, output)
		}
		target := firstNonEmpty(plan.Target, "대상 미지정")
		actionName := routerActionLabel(plan.Intent, plan.Action)
		lines := []string{
			"승인이 필요한 요청입니다.",
			"",
			fmt.Sprintf("%s에 대해 `%s` 작업을 요청했지만, 이 작업은 실제 상태를 바꿀 수 있어서 바로 실행하지 않았습니다.", target, actionName),
			"",
			"현재 상태: 승인 대기",
			"처리 결과: 실행하지 않음",
			"이유: " + routerPolicyReasonKorean(plan.Decision.Reason),
			"",
			"승인되면 그때 실행 경로와 evidence를 남기고 진행합니다.",
		}
		if request, ok := output["approval_request"].(map[string]interface{}); ok {
			if record, ok := request["evidence"].(evidence.Record); ok && record.StoredAt != "" {
				lines = append(lines, "", "evidence: `"+record.StoredAt+"`")
			}
		}
		if notification, ok := output["notification"].(map[string]interface{}); ok {
			switch notification["status"] {
			case "sent":
				lines = append(lines, "", "Signal 승인 알림을 보냈습니다.")
			case "dry_run":
				lines = append(lines, "", "Signal 승인 알림은 dry-run으로 준비됐습니다. 실제 전송은 `MESHCLAW_ROUTER_APPROVAL_NOTIFY=execute`가 필요합니다.")
			case "not_configured":
				lines = append(lines, "", "Signal 승인 알림 대상은 아직 설정되지 않았습니다.")
			}
		}
		return strings.Join(lines, "\n")
	case "send_to_model":
		if lang == "en" {
			return "I classified this as a normal chat message.\n\nMeshClaw Router handles server state, security, policy, evidence, and automation requests. For normal conversation, choose a regular chat model in Open WebUI, such as gpt-oss, gemma, or Claude."
		}
		return "이 요청은 일반 대화로 분류했습니다.\n\nMeshClaw Router는 서버 상태, 보안, 정책, evidence, 자동화 요청만 처리합니다. 일반 대화는 Open WebUI에서 gpt-oss, gemma, Claude 같은 일반 채팅 모델을 선택해서 이어가세요."
	case "executed":
		return formatRouterExecutedDisplay(plan, output)
	default:
		if answer, _ := output["answer"].(string); answer != "" {
			return answer
		}
		return "처리할 MeshClaw 작업이 없습니다."
	}
}

func formatRouterGuardApprovalDisplay(plan router.Plan, output map[string]interface{}) string {
	if routerReplyLanguage(plan.Message) == "en" {
		lines := []string{
			"Do not paste raw passwords, API keys, or tokens into this chat.",
			"",
			"MeshClaw Guard should receive secrets through a separate storage flow that avoids normal chat logs. I classified this as secret handling, and I did not store, reveal, or use the secret.",
			"",
			"Recommended flow:",
			"1. Open the Guard-only input flow.",
			"2. Store the value in local secret storage such as Apple Keychain, pass, 1Password, or Bitwarden.",
			"3. Give Claude, Codex, and local models only a handle/reference, never the raw value.",
			"",
			"So the safe answer is: do not paste the token here; send it through the Guard storage flow.",
		}
		if request, ok := output["approval_request"].(map[string]interface{}); ok {
			if record, ok := request["evidence"].(evidence.Record); ok && record.StoredAt != "" {
				lines = append(lines, "", "evidence: `"+record.StoredAt+"`")
			}
		}
		return strings.Join(lines, "\n")
	}
	lines := []string{
		"여기에는 원문 비밀번호나 토큰을 그대로 붙이지 않는 게 맞습니다.",
		"",
		"MeshClaw Guard는 비밀값을 일반 대화 로그에 남기지 않는 별도 흐름으로 받아야 합니다. 지금 요청은 비밀정보 처리로 분류했고, 실제 저장이나 조회는 아직 실행하지 않았습니다.",
		"",
		"권장 흐름:",
		"1. Guard 전용 입력 흐름을 엽니다.",
		"2. 로컬 저장소(Apple Keychain, pass, 1Password/Bitwarden 연동 등)에 저장합니다.",
		"3. Claude, Codex, 로컬 모델에게는 원문 대신 handle/reference만 줍니다.",
		"",
		"즉, 이 Open WebUI 대화창에는 토큰 원문을 붙이지 말고 Guard 저장 흐름으로 넘겨야 합니다.",
	}
	if request, ok := output["approval_request"].(map[string]interface{}); ok {
		if record, ok := request["evidence"].(evidence.Record); ok && record.StoredAt != "" {
			lines = append(lines, "", "evidence: `"+record.StoredAt+"`")
		}
	}
	return strings.Join(lines, "\n")
}

func routerActionLabel(intent, action string) string {
	switch intent {
	case "restart_service":
		return "서비스 재시작"
	case "data_clean":
		return "데이터 정리"
	case "email_send":
		return "이메일 발송"
	case "signal_call":
		return "Signal 전화"
	case "guard_secret":
		return "비밀정보 처리"
	}
	switch action {
	case "restart_service":
		return "서비스 재시작"
	case "delete_data":
		return "데이터 삭제/정리"
	case "send_email":
		return "이메일 발송"
	case "signal_call":
		return "Signal 전화"
	case "store_secret":
		return "비밀정보 저장"
	}
	return firstNonEmpty(action, intent, "요청한 작업")
}

func routerPolicyReasonKorean(reason string) string {
	lower := strings.ToLower(strings.TrimSpace(reason))
	switch {
	case strings.Contains(lower, "local model") && strings.Contains(lower, "require"):
		return "로컬 모델에서 들어온 변경 작업은 사람의 명시적 승인이 필요합니다."
	case strings.Contains(lower, "destructive") || strings.Contains(lower, "dangerous"):
		return "삭제, 재시작, 종료처럼 위험할 수 있는 작업은 보호 정책에 걸립니다."
	case strings.Contains(lower, "secret"):
		return "비밀번호나 토큰 같은 민감정보는 별도 Guard 흐름으로만 다룹니다."
	case reason != "":
		return reason
	default:
		return "정책상 변경 작업은 승인 후에만 실행합니다."
	}
}

func routerReplyLanguage(message string) string {
	text := strings.TrimSpace(message)
	if text == "" {
		return "ko"
	}
	hasHangul := false
	latinLetters := 0
	otherLetters := 0
	for _, r := range text {
		switch {
		case r >= 0xAC00 && r <= 0xD7AF:
			hasHangul = true
		case (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z'):
			latinLetters++
		case r > 127 && ((r >= 0x3040 && r <= 0x30FF) || (r >= 0x3400 && r <= 0x9FFF) || (r >= 0x0E00 && r <= 0x0E7F)):
			otherLetters++
		}
	}
	if hasHangul {
		return "ko"
	}
	if latinLetters > 0 && latinLetters >= otherLetters {
		return "en"
	}
	return "ko"
}

func formatRouterExecutedDisplay(plan router.Plan, output map[string]interface{}) string {
	wrapped, _ := output["result"].(map[string]interface{})
	payload, _ := wrapped["result"].(map[string]interface{})
	if payload == nil {
		payload = wrapped
	}
	lang := routerReplyLanguage(plan.Message)
	switch plan.Intent {
	case "meshclaw_help":
		return formatRouterMeshClawHelp(plan, payload)
	case "openwebui_status":
		report, _ := payload["report"].(openwebui.ScanReport)
		if lang == "en" {
			lines := []string{
				"I checked Open WebUI.",
				"",
				fmt.Sprintf("Summary: %d installed, %d with MCP/tool support, %d router pipe, %d gateway, %d failures", report.Installed, report.WithTool, report.WithPipe, report.WithGateway, report.Failures),
			}
			for _, host := range report.Hosts {
				switch host.Status {
				case "ok":
					lines = append(lines, fmt.Sprintf("- %s: ok | %s %s | runtime=%s | gateway=%s", host.Host, firstNonEmpty(host.Name, "Open WebUI"), host.Version, firstNonEmpty(host.Runtime, "unknown"), host.Gateway))
				case "not_installed":
					lines = append(lines, fmt.Sprintf("- %s: Open WebUI not installed", host.Host))
				default:
					lines = append(lines, fmt.Sprintf("- %s: %s | %s", host.Host, host.Status, firstNonEmpty(host.Error, host.Gateway)))
				}
			}
			appendRouterEvidence(&lines, payload)
			return strings.Join(lines, "\n")
		}
		lines := []string{
			"Open WebUI 상태를 확인했습니다.",
			"",
			fmt.Sprintf("요약: 설치 %d개, MCP/Tool %d개, Router Pipe %d개, Gateway %d개, 실패 %d개", report.Installed, report.WithTool, report.WithPipe, report.WithGateway, report.Failures),
		}
		for _, host := range report.Hosts {
			switch host.Status {
			case "ok":
				lines = append(lines, fmt.Sprintf("- %s: 정상 | %s %s | runtime=%s | gateway=%s", host.Host, firstNonEmpty(host.Name, "Open WebUI"), host.Version, firstNonEmpty(host.Runtime, "unknown"), host.Gateway))
			case "not_installed":
				lines = append(lines, fmt.Sprintf("- %s: Open WebUI 없음", host.Host))
			default:
				lines = append(lines, fmt.Sprintf("- %s: %s | %s", host.Host, host.Status, firstNonEmpty(host.Error, host.Gateway)))
			}
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "fleet_status":
		states, _ := payload["states"].(map[string]*monitor.NodeState)
		alerts, _ := payload["alerts"].([]monitor.Alert)
		if changeOnly, _ := payload["change_only"].(bool); changeOnly {
			return formatRouterChangeOnlyReport(plan, payload, lang)
		}
		if explain, _ := payload["alert_explain"].(bool); explain {
			return formatRouterAlertExplanation(payload, lang)
		}
		if deep, _ := payload["deep_report"].(bool); deep {
			return formatRouterFleetOpsReport(plan, payload, lang)
		}
		online := 0
		for _, state := range states {
			if state != nil && state.Online {
				online++
			}
		}
		if strings.TrimSpace(plan.Target) != "" {
			report, _ := payload["workloads"].(agentWorkloadsReport)
			if text := formatRouterTargetAIView(plan.Target, report, lang); text != "" {
				lines := []string{text}
				appendRouterEvidence(&lines, payload)
				return strings.Join(lines, "\n")
			}
		}
		if lang == "en" {
			lines := []string{
				"I checked the server fleet.",
				"",
				fmt.Sprintf("Summary: %d nodes, %d online, %d alerts", len(states), online, len(alerts)),
			}
			if cacheInfo, ok := payload["cache"].(map[string]interface{}); ok {
				stale, _ := cacheInfo["stale"].(bool)
				if used, _ := cacheInfo["used"].(bool); used {
					if ttl, _ := cacheInfo["ttl"].(string); ttl != "" {
						if stale {
							lines = append(lines, fmt.Sprintf("cache: stale snapshot used | ttl=%s | ask for a fresh status to rescan", ttl))
						} else {
							lines = append(lines, fmt.Sprintf("cache: used | ttl=%s", ttl))
						}
					} else {
						lines = append(lines, "cache: used")
					}
				} else {
					lines = append(lines, "cache: refreshed")
				}
			}
			if len(alerts) > 0 {
				lines = append(lines, "", "Alerts to check first:")
				for i, alert := range alerts {
					if i >= 8 {
						lines = append(lines, fmt.Sprintf("- plus %d more", len(alerts)-i))
						break
					}
					lines = append(lines, fmt.Sprintf("- [%s] %s %s: %s", alert.Level, alert.Node, alert.Type, alert.Message))
				}
			} else if len(states) > 0 {
				lines = append(lines, "", "No active alerts were detected.")
			}
			appendRouterWorkloadDigest(&lines, payload, plan.Target, "en")
			appendRouterFleetStateLines(&lines, states, plan.Target, "en")
			appendRouterEvidence(&lines, payload)
			return strings.Join(lines, "\n")
		}
		lines := []string{
			"서버 상태를 확인했습니다.",
			"",
			fmt.Sprintf("요약: 노드 %d개, 온라인 %d개, 알림 %d개", len(states), online, len(alerts)),
		}
		if cacheInfo, ok := payload["cache"].(map[string]interface{}); ok {
			stale, _ := cacheInfo["stale"].(bool)
			if used, _ := cacheInfo["used"].(bool); used {
				if ttl, _ := cacheInfo["ttl"].(string); ttl != "" {
					if stale {
						lines = append(lines, fmt.Sprintf("cache: 오래된 스냅샷 사용 | ttl=%s | 최신 상태가 필요하면 '새로 확인'이라고 보내세요", ttl))
					} else {
						lines = append(lines, fmt.Sprintf("cache: used | ttl=%s", ttl))
					}
				} else {
					lines = append(lines, "cache: used")
				}
			} else {
				lines = append(lines, "cache: refreshed")
			}
		}
		if len(alerts) > 0 {
			lines = append(lines, "", "우선 확인할 알림:")
			for i, alert := range alerts {
				if i >= 8 {
					lines = append(lines, fmt.Sprintf("- 그 외 %d개", len(alerts)-i))
					break
				}
				lines = append(lines, fmt.Sprintf("- [%s] %s %s: %s", alert.Level, alert.Node, alert.Type, alert.Message))
			}
		} else if len(states) > 0 {
			lines = append(lines, "", "현재 감지된 알림은 없습니다.")
		}
		appendRouterWorkloadDigest(&lines, payload, plan.Target, "ko")
		appendRouterFleetStateLines(&lines, states, plan.Target, "ko")
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "opsdb_power_events":
		report, _ := payload["report"].(opsdb.PowerEventReport)
		return formatRouterPowerEventsReport(plan, payload, report, lang)
	case "disk_investigate":
		run, _ := payload["run"].(runtime.Evidence)
		path, _ := payload["path"].(string)
		if strings.EqualFold(strings.TrimSpace(plan.Source), "openwebui") {
			if lang == "en" {
				return formatRouterDiskCardEN(plan, payload, run, path)
			}
			return formatRouterDiskCardKO(plan, payload, run, path)
		}
		lines := []string{
			fmt.Sprintf("%s 디스크 상태를 확인했습니다.", firstNonEmpty(plan.Target, "노드")),
			"",
			"path: `" + firstNonEmpty(path, "/") + "`",
			fmt.Sprintf("success: %t | transport: %s | duration_ms: %d", run.Success, run.Transport, run.DurationMs),
		}
		if !run.Success {
			lines = append(lines, "", "판단: 디스크 명령이 아니라 노드 연결/실행 경로에서 실패했습니다. vssh daemon, Tailscale, SSH fallback 상태를 먼저 확인해야 합니다.")
		}
		if strings.TrimSpace(run.Stdout) != "" {
			lines = append(lines, "", "결과:", "```text", truncate(run.Stdout, 3000), "```")
		}
		if strings.TrimSpace(run.Stderr) != "" {
			lines = append(lines, "", "stderr:", "```text", truncate(run.Stderr, 1000), "```")
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "process_top":
		report, _ := payload["report"].(workflow.Report)
		return formatRouterProcessTopReport(plan, payload, report)
	case "service_check":
		service, _ := payload["service"].(string)
		title := fmt.Sprintf("%s 서비스 상태를 확인했습니다.", firstNonEmpty(service, "지정한"))
		return formatRouterWorkflowReport(plan, payload, title)
	case "service_audit":
		return formatRouterWorkflowReport(plan, payload, "실패하거나 재시작 중인 서비스를 점검했습니다.")
	case "analyze_logs":
		sourceName, _ := payload["source"].(string)
		return formatRouterWorkflowReport(plan, payload, firstNonEmpty(sourceName, "system")+" 로그를 분석했습니다.")
	case "security_check":
		return formatRouterSecurityReport(plan, payload)
	case "node_inventory":
		return formatRouterNodeInventory(plan, payload)
	case "evidence_list":
		records, _ := payload["result"].([]evidence.Summary)
		if records == nil {
			if result, ok := wrapped["result"].([]evidence.Summary); ok {
				records = result
			}
		}
		if strings.EqualFold(strings.TrimSpace(plan.Source), "openwebui") {
			return formatRouterEvidenceListCard(plan, records)
		}
		lines := []string{"최근 evidence 기록입니다.", ""}
		if len(records) == 0 {
			lines = append(lines, "기록이 없습니다.")
			return strings.Join(lines, "\n")
		}
		for i, record := range records {
			if i >= 10 {
				lines = append(lines, fmt.Sprintf("- 그 외 %d개", len(records)-i))
				break
			}
			lines = append(lines, fmt.Sprintf("- %s | %s | %s | %s", record.Time.Local().Format("2006-01-02 15:04"), record.Kind, firstNonEmpty(record.Host, "-"), record.Summary))
		}
		return strings.Join(lines, "\n")
	case "data_doctor":
		report, _ := payload["report"].(datadoctor.Report)
		lines := []string{fmt.Sprintf("MeshClaw 데이터 상태: ok=%t", report.OK), ""}
		for _, loc := range report.Locations {
			status := "없음"
			if loc.Exists {
				status = fmt.Sprintf("%d개 / %s", loc.Files, humanBytes(loc.Bytes))
			}
			cleaning := "수동"
			if loc.AutoCleaned {
				cleaning = "자동"
			}
			lines = append(lines, fmt.Sprintf("- %s: %s (%s 관리)", loc.ID, status, cleaning))
		}
		lines = append(lines, fmt.Sprintf("- evidence: %d개 / %s (자동 삭제 안 함)", report.Evidence.Files, humanBytes(report.Evidence.Bytes)))
		if len(report.StateFiles) > 0 {
			invalid := []string{}
			for _, file := range report.StateFiles {
				if file.Exists && !file.OK {
					invalid = append(invalid, file.ID)
				}
			}
			lines = append(lines, fmt.Sprintf("- state JSON: %d개 검사 / 깨진 파일 %d개", len(report.StateFiles), len(invalid)))
			if len(invalid) > 0 {
				lines = append(lines, "  깨진 파일: "+strings.Join(invalid, ", "))
			}
		}
		if len(report.Warnings) == 0 {
			lines = append(lines, "", "현재 경고는 없습니다. public 리포트와 진단 파일은 스케줄러가 자동 정리하고, evidence는 삭제 대신 보관/아카이브 대상으로 관리합니다.")
		} else {
			lines = append(lines, "", "주의:")
			for _, warning := range report.Warnings {
				lines = append(lines, "- "+warning)
			}
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "schedule_status":
		status, _ := payload["status"].(map[string]interface{})
		daemon, _ := payload["daemon"].(daemonActionResult)
		lines := []string{
			"Argos 자동화 상태를 확인했습니다.",
			"",
			fmt.Sprintf("- status: %s", firstNonEmpty(stringMapValue(status, "status"), "unknown")),
			fmt.Sprintf("- due_count: %d", intMapValue(status, "due_count")),
		}
		if daemon.Service != "" {
			lines = append(lines, fmt.Sprintf("- schedule_runner: installed=%t running=%t last_status=%s", daemon.Installed, daemon.Running, firstNonEmpty(daemon.LastStatus, "-")))
		}
		if dueJobs, ok := status["due_jobs"].([]string); ok && len(dueJobs) > 0 {
			lines = append(lines, "- due_jobs: "+strings.Join(dueJobs, ", "))
		}
		if next := stringMapValue(status, "next_due_job"); next != "" {
			lines = append(lines, fmt.Sprintf("- next_due_job: %s", next))
		}
		if seconds := intMapValue(status, "next_due_in_seconds"); seconds > 0 {
			lines = append(lines, fmt.Sprintf("- next_due_in_seconds: %d", seconds))
		}
		if stringMapValue(status, "status") == "healthy" && intMapValue(status, "due_count") == 0 {
			lines = append(lines, "", "현재 밀린 자동화 작업은 없습니다.")
		} else if intMapValue(status, "due_count") > 0 {
			lines = append(lines, "", "밀린 작업은 다음 schedule-runner 실행에서 처리됩니다. 급하면 `meshclaw schedule run-due --execute`를 실행하면 됩니다.")
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "policy_show":
		path, _ := payload["path"].(string)
		return "정책 상태를 확인했습니다.\n\n- policy file: `" + firstNonEmpty(path, "default preset") + "`\n- 읽기 작업은 허용하고, 변경/삭제/발송/전화/시크릿 작업은 승인 또는 차단 정책을 적용합니다."
	case "worker_plan":
		report, _ := payload["report"].(workerPlanReport)
		if len(report.Candidates) == 0 {
			return "지금 맡길 수 있는 g 계열 워커 후보를 찾지 못했습니다."
		}
		lines := []string{fmt.Sprintf("이 작업은 %s 쪽 워커에 맡기는 게 맞습니다.", report.Candidates[0].Host), ""}
		for i, candidate := range report.Candidates {
			if i >= 4 {
				break
			}
			lines = append(lines, fmt.Sprintf("- %s: score=%d role=%s address=%s", candidate.Host, candidate.Score, candidate.Role, candidate.Address))
			for _, reason := range candidate.Reasons {
				lines = append(lines, "  근거: "+reason)
			}
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	case "workers":
		list, _ := wrapped["result"].([]workers.Worker)
		lines := []string{"현재 등록된 작업 표면입니다.", ""}
		for _, worker := range list {
			lines = append(lines, fmt.Sprintf("- %s: %s | %s | %s", worker.ID, worker.Status, worker.Kind, worker.Surface))
		}
		return strings.Join(lines, "\n")
	case "linux_worker_nodes":
		return formatLinuxWorkerNodesDisplay(payload)
	case "worker_run":
		return formatWorkerRunDisplay(payload)
	case "assistant_weather", "assistant_news", "assistant_news_sources", "assistant_news_detail", "assistant_morning":
		brief, _ := payload["brief"].(assistantbrief.Brief)
		if strings.TrimSpace(brief.Text) == "" {
			return "브리핑을 생성했지만 표시할 텍스트가 없습니다."
		}
		return brief.Text
	default:
		if answer, _ := output["answer"].(string); answer != "" {
			return answer
		}
		return "MeshClaw Router가 요청을 처리했습니다."
	}
}

