func formatRouterPowerEventsReport(plan router.Plan, payload map[string]interface{}, report opsdb.PowerEventReport, lang string) string {
	if lang == "en" {
		lines := []string{"MeshClaw power-event summary", ""}
		if len(report.Incidents) == 0 {
			lines = append(lines, "Judgement: no new correlated reboot group was detected from OpsDB boot history.")
			if len(report.RecordedEvents) > 0 {
				lines = append(lines, "", "Recorded operator observations:")
				for i, event := range firstNOpsEvents(report.RecordedEvents, 3) {
					lines = append(lines, fmt.Sprintf("Observation %d: %s | %s", i+1, event.Time.Local().Format("2006-01-02 15:04"), compactEvidenceSummary(event.Summary)))
				}
			}
			lines = append(lines, "", "Next: if machines just came back online, run or wait for the node agents to collect fresh snapshots, then ask again.")
			appendRouterEvidence(&lines, payload)
			return strings.Join(lines, "\n")
		}
		lines = append(lines, fmt.Sprintf("Detected incidents: %d", len(report.Incidents)))
		for i, incident := range firstNPowerIncidents(report.Incidents, 3) {
			lines = append(lines, fmt.Sprintf("Incident %d: %s | severity=%s confidence=%s", i+1, incident.Time.Local().Format("2006-01-02 15:04"), incident.Severity, incident.Confidence))
			lines = append(lines, "Affected nodes: "+strings.Join(powerIncidentNodeNames(incident), ", "))
			lines = append(lines, "Meaning: treat this as a physical power-quality candidate before restarting application services.")
		}
		lines = append(lines, "", "Next: check UPS/AVR, outlets, humidity/contact points, and whether affected nodes share a circuit. Do not blame CPU/GPU load unless logs show thermal or power-limit shutdown.")
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	}

	lines := []string{"MeshClaw 전원 이벤트 요약", ""}
	if len(report.Incidents) == 0 {
		lines = append(lines, "판단: opsdb 부팅 히스토리에서는 새로 묶이는 동시 재부팅 그룹을 찾지 못했습니다.")
		if len(report.RecordedEvents) > 0 {
			lines = append(lines, "", "기록된 운영자 관찰:")
			for i, event := range firstNOpsEvents(report.RecordedEvents, 3) {
				lines = append(lines, fmt.Sprintf("관찰 %d: %s | %s", i+1, event.Time.Local().Format("2006-01-02 15:04"), compactEvidenceSummary(event.Summary)))
			}
		}
		lines = append(lines, "", "다음: 막 다시 켠 장비가 있다면 노드 에이전트가 새 스냅샷을 수집한 뒤 다시 물어보세요.")
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	}
	lines = append(lines, fmt.Sprintf("감지된 후보: %d건", len(report.Incidents)))
	for i, incident := range firstNPowerIncidents(report.Incidents, 3) {
		lines = append(lines, fmt.Sprintf("후보 %d: %s | 심각도 %s | 신뢰도 %s", i+1, incident.Time.Local().Format("2006-01-02 15:04"), incident.Severity, incident.Confidence))
		lines = append(lines, "영향 노드: "+strings.Join(powerIncidentNodeNames(incident), ", "))
		lines = append(lines, "의미: 앱 장애로 보기 전에 물리 전원, 전압, UPS, 콘센트, 습기/접촉 문제 후보로 먼저 봐야 합니다.")
	}
	lines = append(lines, "", "다음: UPS/AVR 로그, 콘센트와 멀티탭, 습기 많은 접점, 같은 전기 회로 공유 여부를 확인하세요. CPU/GPU 부하 원인이라고 단정하려면 열/전력 제한 로그가 있어야 합니다.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func firstNPowerIncidents(values []opsdb.PowerIncident, n int) []opsdb.PowerIncident {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func firstNOpsEvents(values []opsdb.Event, n int) []opsdb.Event {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func powerIncidentNodeNames(incident opsdb.PowerIncident) []string {
	out := make([]string, 0, len(incident.Nodes))
	for _, node := range incident.Nodes {
		if strings.TrimSpace(node.Node) != "" {
			out = append(out, node.Node)
		}
	}
	sort.Strings(out)
	return out
}

func formatRouterDiskCardKO(plan router.Plan, payload map[string]interface{}, run runtime.Evidence, path string) string {
	host := firstNonEmpty(plan.Target, "노드")
	summary := parseDiskInvestigationSummary(run.Stdout)
	lines := []string{
		fmt.Sprintf("MeshClaw 디스크 요약: %s", host),
		fmt.Sprintf("대상: %s %s", host, firstNonEmpty(path, "/")),
		fmt.Sprintf("실행: 성공 %t, 전송 %s, 소요 %dms.", run.Success, firstNonEmpty(run.Transport, "unknown"), run.DurationMs),
	}
	if !run.Success {
		lines = append(lines, "", "판단: read-only 조사만 시도했고 삭제는 하지 않았습니다. 제한 시간 안에 끝나지 않았거나 노드 연결/권한 경로에서 실패했습니다.")
		lines = append(lines, "다음: 빠른 화면에서는 여기서 멈추고, 깊은 원인 분석은 Codex/Claude MCP에서 `meshclaw disk-investigate "+host+" "+firstNonEmpty(path, "/")+"`로 이어가는 것이 안전합니다.")
		if errText := compactErrorText(firstNonEmpty(run.Stderr, firstAttemptError(run.Attempts)), 220); errText != "" {
			lines = append(lines, "오류: "+errText)
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	}
	if summary.FilesystemLine != "" {
		lines = append(lines, "", "마운트: "+summary.FilesystemLine)
	}
	if len(summary.TopDirs) > 0 {
		lines = append(lines, "", "큰 위치")
		for i, dir := range firstN(summary.TopDirs, 6) {
			lines = append(lines, fmt.Sprintf("위치 %d: %s", i+1, dir))
		}
	}
	lines = append(lines, "", "판단: read-only 조사만 했고 삭제는 하지 않았습니다. 가장 큰 위치를 기준으로 로그, 모델 캐시, Docker 볼륨, 학습 산출물인지 확인한 뒤 정리 계획을 세우면 됩니다.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func formatRouterDiskCardEN(plan router.Plan, payload map[string]interface{}, run runtime.Evidence, path string) string {
	host := firstNonEmpty(plan.Target, "node")
	summary := parseDiskInvestigationSummary(run.Stdout)
	lines := []string{
		fmt.Sprintf("MeshClaw disk summary: %s", host),
		fmt.Sprintf("Target: %s %s", host, firstNonEmpty(path, "/")),
		fmt.Sprintf("Run: success=%t, transport=%s, duration=%dms.", run.Success, firstNonEmpty(run.Transport, "unknown"), run.DurationMs),
	}
	if !run.Success {
		lines = append(lines, "", "Judgement: MeshClaw only attempted a read-only check. No deletion was performed. The check timed out or failed in connectivity/permissions.")
		lines = append(lines, "Next: keep the Open WebUI path fast, then continue deeper analysis from Codex/Claude MCP with `meshclaw disk-investigate "+host+" "+firstNonEmpty(path, "/")+"`.")
		if errText := compactErrorText(firstNonEmpty(run.Stderr, firstAttemptError(run.Attempts)), 220); errText != "" {
			lines = append(lines, "Error: "+errText)
		}
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	}
	if summary.FilesystemLine != "" {
		lines = append(lines, "", "Mount: "+summary.FilesystemLine)
	}
	if len(summary.TopDirs) > 0 {
		lines = append(lines, "", "Largest paths")
		for i, dir := range firstN(summary.TopDirs, 6) {
			lines = append(lines, fmt.Sprintf("Path %d: %s", i+1, dir))
		}
	}
	lines = append(lines, "", "Judgement: MeshClaw only collected read-only evidence. No deletion was performed. Use the largest paths to decide whether logs, model cache, Docker volumes, or training artifacts need a cleanup plan.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func formatRouterEvidenceListCard(plan router.Plan, records []evidence.Summary) string {
	lang := routerReplyLanguage(plan.Message)
	if lang == "en" {
		lines := []string{"MeshClaw evidence summary"}
		if len(records) == 0 {
			lines = append(lines, "", "No evidence records were found.")
			return strings.Join(lines, "\n")
		}
		lines = append(lines, "", fmt.Sprintf("Recent records: %d shown.", minInt(len(records), 8)))
		for i, record := range firstNEvidence(records, 8) {
			lines = append(lines, fmt.Sprintf("Record %d: %s | %s | %s | %s", i+1, record.Time.Local().Format("2006-01-02 15:04"), record.Kind, firstNonEmpty(record.Host, "-"), compactEvidenceSummary(record.Summary)))
		}
		lines = append(lines, "", "How to use this: ask for a specific evidence id or ask what changed recently, and MeshClaw will use these records as the audit trail.")
		lines = append(lines, "evidence: "+records[0].ID)
		return strings.Join(lines, "\n")
	}
	lines := []string{"MeshClaw evidence 요약"}
	if len(records) == 0 {
		lines = append(lines, "", "최근 evidence 기록이 없습니다.")
		return strings.Join(lines, "\n")
	}
	lines = append(lines, "", fmt.Sprintf("최근 기록: %d개를 보여줍니다.", minInt(len(records), 8)))
	for i, record := range firstNEvidence(records, 8) {
		lines = append(lines, fmt.Sprintf("기록 %d: %s | %s | %s | %s", i+1, record.Time.Local().Format("2006-01-02 15:04"), record.Kind, firstNonEmpty(record.Host, "-"), compactEvidenceSummary(record.Summary)))
	}
	lines = append(lines, "", "사용법: 특정 evidence id를 물어보거나, 최근 변화/작업 결과를 물어보면 이 기록을 근거로 다시 이어볼 수 있습니다.")
	lines = append(lines, "evidence: "+records[0].ID)
	return strings.Join(lines, "\n")
}

func firstNEvidence(records []evidence.Summary, n int) []evidence.Summary {
	if len(records) <= n {
		return records
	}
	return records[:n]
}

func compactEvidenceSummary(value string) string {
	value = strings.Join(strings.Fields(value), " ")
	if value == "" {
		return "-"
	}
	return truncate(value, 70)
}

type diskInvestigationSummary struct {
	FilesystemLine string
	TopDirs        []string
}

func parseDiskInvestigationSummary(stdout string) diskInvestigationSummary {
	var out diskInvestigationSummary
	lines := strings.Split(stdout, "\n")
	for _, raw := range lines {
		line := strings.TrimSpace(raw)
		if line == "" || strings.HasPrefix(line, "Filesystem ") {
			continue
		}
		if out.FilesystemLine == "" && strings.Contains(line, "%") && strings.Contains(line, "/") {
			out.FilesystemLine = strings.Join(strings.Fields(line), " ")
			continue
		}
		fields := strings.Fields(line)
		if len(fields) < 2 {
			continue
		}
		path := fields[len(fields)-1]
		size := fields[0]
		if !strings.HasPrefix(path, "/") {
			continue
		}
		out.TopDirs = append(out.TopDirs, size+" "+path)
	}
	reverseStrings(out.TopDirs)
	return out
}

func reverseStrings(values []string) {
	for i, j := 0, len(values)-1; i < j; i, j = i+1, j-1 {
		values[i], values[j] = values[j], values[i]
	}
}

func firstAttemptError(attempts []runtime.Attempt) string {
	for _, attempt := range attempts {
		if strings.TrimSpace(attempt.Error) != "" {
			return attempt.Error
		}
	}
	return ""
}

func formatRouterTargetAIView(target string, report agentWorkloadsReport, lang string) string {
	target = strings.TrimSpace(target)
	if target == "" || len(report.Nodes) == 0 {
		return ""
	}
	var node *agentWorkloadNodeSummary
	for i := range report.Nodes {
		if strings.EqualFold(report.Nodes[i].Node, target) {
			node = &report.Nodes[i]
			break
		}
	}
	if node == nil || strings.TrimSpace(node.AIView.PlainSummary) == "" {
		return ""
	}
	if lang == "en" {
		lines := []string{
			fmt.Sprintf("%s node report", node.Node),
			"",
			node.AIView.PlainSummary,
		}
		if node.AIView.WhatThisNodeIs != "" {
			lines = append(lines, "", "Role: "+node.AIView.WhatThisNodeIs)
		}
		appendPlainStringList(&lines, "Running now", node.AIView.WhatIsRunning, 4)
		appendPlainStringList(&lines, "Good for", node.AIView.CanUseFor, 4)
		appendPlainStringList(&lines, "Avoid", node.AIView.ShouldAvoid, 4)
		appendPlainStringList(&lines, "Concerns", node.AIView.ImmediateConcerns, 5)
		appendPlainStringList(&lines, "Recommended actions", node.AIView.RecommendedActions, 5)
		return strings.Join(lines, "\n")
	}
	lines := []string{
		fmt.Sprintf("%s 노드 판독입니다.", node.Node),
		"",
		formatTargetSummaryKO(*node),
	}
	if node.AIView.WhatThisNodeIs != "" {
		lines = append(lines, "", "역할: "+translateAIRoleKO(node.AIView.WhatThisNodeIs))
	}
	appendTranslatedPlainListKO(&lines, "현재 하는 일", node.AIView.WhatIsRunning, 4)
	canUseFor := append([]string{}, node.AIView.CanUseFor...)
	if node.GPUs > 0 && node.Load1 < 2 && node.MemoryPct < 70 && node.DiskPct < 80 {
		canUseFor = append([]string{"모델 추론/테스트 작업(보안 점검 후)"}, canUseFor...)
	}
	appendTranslatedPlainListKO(&lines, "맡기기 좋은 작업", appendUniqueStrings(nil, canUseFor...), 4)
	appendTranslatedPlainListKO(&lines, "피해야 할 작업", node.AIView.ShouldAvoid, 4)
	appendTranslatedPlainListKO(&lines, "바로 볼 위험", node.AIView.ImmediateConcerns, 5)
	appendTranslatedPlainListKO(&lines, "추천 조치", node.AIView.RecommendedActions, 5)
	return strings.Join(lines, "\n")
}

func appendPlainStringList(lines *[]string, title string, values []string, limit int) {
	clean := firstNNonEmpty(values, limit)
	if len(clean) == 0 {
		return
	}
	*lines = append(*lines, "", title)
	for i, value := range clean {
		*lines = append(*lines, fmt.Sprintf("%s %d: %s", strings.TrimSuffix(title, ":"), i+1, value))
	}
}

func appendTranslatedPlainListKO(lines *[]string, title string, values []string, limit int) {
	clean := firstNNonEmpty(values, limit)
	if len(clean) == 0 {
		return
	}
	*lines = append(*lines, "", title)
	for i, value := range clean {
		*lines = append(*lines, fmt.Sprintf("%s %d: %s", title, i+1, translateAIPhraseKO(value)))
	}
}

func firstNNonEmpty(values []string, limit int) []string {
	out := make([]string, 0, minInt(len(values), limit))
	for _, value := range values {
		value = strings.TrimSpace(value)
		if value == "" {
			continue
		}
		out = append(out, value)
		if limit > 0 && len(out) >= limit {
			break
		}
	}
	return out
}

func formatTargetSummaryKO(node agentWorkloadNodeSummary) string {
	role := workloadRoleLabelKO(firstNonEmpty(node.Inventory.PrimaryRole, "general-node"))
	pressure := pressureLabelKO(node.Capacity.OverallPressure)
	decision := "현재 스냅샷만 보면 가벼운 읽기/점검 작업은 가능합니다."
	resourceOK := node.Load1 < 2 && node.MemoryPct < 70 && node.DiskPct < 80
	gpuBusy := node.GPUs > 0 && (node.GPUUsagePct >= 80 || node.GPUMemoryPct >= 80 || node.Capacity.GPUHeadroom == "low")
	if node.GPUs > 0 && resourceOK && !gpuBusy {
		decision = "CPU, 메모리, 디스크, GPU 사용률은 여유가 있어 모델 추론이나 테스트 작업을 맡길 수 있습니다."
	} else if node.GPUs > 0 && gpuBusy {
		decision = "CPU와 메모리는 여유가 있어도 GPU가 이미 바쁩니다. 새 모델 작업은 기존 Ollama/vLLM 작업을 확인하거나 내린 뒤 맡기는 것이 안전합니다."
	}
	if len(node.Capacity.Blockers) > 0 {
		decision += " 다만 운영 차단 요인이 있어 새 작업을 바로 올리기 전에는 먼저 확인해야 합니다."
	}
	concern := ""
	if len(node.AIView.ImmediateConcerns) > 0 && !strings.HasPrefix(node.AIView.ImmediateConcerns[0], "No ") {
		concern = " 가장 먼저 볼 위험은 " + translateAIPhraseKO(node.AIView.ImmediateConcerns[0]) + "입니다."
	}
	usage := ""
	if node.GPUs > 0 {
		usage = fmt.Sprintf(" GPU는 %d개이고 현재 사용률 %.0f%%, 메모리 %.0f%%로 보입니다.", node.GPUs, node.GPUUsagePct, node.GPUMemoryPct)
	}
	return fmt.Sprintf("%s는 %s로 보입니다. 전체 압박도는 %s입니다.%s %s%s", node.Node, role, pressure, usage, decision, concern)
}

func workloadRoleLabelKO(role string) string {
	switch role {
	case "llm-worker":
		return "LLM 추론 노드"
	case "gpu-worker":
		return "GPU 작업 노드"
	case "ai-ui":
		return "AI 채팅 UI 노드"
	case "app-host":
		return "애플리케이션 호스트"
	case "database-host":
		return "데이터베이스 노드"
	case "mail-server":
		return "메일 서버"
	case "memory-node":
		return "메모리/상태 저장 노드"
	case "execution-node":
		return "원격 실행 노드"
	case "meshclaw-node":
		return "MeshClaw 런타임 노드"
	default:
		return "일반 노드"
	}
}

func pressureLabelKO(value string) string {
	switch value {
	case "high":
		return "높음"
	case "medium":
		return "중간"
	case "low":
		return "낮음"
	default:
		return firstNonEmpty(value, "알 수 없음")
	}
}

