func translateAIPlainSummaryKO(value string) string {
	value = translateAIPhraseKO(value)
	value = strings.ReplaceAll(value, " is classified as ", "는 ")
	value = strings.ReplaceAll(value, "; overall pressure is ", " 역할로 분류됩니다. 전체 압박도는 ")
	value = strings.ReplaceAll(value, "; it is not a good target for new heavy work right now", "입니다. 지금은 새 무거운 작업을 맡기기 좋지 않습니다")
	value = strings.ReplaceAll(value, "; it is currently schedulable for ", "입니다. 현재 맡기기 좋은 작업은 ")
	value = strings.ReplaceAll(value, "; main concern: ", "입니다. 가장 먼저 볼 위험은 ")
	return value
}

