func appendRouterWorkloadDigest(lines *[]string, payload map[string]interface{}, target, lang string) {
	appendRouterAgentRefreshDigest(lines, payload, lang)
	report, ok := payload["workloads"].(agentWorkloadsReport)
	if !ok || len(report.Nodes) == 0 {
		if errText, _ := payload["workload_error"].(string); errText != "" {
			if lang == "en" {
				*lines = append(*lines, "", "Node-local workload report:", "- unavailable: "+errText)
			} else {
				*lines = append(*lines, "", "노드별 상세 워크로드:", "- 현재 상세 워크로드 보고서를 읽지 못했습니다: "+errText)
			}
		}
		return
	}

	nodes := report.Nodes
	if strings.TrimSpace(target) != "" {
		nodes = nil
		for _, node := range report.Nodes {
			if strings.EqualFold(node.Node, target) {
				nodes = append(nodes, node)
				break
			}
		}
	}

	if lang == "en" {
		*lines = append(*lines, "", fmt.Sprintf("Node-local workload report: %d node(s) with cached agent data", len(report.Nodes)))
	} else {
		*lines = append(*lines, "", fmt.Sprintf("노드별 상세 워크로드: agent 데이터가 있는 노드 %d개", len(report.Nodes)))
	}
	if len(nodes) == 0 {
		if lang == "en" {
			*lines = append(*lines, "- no node-local agent snapshot for "+target)
		} else {
			*lines = append(*lines, "- "+target+"의 node-local agent 스냅샷은 아직 없습니다.")
		}
		return
	}

	maxNodes := 6
	if strings.TrimSpace(target) != "" {
		maxNodes = 1
	}
	for i, node := range nodes {
		if i >= maxNodes {
			if lang == "en" {
				*lines = append(*lines, fmt.Sprintf("- plus %d more workload reports", len(nodes)-i))
			} else {
				*lines = append(*lines, fmt.Sprintf("- 그 외 상세 워크로드 보고 %d개", len(nodes)-i))
			}
			break
		}
		age := ""
		if node.AgeSeconds > int64((30 * time.Minute).Seconds()) {
			if lang == "en" {
				age = fmt.Sprintf(" | stale %dm", node.AgeSeconds/60)
			} else {
				age = fmt.Sprintf(" | 오래됨 %d분", node.AgeSeconds/60)
			}
		}
		gpu := ""
		if node.GPUs > 0 {
			gpu = fmt.Sprintf(" | gpu=%d %.0f%%/%.0f%%mem", node.GPUs, node.GPUUsagePct, node.GPUMemoryPct)
		}
		*lines = append(*lines, fmt.Sprintf("- %s: load=%.2f | mem=%.1f%% | disk=%.1f%%%s%s", node.Node, node.Load1, node.MemoryPct, node.DiskPct, gpu, age))
		if node.NaturalSummary != "" {
			*lines = append(*lines, "  "+translateWorkloadSummary(node.NaturalSummary, lang))
		}
		if len(node.Workloads) > 0 {
			parts := make([]string, 0, 4)
			for _, workload := range firstNWorkloads(node.Workloads, 4) {
				label := workloadPurposeLabel(workload.Purpose)
				if lang != "en" {
					label = workloadPurposeLabelKorean(workload.Purpose)
				}
				detail := label
				if workload.CPUPct > 0 || workload.MemPct > 0 {
					detail += fmt.Sprintf(" cpu %.1f%% mem %.1f%%", workload.CPUPct, workload.MemPct)
				} else if len(workload.Containers) > 0 {
					detail += fmt.Sprintf(" containers %d", len(workload.Containers))
				} else if len(workload.Ports) > 0 {
					detail += fmt.Sprintf(" ports %d", len(workload.Ports))
				}
				parts = append(parts, detail)
			}
			if len(parts) > 0 {
				if lang == "en" {
					*lines = append(*lines, "  workloads: "+strings.Join(parts, " / "))
				} else {
					*lines = append(*lines, "  역할: "+strings.Join(parts, " / "))
				}
			}
		}
		if len(node.TopProcesses) > 0 {
			procParts := make([]string, 0, minInt(len(node.TopProcesses), 3))
			for _, proc := range node.TopProcesses[:minInt(len(node.TopProcesses), 3)] {
				cmd := strings.TrimSpace(proc.Command)
				if len(cmd) > 70 {
					cmd = cmd[:70] + "..."
				}
				procParts = append(procParts, fmt.Sprintf("%s %.1f%%cpu %.1f%%mem", cmd, proc.CPUPct, proc.MemPct))
			}
			if lang == "en" {
				*lines = append(*lines, "  top: "+strings.Join(procParts, " | "))
			} else {
				*lines = append(*lines, "  상위 프로세스: "+strings.Join(procParts, " | "))
			}
		}
		if len(node.Security) > 0 {
			secParts := make([]string, 0, 3)
			for _, finding := range node.Security {
				if finding.Severity == "high" || finding.Severity == "medium" {
					secParts = append(secParts, fmt.Sprintf("[%s] %s", finding.Severity, finding.Title))
				}
				if len(secParts) >= 3 {
					break
				}
			}
			if len(secParts) > 0 {
				if lang == "en" {
					*lines = append(*lines, "  risks: "+strings.Join(secParts, " / "))
				} else {
					*lines = append(*lines, "  주의: "+strings.Join(secParts, " / "))
				}
			}
		}
	}
	if strings.TrimSpace(target) == "" && len(report.NextActions) > 0 {
		if lang == "en" {
			*lines = append(*lines, "", "Suggested next actions:")
		} else {
			*lines = append(*lines, "", "다음 확인 후보:")
		}
		for i, action := range report.NextActions {
			if i >= 4 {
				break
			}
			if lang == "en" {
				*lines = append(*lines, "- "+action)
			} else {
				*lines = append(*lines, "- "+translateAgentNextAction(action))
			}
		}
	}
	appendRouterChangeDigest(lines, payload, target, lang)
}

func formatRouterFleetOpsReport(plan router.Plan, payload map[string]interface{}, lang string) string {
	states, _ := payload["states"].(map[string]*monitor.NodeState)
	alerts, _ := payload["alerts"].([]monitor.Alert)
	workloads, _ := payload["workloads"].(agentWorkloadsReport)
	security, _ := payload["security"].(agentSecurityReport)
	changes, _ := payload["changes"].(agentChangesReport)
	refresh, _ := payload["agent_refresh"].(agentPullReport)
	online := 0
	for _, state := range states {
		if state != nil && state.Online {
			online++
		}
	}
	if strings.TrimSpace(plan.Target) != "" {
		report, _ := payload["workloads"].(agentWorkloadsReport)
		if text := formatRouterTargetAIView(plan.Target, report, lang); text != "" {
			lines := []string{text}
			appendRouterEvidence(&lines, payload)
			return strings.Join(lines, "\n")
		}
	}
	if strings.EqualFold(plan.Source, "openwebui") && strings.TrimSpace(plan.Target) == "" {
		if isRouterSecurityFocusedRequest(plan.Message) {
			return formatRouterFleetSecurityCardKO(security, payload)
		}
		if lang == "en" {
			return formatRouterFleetOpsCardEN(states, alerts, workloads, security, changes, refresh, payload, online)
		}
		return formatRouterFleetOpsCardKO(states, alerts, workloads, security, changes, refresh, payload, online)
	}
	if lang == "en" {
		return formatRouterFleetOpsReportEN(plan, states, alerts, workloads, security, changes, refresh, payload)
	}
	return formatRouterFleetOpsReportKO(plan, states, alerts, workloads, security, changes, refresh, payload, online)
}

func formatRouterFleetOpsCardKO(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport, refresh agentPullReport, payload map[string]interface{}, online int) string {
	lines := []string{
		"MeshClaw 운영 요약",
		fmt.Sprintf("상태: 노드 %d개 중 %d개 응답, 알림 %d개, agent 스냅샷 %d개.", len(states), online, len(alerts), len(workloads.Nodes)),
	}
	if refresh.OK > 0 || refresh.Failed > 0 {
		lines = append(lines, fmt.Sprintf("수집: 최신 agent 수집 성공 %d개, 실패 %d개.", refresh.OK, refresh.Failed))
	}
	judgement := routerFleetCardJudgementKO(alerts, workloads, security, changes)
	if judgement != "" {
		lines = append(lines, "", "판단: "+judgement)
	}
	lines = append(lines, "", "바로 볼 위험")
	for i, item := range firstN(routerFleetPriorityItemsKO(alerts, workloads, security, refresh), 3) {
		lines = append(lines, fmt.Sprintf("위험 %d: %s", i+1, item))
	}
	next := routerFleetNextActionsKO(alerts, workloads, security)
	if len(next) > 0 {
		lines = append(lines, "", "다음 조치")
		for i, action := range firstN(next, 3) {
			lines = append(lines, fmt.Sprintf("조치 %d: %s", i+1, routerPlainTextAction(action)))
		}
	}
	lines = append(lines, "", fmt.Sprintf("근거: 공개 리스너 %d개, Docker 공개 포트 %d개, 실패 systemd unit %d개, 보안 주의 높음 %d개 / 주의 %d개.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts, security.Totals.FailedUnits, security.Totals.HighFindings, security.Totals.MediumFindings))
	lines = append(lines, "더 자세히 보려면 노드별 상세, 보안만 자세히, d1 디스크 조사처럼 이어서 물어보세요.")
	lines = append(lines, "깊은 복구 판단이나 실제 수정은 Codex/Claude MCP에서 이 evidence를 이어받아 진행하는 것이 안전합니다.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func formatRouterFleetOpsCardEN(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport, refresh agentPullReport, payload map[string]interface{}, online int) string {
	lines := []string{
		"MeshClaw operations summary",
		fmt.Sprintf("Status: %d/%d nodes responding, %d alerts, %d agent snapshots.", online, len(states), len(alerts), len(workloads.Nodes)),
	}
	if refresh.OK > 0 || refresh.Failed > 0 {
		lines = append(lines, fmt.Sprintf("Collection: %d fresh agent pulls ok, %d failed.", refresh.OK, refresh.Failed))
	}
	if len(alerts) == 0 && len(security.Risks) == 0 {
		lines = append(lines, "", "Judgement: no immediate critical issue in the available snapshots.")
	} else {
		lines = append(lines, "", "Judgement: investigate the highest-severity operational risks first; this is evidence triage, not proof of compromise.")
	}
	lines = append(lines, "", "Risks to check now")
	for i, item := range firstN(routerFleetPriorityItemsEN(alerts, workloads, security, refresh), 3) {
		lines = append(lines, fmt.Sprintf("Risk %d: %s", i+1, item))
	}
	next := routerFleetNextActionsKO(alerts, workloads, security)
	if len(next) > 0 {
		lines = append(lines, "", "Next checks")
		for i, action := range firstN(next, 3) {
			lines = append(lines, fmt.Sprintf("Check %d: %s", i+1, routerPlainTextAction(action)))
		}
	}
	lines = append(lines, "", fmt.Sprintf("Evidence basis: public listeners=%d, public Docker ports=%d, failed systemd units=%d, security findings high=%d / medium=%d.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts, security.Totals.FailedUnits, security.Totals.HighFindings, security.Totals.MediumFindings))
	lines = append(lines, "Ask for node details, security only, or investigate d1 disk to drill down.")
	lines = append(lines, "For deep repair judgement or real changes, continue from this evidence in Codex/Claude MCP.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func routerPlainTextAction(action string) string {
	action = strings.ReplaceAll(action, "`", "")
	action = strings.ReplaceAll(action, "  ", " ")
	return strings.TrimSpace(action)
}

func isRouterSecurityFocusedRequest(message string) bool {
	lower := strings.ToLower(strings.TrimSpace(message))
	return containsAny(lower,
		"보안만", "보안 자세", "보안 상세", "공개 포트", "열린 포트", "fail2ban", "ssh 공격", "침입 징후", "방화벽",
		"security only", "security detail", "public port", "open port", "firewall", "ssh attack",
	)
}

func formatRouterFleetSecurityCardKO(security agentSecurityReport, payload map[string]interface{}) string {
	lines := []string{
		"MeshClaw 보안 요약",
		fmt.Sprintf("범위: agent 스냅샷 %d개 노드 기준.", security.Totals.Nodes),
		fmt.Sprintf("노출: 공개 리스너 %d개, Docker 공개 포트 %d개.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts),
		fmt.Sprintf("방어/장애: cron %d개, systemd timer %d개, 실패 unit %d개, 보안 주의 높음 %d개 / 주의 %d개.", security.Totals.CronEntries, security.Totals.SystemdTimers, security.Totals.FailedUnits, security.Totals.HighFindings, security.Totals.MediumFindings),
		"",
		"판단: 이 값은 침입 확정이 아니라 공격 표면과 운영 위험을 좁히는 신호입니다. 공개 SSH, fail2ban 부재, 불필요한 공개 포트, 실패 서비스부터 확인해야 합니다.",
	}
	if len(security.Risks) > 0 {
		lines = append(lines, "", "바로 볼 보안 위험")
		for i, risk := range firstNSecurityRisks(security.Risks, 5) {
			lines = append(lines, fmt.Sprintf("위험 %d: %s: %s - %s", i+1, risk.Node, routerSeverityKorean(risk.Severity), routerSecurityRiskKorean(risk)))
		}
	}
	nodes := firstNSecurityNodesWithSignal(security.Nodes, 5)
	if len(nodes) > 0 {
		lines = append(lines, "", "노드별 신호")
		for _, node := range nodes {
			fail2ban := "fail2ban 미확인"
			if node.Fail2Ban.Running {
				fail2ban = fmt.Sprintf("fail2ban 실행 중(%d jail)", len(node.Fail2Ban.Jails))
			}
			lines = append(lines, fmt.Sprintf("%s: 공개 리스너 %d개, Docker 공개 포트 %d개, 실패 unit %d개, %s", node.Node, len(node.PublicListeners), len(node.PublicDockerPorts), len(node.FailedUnits), fail2ban))
		}
	}
	if len(security.NextActions) > 0 {
		lines = append(lines, "", "다음 조치")
		for i, action := range firstN(security.NextActions, 4) {
			lines = append(lines, fmt.Sprintf("조치 %d: %s", i+1, routerPlainTextAction(translateAgentNextAction(action))))
		}
	}
	lines = append(lines, "", "해석 기준: 이 화면은 로컬 모델이 보는 빠른 보안 요약입니다. 침입 판정, 차단 정책 변경, 서비스 수정은 Codex/Claude MCP에서 이 evidence를 이어받아 진행하는 것이 안전합니다.")
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func firstNSecurityNodesWithSignal(nodes []agentSecurityNode, n int) []agentSecurityNode {
	out := []agentSecurityNode{}
	for _, node := range nodes {
		if len(node.PublicListeners) == 0 && len(node.PublicDockerPorts) == 0 && len(node.FailedUnits) == 0 && len(node.SecurityFindings) == 0 {
			continue
		}
		out = append(out, node)
		if len(out) >= n {
			break
		}
	}
	return out
}

func routerFleetCardJudgementKO(alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport) string {
	offline := 0
	for _, alert := range alerts {
		if alert.Type == "offline" {
			offline++
		}
	}
	switch {
	case offline > 0:
		return fmt.Sprintf("응답하지 않는 노드 %d개가 최우선입니다. 침입 확정은 아니고 전원, Tailscale, vssh daemon 문제일 가능성을 먼저 확인합니다.", offline)
	case security.Totals.HighFindings > 0:
		return "보안 고위험 항목이 있어 공개 포트, SSH/fail2ban, 실패 서비스 순서로 확인해야 합니다."
	case len(workloads.Risks) > 0:
		return "자원 사용 또는 워크로드 위험이 있습니다. 새 작업 배치 전에 해당 노드의 프로세스와 디스크를 확인해야 합니다."
	case len(changes.Nodes) > 0:
		return "큰 장애 신호는 약하지만 최근 변화가 있습니다. 변화가 있는 노드부터 확인하면 됩니다."
	default:
		return "현재 스냅샷 기준으로 즉시 장애 신호는 강하지 않습니다. 정기 수집 상태를 유지하면 됩니다."
	}
}

func formatRouterFleetOpsReportKO(plan router.Plan, states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport, refresh agentPullReport, payload map[string]interface{}, online int) string {
	nodeLimit := 6
	priorityLimit := 6
	actionLimit := 5
	if strings.EqualFold(plan.Source, "openwebui") {
		nodeLimit = 4
		priorityLimit = 5
		actionLimit = 4
	}
	lines := []string{
		"MeshClaw 종합 운영 보고입니다.",
		"",
		fmt.Sprintf("현재 기준으로 %d개 노드 중 %d개가 응답하고 있습니다. 활성 알림은 %d개이고, agent 상세 스냅샷은 %d개 노드에서 확보됐습니다.", len(states), online, len(alerts), len(workloads.Nodes)),
	}
	if refresh.OK > 0 || refresh.Failed > 0 {
		lines = append(lines, fmt.Sprintf("최신 수집: 성공 %d개, 실패 %d개", refresh.OK, refresh.Failed))
	}
	narrative := routerFleetModelNarrativeKO(states, alerts, workloads, security, changes)
	if narrative == "" {
		narrative = routerFleetDeterministicNarrativeKO(states, alerts, workloads, security, changes)
	}
	if narrative != "" {
		lines = append(lines, "", "판단:", narrative)
	}

	lines = append(lines, "", "먼저 볼 것:")
	for _, item := range firstN(routerFleetPriorityItemsKO(alerts, workloads, security, refresh), priorityLimit) {
		lines = append(lines, "- "+item)
	}

	lines = append(lines, "", "노드별 판독:")
	for _, line := range routerFleetNodeInterpretationsKO(states, workloads, security, plan.Target, nodeLimit) {
		lines = append(lines, "- "+line)
	}
	if strings.EqualFold(plan.Source, "openwebui") && plan.Target == "" && len(workloads.Nodes) > nodeLimit {
		lines = append(lines, "- 전체 노드 상세를 계속 보려면 `나머지 노드도 이어서 보여줘`라고 보내세요.")
	}

	if len(changes.Nodes) > 0 {
		lines = append(lines, "", "최근 변화:")
		for _, item := range firstNAgentChanges(changes.Nodes, 5) {
			lines = append(lines, "- "+item.Node+": "+translateAgentChangeSummary(firstNonEmpty(item.Summary, "No material change in the last two samples."), "ko"))
			if len(item.NewSecurityFindings) > 0 {
				lines = append(lines, "  새 보안 주의: "+strings.Join(firstN(item.NewSecurityFindings, 2), " / "))
			}
		}
	}

	next := routerFleetNextActionsKO(alerts, workloads, security)
	if len(next) > 0 {
		lines = append(lines, "", "바로 실행할 수 있는 확인:")
		for _, action := range firstN(next, actionLimit) {
			lines = append(lines, "- "+action)
		}
	}
	lines = append(lines, "", fmt.Sprintf("근거 요약: 공개 리스너 %d개, 공개 Docker 포트 %d개, 실패 systemd unit %d개, 보안 주의 높음 %d개 / 주의 %d개입니다.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts, security.Totals.FailedUnits, security.Totals.HighFindings, security.Totals.MediumFindings))
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func formatRouterFleetOpsReportEN(plan router.Plan, states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport, refresh agentPullReport, payload map[string]interface{}) string {
	online := 0
	for _, state := range states {
		if state != nil && state.Online {
			online++
		}
	}
	lines := []string{
		"MeshClaw fleet operations report.",
		"",
		fmt.Sprintf("Summary: %d nodes, %d online, %d active alerts, %d agent snapshots, %d security findings (high %d / medium %d)", len(states), online, len(alerts), len(workloads.Nodes), security.Totals.HighFindings+security.Totals.MediumFindings, security.Totals.HighFindings, security.Totals.MediumFindings),
	}
	if refresh.OK > 0 || refresh.Failed > 0 {
		lines = append(lines, fmt.Sprintf("Fresh collection: %d ok, %d failed", refresh.OK, refresh.Failed))
	}
	lines = append(lines, "", "Operator judgement:")
	if len(alerts) == 0 && len(security.Risks) == 0 {
		lines = append(lines, "- No immediate critical condition was detected in the available snapshots.")
	} else {
		lines = append(lines, "- Treat this as evidence of operational risk, not proof of compromise. Investigate the highest-severity nodes first.")
	}
	if security.Totals.PublicListeners > 0 || security.Totals.PublicDockerPorts > 0 {
		lines = append(lines, fmt.Sprintf("- Public exposure exists: listeners=%d, Docker ports=%d. Confirm each public surface is intentional.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts))
	}
	lines = append(lines, "", "Priorities:")
	for _, item := range routerFleetPriorityItemsKO(alerts, workloads, security, refresh) {
		lines = append(lines, "- "+item)
	}
	lines = append(lines, "", "Node interpretation:")
	for _, line := range routerFleetNodeInterpretationsKO(states, workloads, security, plan.Target, 8) {
		lines = append(lines, "- "+line)
	}
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func routerFleetJudgementKO(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport) []string {
	lines := []string{}
	if len(alerts) == 0 && len(security.Risks) == 0 {
		lines = append(lines, "- 현재 스냅샷 기준으로 즉시 장애나 침입 징후는 강하게 보이지 않습니다.")
	} else {
		lines = append(lines, "- 이 보고서는 침입 확정 판정이 아니라 운영 징후 정리입니다. 오프라인, 공개 포트, fail2ban 부재, 실패 서비스, 자원 급증을 우선 확인해야 합니다.")
	}
	offline := []string{}
	for name, state := range states {
		if state != nil && !state.Online {
			offline = append(offline, name)
		}
	}
	sort.Strings(offline)
	if len(offline) > 0 {
		lines = append(lines, "- 오프라인/응답불가 노드: "+strings.Join(offline, ", ")+". Tailscale/vssh/전원 상태를 먼저 확인해야 합니다.")
	}
	if security.Totals.PublicListeners > 0 || security.Totals.PublicDockerPorts > 0 {
		lines = append(lines, fmt.Sprintf("- 외부 노출 표면: 공개 리스너 %d개, 공개 Docker 포트 %d개. 의도한 서비스인지 검토해야 합니다.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts))
	}
	if security.Totals.FailedUnits > 0 {
		lines = append(lines, fmt.Sprintf("- 실패한 systemd unit %d개가 보입니다. 장애인지 오래된 잔재 서비스인지 분리해야 합니다.", security.Totals.FailedUnits))
	}
	if len(changes.Nodes) > 0 {
		lines = append(lines, fmt.Sprintf("- 최근 변화 비교가 가능한 노드 %d개가 있습니다. 새 보안 주의나 워크로드 변화가 있는 노드를 먼저 봅니다.", len(changes.Nodes)))
	}
	if len(workloads.Nodes) == 0 {
		lines = append(lines, "- node-local agent 스냅샷이 아직 부족합니다. 모든 서버에 agent collector가 상시 실행되어야 보고 품질이 올라갑니다.")
	}
	return lines
}

func routerFleetPriorityItemsKO(alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, refresh agentPullReport) []string {
	items := []string{}
	for _, alert := range alerts {
		switch alert.Level {
		case "critical":
			items = append(items, fmt.Sprintf("%s: 긴급 - %s", alert.Node, routerAlertKorean(alert)))
		case "warning":
			items = append(items, fmt.Sprintf("%s: 주의 - %s", alert.Node, routerAlertKorean(alert)))
		}
	}
	for _, risk := range security.Risks {
		if risk.Severity == "high" || risk.Severity == "medium" {
			items = append(items, fmt.Sprintf("%s: %s - %s", risk.Node, routerSeverityKorean(risk.Severity), routerSecurityRiskKorean(risk)))
		}
		if len(items) >= 10 {
			break
		}
	}
	for _, risk := range workloads.Risks {
		if risk.Severity == "high" {
			items = append(items, fmt.Sprintf("%s: 높음 - %s", risk.Node, routerWorkloadRiskKorean(risk)))
		}
		if len(items) >= 10 {
			break
		}
	}
	if refresh.Failed > 0 {
		failed := []string{}
		for _, host := range refresh.Hosts {
			if !host.OK && host.Host != "" {
				failed = append(failed, host.Host)
			}
		}
		if len(failed) > 0 {
			items = append(items, "agent 최신 수집 실패: "+strings.Join(firstN(failed, 6), ", ")+". 이 노드들은 보고가 오래됐을 수 있습니다.")
		}
	}
	items = appendUniqueStrings(nil, items...)
	if len(items) == 0 {
		items = append(items, "즉시 조치할 critical 항목은 없습니다. 정기 모니터링과 agent collector 상태를 유지하세요.")
	}
	if len(items) > 12 {
		items = items[:12]
	}
	return items
}

func routerFleetPriorityItemsEN(alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, refresh agentPullReport) []string {
	items := []string{}
	for _, alert := range alerts {
		if alert.Level == "critical" || alert.Level == "warning" {
			items = append(items, fmt.Sprintf("%s: %s - %s", alert.Node, alert.Level, alert.Message))
		}
	}
	for _, risk := range security.Risks {
		if risk.Severity == "high" || risk.Severity == "medium" {
			items = append(items, fmt.Sprintf("%s: %s - %s", risk.Node, risk.Severity, risk.Title))
		}
		if len(items) >= 10 {
			break
		}
	}
	for _, risk := range workloads.Risks {
		if risk.Severity == "high" {
			items = append(items, fmt.Sprintf("%s: high - %s", risk.Node, risk.Title))
		}
		if len(items) >= 10 {
			break
		}
	}
	if refresh.Failed > 0 {
		failed := []string{}
		for _, host := range refresh.Hosts {
			if !host.OK && host.Host != "" {
				failed = append(failed, host.Host)
			}
		}
		if len(failed) > 0 {
			items = append(items, "fresh agent collection failed: "+strings.Join(firstN(failed, 6), ", "))
		}
	}
	items = appendUniqueStrings(nil, items...)
	if len(items) == 0 {
		items = append(items, "No critical item detected; keep scheduled monitoring and agent collectors running.")
	}
	if len(items) > 12 {
		items = items[:12]
	}
	return items
}

func routerFleetModelNarrativeKO(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport) string {
	if !envBool("MESHCLAW_ROUTER_FLEET_MODEL_SUMMARY") {
		return ""
	}
	facts := buildRouterFleetNarrativeFacts(states, alerts, workloads, security, changes)
	if facts == "" {
		return ""
	}
	timeout := 12 * time.Second
	if raw := strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_EXPLAINER_TIMEOUT")); raw != "" {
		if parsed, err := time.ParseDuration(raw); err == nil && parsed > 0 && parsed < 45*time.Second {
			timeout = parsed
		}
	}
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()
	cfg := aichat.Config{
		BaseURL: firstNonEmpty(
			strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_EXPLAINER_BASE_URL")),
			strings.TrimSpace(os.Getenv("MESHCLAW_ASSISTANT_BASE_URL")),
			"http://localhost:11434/v1",
		),
		APIKey:      firstNonEmpty(strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_EXPLAINER_API_KEY")), "ollama"),
		Model:       firstNonEmpty(strings.TrimSpace(os.Getenv("MESHCLAW_ROUTER_EXPLAINER_MODEL")), strings.TrimSpace(os.Getenv("MESHCLAW_ASSISTANT_MODEL")), "gemma4:e4b"),
		MaxTokens:   650,
		Temperature: 0.2,
		SystemPrompt: strings.Join([]string{
			"You are MeshClaw's Korean operations interpreter.",
			"Write Korean only.",
			"Do not invent facts.",
			"Do not say you executed commands.",
			"Do not mention raw JSON or DSL.",
			"Write like a senior server operator briefing a human.",
			"Keep it concise: 5 to 7 sentences.",
			"Cover: current risk, likely meaning, what to check first, what is not yet proven.",
		}, "\n"),
	}
	reply, err := aichat.NewClient(cfg).Chat(ctx, nil, "다음 구조화된 서버 상태 사실을 운영자가 바로 이해할 수 있게 자연스러운 한국어로 해석해줘.\n\n"+facts)
	if err != nil {
		return ""
	}
	return truncate(aichat.CleanResponse(reply), 1100)
}

func envBool(name string) bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(name))) {
	case "1", "true", "yes", "on":
		return true
	default:
		return false
	}
}

func routerFleetDeterministicNarrativeKO(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport) string {
	offline := []string{}
	diskNodes := []string{}
	memNodes := []string{}
	for name, state := range states {
		if state == nil {
			continue
		}
		if !state.Online {
			offline = append(offline, name)
			continue
		}
		if state.Disk >= 80 {
			diskNodes = append(diskNodes, fmt.Sprintf("%s %.0f%%", name, state.Disk))
		}
		if state.Memory >= 85 {
			memNodes = append(memNodes, fmt.Sprintf("%s %.0f%%", name, state.Memory))
		}
	}
	sort.Strings(offline)
	sort.Strings(diskNodes)
	sort.Strings(memNodes)

	sentences := []string{}
	if len(offline) > 0 {
		sentences = append(sentences, "현재 가장 먼저 볼 것은 "+strings.Join(offline, ", ")+"의 응답 불가 상태입니다. 이것은 침입 증거라기보다 전원, Tailscale, vssh daemon, 방화벽 중 하나가 끊겼다는 운영 신호입니다.")
	} else {
		sentences = append(sentences, "현재 수집된 스냅샷 기준으로 전체 플릿의 기본 연결성은 유지되고 있습니다.")
	}
	if len(diskNodes) > 0 {
		sentences = append(sentences, "디스크는 "+strings.Join(diskNodes, ", ")+"가 우선 점검 대상입니다. 학습 산출물, 모델 캐시, Docker 볼륨처럼 빠르게 커지는 데이터를 먼저 확인해야 합니다.")
	}
	if len(memNodes) > 0 {
		sentences = append(sentences, "메모리는 "+strings.Join(memNodes, ", ")+"에서 압박이 보입니다. 브라우저, Open WebUI, Ollama, 장기 실행 작업이 실제 용도인지 확인해야 합니다.")
	}
	if security.Totals.PublicListeners > 0 || security.Totals.PublicDockerPorts > 0 {
		sentences = append(sentences, fmt.Sprintf("보안 측면에서는 공개 리스너 %d개와 공개 Docker 포트 %d개가 보입니다. 공개 자체가 문제라는 뜻은 아니지만, 각 포트가 의도된 서비스인지와 fail2ban 같은 방어 계층이 있는지 확인해야 합니다.", security.Totals.PublicListeners, security.Totals.PublicDockerPorts))
	}
	if security.Totals.FailedUnits > 0 {
		sentences = append(sentences, fmt.Sprintf("실패한 systemd unit이 %d개 있어 서비스 장애와 오래된 잔재 unit을 분리해야 합니다. 실제 사용자 기능에 영향을 주는 unit부터 트리아지하는 것이 맞습니다.", security.Totals.FailedUnits))
	}
	if len(changes.Nodes) > 0 {
		sentences = append(sentences, fmt.Sprintf("최근 변화 비교가 가능한 노드가 %d개 있으므로, 다음 단계는 새로 생긴 보안 주의와 워크로드 변화를 기준으로 원인을 좁히는 것입니다.", len(changes.Nodes)))
	}
	if len(workloads.Nodes) == 0 {
		sentences = append(sentences, "다만 node-local agent 상세 스냅샷이 부족하면 프로세스 용도와 보안 해석의 정확도가 떨어집니다. 각 노드의 collector가 주기적으로 최신 상태를 저장하도록 유지해야 합니다.")
	}
	if len(sentences) == 0 {
		sentences = append(sentences, "현재 스냅샷에서는 즉시 조치할 강한 이상 징후가 보이지 않습니다. 그래도 공개 포트, 실패 서비스, 디스크 증가 추세는 정기적으로 비교해야 합니다.")
	}
	if len(sentences) > 6 {
		sentences = sentences[:6]
	}
	return strings.Join(sentences, " ")
}

func buildRouterFleetNarrativeFacts(states map[string]*monitor.NodeState, alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport, changes agentChangesReport) string {
	offline := []string{}
	for name, state := range states {
		if state != nil && !state.Online {
			offline = append(offline, name)
		}
	}
	sort.Strings(offline)
	lines := []string{
		fmt.Sprintf("nodes=%d offline=%s alerts=%d", len(states), strings.Join(offline, ","), len(alerts)),
		fmt.Sprintf("public_listeners=%d public_docker_ports=%d failed_systemd_units=%d high_findings=%d medium_findings=%d", security.Totals.PublicListeners, security.Totals.PublicDockerPorts, security.Totals.FailedUnits, security.Totals.HighFindings, security.Totals.MediumFindings),
	}
	for _, alert := range firstNAlerts(alerts, 6) {
		lines = append(lines, "alert: "+alert.Node+" "+routerAlertKorean(alert))
	}
	for _, risk := range firstNSecurityRisks(security.Risks, 8) {
		lines = append(lines, "risk: "+risk.Node+" "+routerSeverityKorean(risk.Severity)+" "+routerSecurityRiskKorean(risk))
	}
	for _, node := range firstNWorkloadNodes(workloads.Nodes, 5) {
		lines = append(lines, "workload: "+node.Node+" "+strings.TrimPrefix(translateWorkloadSummary(node.NaturalSummary, "ko"), "현재 용도: "))
	}
	for _, change := range firstNAgentChanges(changes.Nodes, 4) {
		lines = append(lines, "change: "+change.Node+" "+translateAgentChangeSummary(change.Summary, "ko"))
	}
	return strings.Join(lines, "\n")
}

func firstNAlerts(values []monitor.Alert, n int) []monitor.Alert {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func firstNSecurityRisks(values []agentSecurityRisk, n int) []agentSecurityRisk {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func firstNWorkloadNodes(values []agentWorkloadNodeSummary, n int) []agentWorkloadNodeSummary {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func routerFleetNodeInterpretationsKO(states map[string]*monitor.NodeState, workloads agentWorkloadsReport, security agentSecurityReport, target string, limit int) []string {
	workByNode := map[string]agentWorkloadNodeSummary{}
	for _, node := range workloads.Nodes {
		workByNode[strings.ToLower(node.Node)] = node
	}
	secByNode := map[string]agentSecurityNode{}
	for _, node := range security.Nodes {
		secByNode[strings.ToLower(node.Node)] = node
	}
	names := make([]string, 0, len(states)+len(workByNode))
	seen := map[string]bool{}
	for name := range states {
		if target != "" && !strings.EqualFold(name, target) {
			continue
		}
		seen[strings.ToLower(name)] = true
		names = append(names, name)
	}
	for _, node := range workloads.Nodes {
		if target != "" && !strings.EqualFold(node.Node, target) {
			continue
		}
		key := strings.ToLower(node.Node)
		if !seen[key] {
			seen[key] = true
			names = append(names, node.Node)
		}
	}
	sort.Strings(names)
	if limit <= 0 {
		limit = len(names)
	}
	lines := []string{}
	displayed := 0
	for _, name := range names {
		if displayed >= limit {
			lines = append(lines, "나머지 노드도 필요하면 이어서 보여줄 수 있습니다.")
			break
		}
		state := states[name]
		work := workByNode[strings.ToLower(name)]
		sec := secByNode[strings.ToLower(name)]
		sentences := []string{}
		if state != nil {
			status := "오프라인"
			if state.Online {
				status = "온라인"
			}
			metricParts := []string{}
			if state.CPU > 0 {
				metricParts = append(metricParts, fmt.Sprintf("부하 %.2f", state.CPU))
			}
			if state.Memory > 0 {
				metricParts = append(metricParts, fmt.Sprintf("메모리 %.1f%%", state.Memory))
			}
			if state.Disk > 0 {
				metricParts = append(metricParts, fmt.Sprintf("디스크 %.1f%%", state.Disk))
			}
			if len(metricParts) > 0 {
				sentences = append(sentences, fmt.Sprintf("%s는 %s이고 %s입니다.", name, status, strings.Join(metricParts, ", ")))
			} else {
				sentences = append(sentences, fmt.Sprintf("%s는 %s입니다.", name, status))
			}
		} else {
			sentences = append(sentences, fmt.Sprintf("%s는 monitor 스냅샷이 없습니다.", name))
		}
		if work.Node != "" {
			summary := routerCleanWorkloadSummaryKO(work.NaturalSummary)
			if summary != "" {
				if strings.HasSuffix(summary, "합니다") || strings.HasSuffix(summary, "해야 합니다") {
					sentences = append(sentences, summary+".")
				} else {
					sentences = append(sentences, "현재 역할은 "+summary+"입니다.")
				}
			}
			if len(work.TopProcesses) > 0 {
				sentences = append(sentences, "가장 눈에 띄는 프로세스는 "+routerTopProcessPhraseKO(work.TopProcesses[0])+"입니다.")
			}
		} else {
			sentences = append(sentences, "프로세스 용도까지 해석할 agent 상세 스냅샷은 아직 없습니다.")
		}
		secParts := []string{}
		if sec.Node != "" {
			if len(sec.PublicListeners) > 0 {
				secParts = append(secParts, fmt.Sprintf("공개 리스너 %d개", len(sec.PublicListeners)))
			}
			if len(sec.PublicDockerPorts) > 0 {
				secParts = append(secParts, fmt.Sprintf("공개 Docker 포트 %d개", len(sec.PublicDockerPorts)))
			}
			if sec.Fail2Ban.Available && sec.Fail2Ban.Running {
				secParts = append(secParts, fmt.Sprintf("fail2ban 실행 중(%d개 jail)", len(sec.Fail2Ban.Jails)))
			} else if sec.OS == "linux" {
				secParts = append(secParts, "fail2ban 미확인")
			}
			if len(sec.FailedUnits) > 0 {
				secParts = append(secParts, fmt.Sprintf("실패 unit %d개", len(sec.FailedUnits)))
			}
			high, medium := securityFindingCounts(sec.SecurityFindings)
			if high+medium > 0 {
				secParts = append(secParts, fmt.Sprintf("보안 주의 높음 %d개 / 주의 %d개", high, medium))
			}
		}
		if len(secParts) > 0 {
			sentences = append(sentences, "보안 관점에서는 "+strings.Join(secParts, ", ")+" 상태입니다.")
		}
		lines = append(lines, strings.Join(sentences, " "))
		displayed++
	}
	if len(lines) == 0 {
		lines = append(lines, "표시할 노드 상세가 없습니다. agent collector가 수집한 스냅샷을 먼저 확보해야 합니다.")
	}
	return lines
}

func routerFleetNextActionsKO(alerts []monitor.Alert, workloads agentWorkloadsReport, security agentSecurityReport) []string {
	actions := []string{}
	for _, alert := range alerts {
		switch alert.Type {
		case "offline":
			actions = append(actions, fmt.Sprintf("%s: 전원/Tailscale/vssh daemon 상태를 확인합니다.", alert.Node))
		case "disk":
			actions = append(actions, fmt.Sprintf("%s: `meshclaw disk-investigate %s /`로 큰 디렉터리를 확인한 뒤 정리 계획을 세웁니다.", alert.Node, alert.Node))
		case "memory":
			actions = append(actions, fmt.Sprintf("%s: `meshclaw process-top %s`로 메모리 상위 프로세스를 확인합니다.", alert.Node, alert.Node))
		}
	}
	for _, action := range security.NextActions {
		actions = append(actions, translateAgentNextAction(action))
	}
	for _, action := range workloads.NextActions {
		actions = append(actions, translateAgentNextAction(action))
	}
	actions = appendUniqueStrings(nil, actions...)
	if len(actions) > 8 {
		actions = actions[:8]
	}
	return actions
}

func routerTopProcessPhrase(process nodestate.ProcessState) string {
	cmd := strings.TrimSpace(process.Command)
	if cmd == "" {
		cmd = "unknown"
	}
	if len(cmd) > 48 {
		cmd = cmd[:48] + "..."
	}
	return fmt.Sprintf("%s %.1f%%cpu %.1f%%mem", cmd, process.CPUPct, process.MemPct)
}

func routerTopProcessPhraseKO(process nodestate.ProcessState) string {
	cmd := strings.TrimSpace(process.Command)
	if cmd == "" || cmd == "unknown" {
		cmd = "이름이 확인되지 않은 프로세스"
	}
	if len(cmd) > 48 {
		cmd = cmd[:48] + "..."
	}
	return fmt.Sprintf("%s(CPU %.1f%%, 메모리 %.1f%%)", cmd, process.CPUPct, process.MemPct)
}

func routerCleanWorkloadSummaryKO(summary string) string {
	out := strings.TrimSpace(strings.TrimPrefix(translateWorkloadSummary(summary, "ko"), "현재 용도:"))
	out = strings.ReplaceAll(out, "unknown", "미분류 프로세스")
	out = strings.ReplaceAll(out, "SSH access", "SSH 접근")
	out = strings.ReplaceAll(out, "cpu ", "CPU ")
	out = strings.ReplaceAll(out, "mem ", "메모리 ")
	out = strings.ReplaceAll(out, ",.", ".")
	out = strings.TrimSpace(out)
	out = strings.TrimSuffix(out, ".")
	out = strings.TrimSuffix(out, "입니다")
	return strings.TrimSpace(out)
}

func securityFindingCounts(values []nodestate.SecurityFinding) (int, int) {
	high, medium := 0, 0
	for _, finding := range values {
		switch finding.Severity {
		case "high":
			high++
		case "medium":
			medium++
		}
	}
	return high, medium
}

func firstNAgentChanges(values []agentNodeChange, n int) []agentNodeChange {
	if len(values) <= n {
		return values
	}
	return values[:n]
}

func optionalDetail(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	return ": " + value
}

func routerSeverityKorean(severity string) string {
	switch strings.ToLower(strings.TrimSpace(severity)) {
	case "critical":
		return "긴급"
	case "high":
		return "높음"
	case "medium":
		return "주의"
	case "low":
		return "낮음"
	default:
		return firstNonEmpty(severity, "주의")
	}
}

func routerAlertKorean(alert monitor.Alert) string {
	switch strings.ToLower(strings.TrimSpace(alert.Type)) {
	case "offline":
		return "노드가 응답하지 않습니다. 전원, Tailscale 연결, vssh daemon 상태를 확인해야 합니다."
	case "disk":
		if msg := strings.TrimSpace(alert.Message); msg != "" {
			return translateCommonOpsPhrase(msg)
		}
		return "디스크 사용량이 높습니다. 큰 파일과 학습/캐시 산출물을 확인해야 합니다."
	case "memory":
		if msg := strings.TrimSpace(alert.Message); msg != "" {
			return translateCommonOpsPhrase(msg)
		}
		return "메모리 사용량이 높습니다. 상위 프로세스를 확인해야 합니다."
	default:
		if msg := strings.TrimSpace(alert.Message); msg != "" {
			return translateCommonOpsPhrase(msg)
		}
		return "운영자가 확인해야 하는 상태 변화가 있습니다."
	}
}

func routerSecurityRiskKorean(risk agentSecurityRisk) string {
	title := strings.ToLower(strings.TrimSpace(risk.Title))
	detail := strings.TrimSpace(risk.Detail)
	switch {
	case strings.Contains(title, "ssh appears public") && strings.Contains(title, "fail2ban"):
		return "SSH가 외부에 열려 있는 것으로 보이지만 fail2ban 보호가 확인되지 않습니다. 무차별 대입 공격 방어 계층을 확인해야 합니다."
	case strings.Contains(title, "failed systemd"):
		return translateUnitCount(detail) + " systemd 서비스가 실패 상태입니다. 실제 장애인지 남은 잔재 unit인지 분리해야 합니다."
	case strings.Contains(title, "system clock"):
		return "시스템 시간이 동기화되지 않았습니다. 스케줄러, 인증, 로그 타임라인이 틀어질 수 있습니다."
	case strings.Contains(title, "public listening"):
		return translateCountPrefix(detail, "공개 리스너") + " 감지됐습니다. 의도한 서비스만 외부에 열려 있는지 확인해야 합니다."
	case strings.Contains(title, "docker ports exposed"):
		return translateCountPrefix(detail, "공개 Docker 포트") + " 감지됐습니다. 컨테이너 포트 노출이 의도된 것인지 확인해야 합니다."
	case strings.Contains(title, "recent ssh authentication failures"):
		return translateCountPrefix(detail, "최근 SSH 인증 실패 로그") + " 보입니다. 반복 실패 IP와 fail2ban 적용 여부를 확인해야 합니다."
	case strings.Contains(title, "recent kernel warnings"):
		return translateCountPrefix(detail, "최근 커널 경고") + " 보입니다. 디스크, 드라이버, 네트워크 오류와 연결되는지 확인해야 합니다."
	case strings.Contains(title, "root disk above 90"):
		return "루트 디스크 사용량이 90%를 넘었습니다. 즉시 큰 파일과 캐시를 확인해야 합니다."
	case strings.Contains(title, "root disk above 80"):
		return "루트 디스크 사용량이 80%를 넘었습니다. 가까운 시일 내 정리 계획이 필요합니다."
	case strings.Contains(title, "reboot required"):
		return "재부팅이 필요한 업데이트 상태입니다. 운영 영향 시간을 정해서 처리해야 합니다."
	case strings.Contains(title, "swap usage"):
		return "swap 사용량이 높습니다. 메모리 압박이나 장기 실행 프로세스를 확인해야 합니다."
	case strings.Contains(title, "unknown high-resource process"):
		return "정체가 분명하지 않은 고자원 프로세스가 있습니다. 명령줄과 실행 사용자를 확인해야 합니다." + optionalDetail(detail)
	case strings.Contains(title, "sensitive-looking value redacted"):
		return "로그에서 민감정보처럼 보이는 값이 감지되어 가려졌습니다. 로그 보관/전송 경로를 점검해야 합니다."
	default:
		return translateCommonOpsPhrase(firstNonEmpty(risk.Title, "보안 주의 항목")) + optionalDetail(translateCommonOpsPhrase(detail))
	}
}

func routerWorkloadRiskKorean(risk agentWorkloadFleetRisk) string {
	text := strings.ToLower(strings.TrimSpace(risk.Title + " " + risk.Detail))
	switch {
	case strings.Contains(text, "ssh appears public") && strings.Contains(text, "fail2ban"):
		return "SSH가 외부에 열려 있는 것으로 보이지만 fail2ban 보호가 확인되지 않습니다. 무차별 대입 공격 방어 계층을 확인해야 합니다."
	case strings.Contains(text, "failed systemd"):
		return translateUnitCount(risk.Detail) + " systemd 서비스가 실패 상태입니다. 실제 장애인지 남은 잔재 unit인지 분리해야 합니다."
	case strings.Contains(text, "high cpu"):
		return "CPU 사용량이 높은 프로세스가 있습니다. 실제 작업인지 비정상 루프인지 확인해야 합니다." + optionalDetail(translateCommonOpsPhrase(risk.Detail))
	case strings.Contains(text, "high memory"):
		return "메모리 사용량이 높은 프로세스가 있습니다. 모델/브라우저/컨테이너 메모리 사용을 확인해야 합니다." + optionalDetail(translateCommonOpsPhrase(risk.Detail))
	default:
		return translateCommonOpsPhrase(firstNonEmpty(risk.Title, "워크로드 주의 항목")) + optionalDetail(translateCommonOpsPhrase(risk.Detail))
	}
}

func translateCommonOpsPhrase(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	replacements := []struct{ old, new string }{
		{"Disk usage high", "디스크 사용량 높음"},
		{"Memory usage high", "메모리 사용량 높음"},
		{"Node ", "노드 "},
		{" is offline", " 응답 없음"},
		{"SSH appears public and fail2ban is unavailable", "SSH가 외부에 열려 있고 fail2ban 보호가 확인되지 않음"},
		{"failed systemd units present", "실패한 systemd 서비스 있음"},
		{"system clock is not synchronized", "시스템 시간 동기화 안 됨"},
		{"public listening ports present", "공개 리스너 있음"},
		{"docker ports exposed on public interfaces", "공개 인터페이스에 Docker 포트 노출"},
		{"public listeners", "공개 리스너"},
		{"public Docker port mappings", "공개 Docker 포트 매핑"},
		{"public Docker ports", "공개 Docker 포트"},
		{"recent error lines", "최근 오류 로그"},
		{"matching log lines", "관련 로그 줄"},
		{"units", "개 unit"},
		{"packages", "개 패키지"},
		{"install/enable fail2ban or confirm another brute-force protection layer", "fail2ban을 설치/활성화하거나 다른 무차별 대입 공격 방어 계층을 확인해야 합니다"},
	}
	out := value
	for _, replacement := range replacements {
		out = strings.ReplaceAll(out, replacement.old, replacement.new)
	}
	return out
}

func translateCountPrefix(detail, label string) string {
	detail = strings.TrimSpace(detail)
	if detail == "" {
		return label
	}
	fields := strings.Fields(detail)
	if len(fields) > 0 {
		if _, err := strconv.Atoi(fields[0]); err == nil {
			return fields[0] + "개의 " + label
		}
	}
	return label + " " + translateCommonOpsPhrase(detail)
}

func translateUnitCount(detail string) string {
	detail = strings.TrimSpace(detail)
	fields := strings.Fields(detail)
	if len(fields) > 0 {
		if _, err := strconv.Atoi(fields[0]); err == nil {
			return fields[0] + "개의"
		}
	}
	return "일부"
}

func formatRouterAlertExplanation(payload map[string]interface{}, lang string) string {
	alerts, _ := payload["alerts"].([]monitor.Alert)
	states, _ := payload["states"].(map[string]*monitor.NodeState)
	if lang == "en" {
		lines := []string{
			"Alerts are MeshClaw operational warnings.",
			"",
			"They are generated from node state, agent snapshots, and policy checks. Treat them as triage signals: they do not prove an incident by themselves, but they tell you what to inspect first.",
		}
		if len(alerts) == 0 {
			lines = append(lines, "", "There are no active alerts right now.")
		} else {
			lines = append(lines, "", "What the current alerts mean:")
			for _, alert := range alerts {
				lines = append(lines, "- "+routerAlertExplanationLineEN(alert, states[alert.Node]))
			}
			lines = append(lines, "", "Recommended next step:")
			lines = append(lines, "- For offline nodes, verify power/Tailscale/vsshd before treating it as an app failure.")
			lines = append(lines, "- For disk or memory alerts, collect read-only evidence first, then plan cleanup or restart with approval.")
		}
		lines = append(lines, "", fmt.Sprintf("Current snapshot: %d nodes checked.", len(states)))
		appendRouterEvidence(&lines, payload)
		return strings.Join(lines, "\n")
	}
	lines := []string{
		"알림은 MeshClaw가 만든 운영 경고입니다.",
		"",
		"노드 상태, 에이전트 스냅샷, 정책 검사 결과를 보고 “먼저 봐야 할 것”을 표시합니다. 알림 자체가 침입이나 장애 확정은 아니고, 운영자가 어디부터 확인할지 정해주는 신호입니다.",
	}
	if len(alerts) == 0 {
		lines = append(lines, "", "현재 활성 알림은 없습니다.")
	} else {
		lines = append(lines, "", "현재 알림의 의미:")
		for _, alert := range alerts {
			lines = append(lines, "- "+routerAlertExplanationLineKO(alert, states[alert.Node]))
		}
		lines = append(lines, "", "다음 조치:")
		lines = append(lines, "- 오프라인 노드는 앱 장애로 보기 전에 전원, Tailscale, vsshd 상태를 먼저 확인합니다.")
		lines = append(lines, "- 디스크/메모리 알림은 바로 삭제하거나 재시작하지 말고 read-only evidence를 먼저 수집한 뒤 정리 계획을 세웁니다.")
	}
	lines = append(lines, "", fmt.Sprintf("현재 스냅샷: 노드 %d개를 확인했습니다.", len(states)))
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func routerAlertExplanationLineKO(alert monitor.Alert, state *monitor.NodeState) string {
	level := routerAlertLevelKO(alert.Level)
	node := firstNonEmpty(alert.Node, "unknown")
	switch alert.Type {
	case "offline":
		if state != nil && state.Error != "" {
			return fmt.Sprintf("%s: %s가 응답하지 않습니다. 의미: 이 노드는 현재 작업 대상으로 쓰면 실패할 가능성이 큽니다. 우선 확인: 전원, Tailscale 연결, vssh 데몬. 세부 오류: %s", level, node, state.Error)
		}
		return fmt.Sprintf("%s: %s가 응답하지 않습니다. 의미: 이 노드는 현재 작업 대상으로 쓰면 실패할 가능성이 큽니다. 우선 확인: 전원, Tailscale 연결, vssh 데몬.", level, node)
	case "disk":
		if state != nil {
			return fmt.Sprintf("%s: %s 디스크 사용률이 %.1f%%입니다. 의미: 로그, 모델 파일, Docker 이미지, 학습 산출물이 더 쌓이면 서비스 실패나 쓰기 오류가 날 수 있습니다. 우선 확인: `meshclaw disk-investigate %s /`.", level, node, state.Disk, node)
		}
		return fmt.Sprintf("%s: %s 디스크 사용량이 높습니다. 의미: 서비스 실패나 쓰기 오류로 이어질 수 있습니다. 우선 확인: `meshclaw disk-investigate %s /`.", level, node, node)
	case "memory":
		if state != nil {
			return fmt.Sprintf("%s: %s 메모리 사용률이 %.1f%%입니다. 의미: 모델 로딩, 브라우저, Docker 컨테이너가 밀리면서 응답 지연이나 OOM이 날 수 있습니다. 우선 확인: `meshclaw process-top %s`.", level, node, state.Memory, node)
		}
		return fmt.Sprintf("%s: %s 메모리 사용량이 높습니다. 의미: 응답 지연이나 OOM 위험이 있습니다. 우선 확인: `meshclaw process-top %s`.", level, node, node)
	default:
		return fmt.Sprintf("%s: %s %s 알림입니다. 메시지: %s. 우선 확인: 관련 evidence를 열어 원인 범위를 좁힙니다.", level, node, firstNonEmpty(alert.Type, "unknown"), firstNonEmpty(alert.Message, "no details"))
	}
}

func routerAlertExplanationLineEN(alert monitor.Alert, state *monitor.NodeState) string {
	level := routerAlertLevelEN(alert.Level)
	node := firstNonEmpty(alert.Node, "unknown")
	switch alert.Type {
	case "offline":
		if state != nil && state.Error != "" {
			return fmt.Sprintf("%s: %s is not responding. Meaning: this node is unsafe to pick for work right now. Check power, Tailscale, and vsshd first. Detail: %s", level, node, state.Error)
		}
		return fmt.Sprintf("%s: %s is not responding. Meaning: this node is unsafe to pick for work right now. Check power, Tailscale, and vsshd first.", level, node)
	case "disk":
		if state != nil {
			return fmt.Sprintf("%s: %s disk usage is %.1f%%. Meaning: logs, model files, Docker images, or training artifacts may soon cause write failures. First check: `meshclaw disk-investigate %s /`.", level, node, state.Disk, node)
		}
		return fmt.Sprintf("%s: %s disk usage is high. Meaning: it may lead to service or write failures. First check: `meshclaw disk-investigate %s /`.", level, node, node)
	case "memory":
		if state != nil {
			return fmt.Sprintf("%s: %s memory usage is %.1f%%. Meaning: model loads, browsers, or containers may cause latency or OOM. First check: `meshclaw process-top %s`.", level, node, state.Memory, node)
		}
		return fmt.Sprintf("%s: %s memory usage is high. Meaning: latency or OOM risk. First check: `meshclaw process-top %s`.", level, node, node)
	default:
		return fmt.Sprintf("%s: %s has a %s alert. Message: %s. First check: open the related evidence and narrow the cause.", level, node, firstNonEmpty(alert.Type, "unknown"), firstNonEmpty(alert.Message, "no details"))
	}
}

func routerAlertLevelKO(level string) string {
	switch strings.ToLower(strings.TrimSpace(level)) {
	case "critical":
		return "긴급"
	case "warning":
		return "주의"
	case "info":
		return "정보"
	default:
		return firstNonEmpty(level, "알림")
	}
}

func routerAlertLevelEN(level string) string {
	switch strings.ToLower(strings.TrimSpace(level)) {
	case "critical":
		return "Critical"
	case "warning":
		return "Warning"
	case "info":
		return "Info"
	default:
		return firstNonEmpty(level, "Alert")
	}
}

func appendRouterAgentRefreshDigest(lines *[]string, payload map[string]interface{}, lang string) {
	refresh, ok := payload["agent_refresh"].(agentPullReport)
	if !ok {
		return
	}
	if len(refresh.Hosts) == 0 && refresh.OK == 0 && refresh.Failed == 0 && refresh.Error == "" {
		return
	}
	if lang == "en" {
		*lines = append(*lines, "", fmt.Sprintf("Fresh collection: %d ok, %d failed", refresh.OK, refresh.Failed))
	} else {
		*lines = append(*lines, "", fmt.Sprintf("최신 수집: 성공 %d개, 실패 %d개", refresh.OK, refresh.Failed))
	}
	if refresh.Error != "" {
		if lang == "en" {
			*lines = append(*lines, "- collection warning: "+refresh.Error)
		} else {
			*lines = append(*lines, "- 수집 경고: "+refresh.Error)
		}
	}
	failedShown := 0
	for _, host := range refresh.Hosts {
		if host.OK || host.Error == "" {
			continue
		}
		if failedShown >= 4 {
			break
		}
		if lang == "en" {
			*lines = append(*lines, fmt.Sprintf("- %s refresh failed: %s", host.Host, compactErrorText(host.Error, 120)))
		} else {
			*lines = append(*lines, fmt.Sprintf("- %s 최신 수집 실패: %s", host.Host, compactErrorText(host.Error, 120)))
		}
		failedShown++
	}
}

func appendRouterChangeDigest(lines *[]string, payload map[string]interface{}, target, lang string) {
	changes, ok := payload["changes"].(agentChangesReport)
	if !ok {
		return
	}
	if len(changes.Nodes) == 0 {
		if lang == "en" {
			*lines = append(*lines, "", "Recent changes: no comparable previous snapshot yet.")
		} else {
			*lines = append(*lines, "", "최근 변화: 비교할 이전 스냅샷이 아직 없거나 변화가 없습니다.")
		}
		return
	}
	if lang == "en" {
		*lines = append(*lines, "", "Recent changes:")
	} else {
		*lines = append(*lines, "", "최근 변화:")
	}
	shown := 0
	for _, change := range changes.Nodes {
		if strings.TrimSpace(target) != "" && !strings.EqualFold(change.Node, target) {
			continue
		}
		if shown >= 5 {
			break
		}
		summary := strings.TrimSpace(change.Summary)
		if summary == "" {
			summary = fmt.Sprintf("load %.2f, memory %.1f%%p, disk %.1f%%p", change.Load1Delta, change.MemoryPctDelta, change.DiskPctDelta)
		}
		*lines = append(*lines, fmt.Sprintf("- %s: %s", change.Node, translateAgentChangeSummary(summary, lang)))
		if len(change.AddedWorkloads) > 0 {
			if lang == "en" {
				*lines = append(*lines, "  added workloads: "+strings.Join(firstN(change.AddedWorkloads, 3), ", "))
			} else {
				*lines = append(*lines, "  새 역할: "+strings.Join(translateWorkloadIDsKO(firstN(change.AddedWorkloads, 3)), ", "))
			}
		}
		if len(change.NewSecurityFindings) > 0 {
			if lang == "en" {
				*lines = append(*lines, "  new risks: "+strings.Join(firstN(change.NewSecurityFindings, 3), " / "))
			} else {
				*lines = append(*lines, "  새 보안 주의: "+strings.Join(firstN(change.NewSecurityFindings, 3), " / "))
			}
		}
		shown++
	}
}

func formatRouterChangeOnlyReport(plan router.Plan, payload map[string]interface{}, lang string) string {
	changes, _ := payload["changes"].(agentChangesReport)
	workloads, _ := payload["workloads"].(agentWorkloadsReport)
	target := strings.TrimSpace(plan.Target)
	var lines []string
	if lang == "en" {
		lines = append(lines, "Recent fleet changes from stored agent snapshots.", "")
	} else {
		lines = append(lines, "최근 서버 변화 요약입니다.", "")
	}
	comparable := 0
	material := make([]agentNodeChange, 0)
	stable := make([]string, 0)
	for _, change := range changes.Nodes {
		if target != "" && !strings.EqualFold(change.Node, target) {
			continue
		}
		comparable++
		if isMaterialAgentChange(change) {
			material = append(material, change)
		} else if len(stable) < 6 {
			stable = append(stable, change.Node)
		}
	}
	if lang == "en" {
		lines = append(lines, fmt.Sprintf("Comparable nodes: %d. Material changes: %d.", comparable, len(material)))
	} else {
		lines = append(lines, fmt.Sprintf("비교 가능한 노드: %d개. 의미 있는 변화: %d개.", comparable, len(material)))
	}
	if len(material) > 0 {
		if lang == "en" {
			lines = append(lines, "", "Important changes:")
		} else {
			lines = append(lines, "", "중요 변화:")
		}
		for _, change := range firstNAgentChanges(material, 8) {
			summary := translateAgentChangeSummary(firstNonEmpty(change.Summary, fallbackAgentChangeSummary(change)), lang)
			lines = append(lines, fmt.Sprintf("- %s: %s", change.Node, summary))
			if len(change.AddedWorkloads) > 0 {
				if lang == "en" {
					lines = append(lines, "  added workloads: "+strings.Join(firstN(change.AddedWorkloads, 3), ", "))
				} else {
					lines = append(lines, "  새 역할: "+strings.Join(translateWorkloadIDsKO(firstN(change.AddedWorkloads, 3)), ", "))
				}
			}
			if len(change.NewSecurityFindings) > 0 {
				if lang == "en" {
					lines = append(lines, "  new risks: "+strings.Join(firstN(change.NewSecurityFindings, 2), " / "))
				} else {
					lines = append(lines, "  새 보안 주의: "+strings.Join(firstN(change.NewSecurityFindings, 2), " / "))
				}
			}
		}
	} else if lang == "en" {
		lines = append(lines, "", "No material workload, risk, disk, memory, or load changes were found.")
	} else {
		lines = append(lines, "", "워크로드, 보안 주의, 디스크, 메모리, 부하에서 큰 변화는 보이지 않습니다.")
	}
	if len(stable) > 0 {
		if lang == "en" {
			lines = append(lines, "", "Stable or minor-only nodes: "+strings.Join(stable, ", "))
		} else {
			lines = append(lines, "", "큰 변화 없는 노드: "+strings.Join(stable, ", "))
		}
	}
	if len(workloads.NextActions) > 0 {
		if lang == "en" {
			lines = append(lines, "", "Suggested checks:")
		} else {
			lines = append(lines, "", "바로 확인할 것:")
		}
		for _, action := range firstN(workloads.NextActions, 4) {
			if lang == "en" {
				lines = append(lines, "- "+action)
			} else {
				lines = append(lines, "- "+translateAgentNextAction(action))
			}
		}
	}
	if errText, _ := payload["changes_error"].(string); errText != "" {
		lines = append(lines, "", "changes_error: "+compactErrorText(errText, 160))
	}
	if errText, _ := payload["workload_error"].(string); errText != "" {
		lines = append(lines, "", "workload_error: "+compactErrorText(errText, 160))
	}
	appendRouterEvidence(&lines, payload)
	return strings.Join(lines, "\n")
}

func isMaterialAgentChange(change agentNodeChange) bool {
	if len(change.AddedWorkloads) > 0 || len(change.RemovedWorkloads) > 0 || len(change.NewSecurityFindings) > 0 || len(change.ClearedSecurityFindings) > 0 {
		return true
	}
	if absFloat64(change.Load1Delta) >= 1.0 || absFloat64(change.MemoryPctDelta) >= 5.0 || absFloat64(change.DiskPctDelta) >= 3.0 {
		return true
	}
	return false
}

func fallbackAgentChangeSummary(change agentNodeChange) string {
	return fmt.Sprintf("load %.1f, memory %.1f%%p, disk %.1f%%p", change.Load1Delta, change.MemoryPctDelta, change.DiskPctDelta)
}

func absFloat64(value float64) float64 {
	if value < 0 {
		return -value
	}
	return value
}

func compactErrorText(value string, limit int) string {
	value = strings.Join(strings.Fields(value), " ")
	if limit > 0 && len(value) > limit {
		return value[:limit] + "..."
	}
	return value
}

