func argosPermissionLegacyAction(action string) bool {
	switch strings.TrimSpace(action) {
	case "macbook_command", "device_runner_command":
		return true
	default:
		return false
	}
}

func hasLegacyArgosPermission(grants []osauto.ArgosPermissionGrant) bool {
	for _, grant := range grants {
		if argosPermissionLegacyAction(grant.Action) {
			return true
		}
	}
	return false
}

func argosRunnersCommand(args []string, jsonOut bool) error {
	if len(args) == 0 {
		return fmt.Errorf("usage: meshclaw argos runners <list|add|remove|select|doctor> [--json]")
	}
	switch args[0] {
	case "list", "ls":
		if len(args) != 1 {
			return fmt.Errorf("usage: meshclaw argos runners list [--json]")
		}
		store, err := osauto.ListMacRunners()
		if err != nil {
			return err
		}
		if jsonOut {
			return printJSON(store)
		}
		fmt.Println(formatMacRunnersDisplay(store))
		return nil
	case "add", "set", "upsert":
		runner, err := parseMacRunnerAdd(args[1:])
		if err != nil {
			return err
		}
		store, saved, err := osauto.UpsertMacRunner(runner)
		record, storeErr := evidence.Store("mac-runner-upsert", saved.ID, saved.SSHTarget, saved)
		if jsonOut {
			return printJSON(map[string]interface{}{"runner": saved, "store": store, "evidence": record, "store_error": errString(storeErr), "error": errString(err)})
		}
		if err != nil {
			return err
		}
		fmt.Printf("mac_runner=%s enabled=%t selected=%t ssh=%s\n", saved.ID, saved.Enabled, saved.Selected, saved.SSHTarget)
		printEvidenceStoreStatus(record, storeErr)
		return nil
	case "remove", "rm", "delete":
		if len(args) != 2 {
			return fmt.Errorf("usage: meshclaw argos runners remove <id> [--json]")
		}
		store, removed, err := osauto.RemoveMacRunner(args[1])
		record, storeErr := evidence.Store("mac-runner-remove", args[1], fmt.Sprintf("removed=%t", removed), map[string]interface{}{"id": args[1], "removed": removed, "path": store.Path})
		if jsonOut {
			return printJSON(map[string]interface{}{"store": store, "removed": removed, "evidence": record, "store_error": errString(storeErr), "error": errString(err)})
		}
		if err != nil {
			return err
		}
		fmt.Printf("mac_runner_removed=%t id=%s\n", removed, args[1])
		printEvidenceStoreStatus(record, storeErr)
		return nil
	case "select", "use":
		if len(args) != 2 {
			return fmt.Errorf("usage: meshclaw argos runners select <id> [--json]")
		}
		store, selected, err := osauto.SelectMacRunner(args[1])
		record, storeErr := evidence.Store("mac-runner-select", args[1], selected.SSHTarget, selected)
		if jsonOut {
			return printJSON(map[string]interface{}{"runner": selected, "store": store, "evidence": record, "store_error": errString(storeErr), "error": errString(err)})
		}
		if err != nil {
			return err
		}
		fmt.Printf("mac_runner_selected=%s ssh=%s\n", selected.ID, selected.SSHTarget)
		printEvidenceStoreStatus(record, storeErr)
		return nil
	case "doctor", "check":
		if len(args) > 2 {
			return fmt.Errorf("usage: meshclaw argos runners doctor [id] [--json]")
		}
		id := ""
		if len(args) == 2 {
			id = args[1]
		}
		report := osauto.DoctorMacRunner(context.Background(), id)
		target := firstNonEmpty(report.Runner.ID, id, "selected")
		record, storeErr := evidence.Store("mac-runner-doctor", target, fmt.Sprintf("ok=%t", report.OK), report)
		if jsonOut {
			return printJSON(map[string]interface{}{"report": report, "evidence": record, "store_error": errString(storeErr)})
		}
		fmt.Println(formatMacRunnerDoctorDisplay(report))
		printEvidenceStoreStatus(record, storeErr)
		if !report.OK {
			return fmt.Errorf("mac runner doctor failed")
		}
		return nil
	default:
		return fmt.Errorf("usage: meshclaw argos runners <list|add|remove|select|doctor> [--json]")
	}
}

func parseMacRunnerAdd(args []string) (osauto.MacRunner, error) {
	if len(args) == 0 {
		return osauto.MacRunner{}, fmt.Errorf("usage: meshclaw argos runners add <id> --ssh user@host [--name text] [--project path] [--python python] [--url url] [--capability name] [--disabled] [--select] [--json]")
	}
	runner := osauto.MacRunner{ID: args[0], Enabled: true}
	for i := 1; i < len(args); i++ {
		switch args[i] {
		case "--name", "--label":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("%s requires a value", args[i-1])
			}
			runner.Name = args[i]
		case "--ssh", "--ssh-target":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("%s requires a value", args[i-1])
			}
			runner.SSHTarget = args[i]
		case "--project":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("--project requires a value")
			}
			runner.Project = args[i]
		case "--python":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("--python requires a value")
			}
			runner.Python = args[i]
		case "--url":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("--url requires a value")
			}
			runner.URL = args[i]
		case "--capability", "--cap":
			i++
			if i >= len(args) {
				return runner, fmt.Errorf("%s requires a value", args[i-1])
			}
			runner.Capabilities = append(runner.Capabilities, splitCSV(args[i])...)
		case "--disabled":
			runner.Enabled = false
		case "--enabled":
			runner.Enabled = true
		case "--select", "--selected":
			runner.Selected = true
		default:
			return runner, fmt.Errorf("unknown mac runner option: %s", args[i])
		}
	}
	return runner, nil
}

func argosSignalImagesDoctor() map[string]interface{} {
	home, _ := os.UserHomeDir()
	dir := filepath.Join(home, ".meshclaw", "signal-attachments")
	vision := argosSignalVisionBackendDoctor()
	result := map[string]interface{}{
		"kind":           "meshclaw_argos_signal_images_doctor",
		"ok":             true,
		"attachment_dir": dir,
		"swift":          "/usr/bin/swift",
		"ocr":            "macos_vision",
		"vision":         vision,
	}
	problems := []string{}
	next := []string{}
	if goruntime.GOOS != "darwin" {
		problems = append(problems, "Signal 이미지 OCR은 현재 macOS Vision 기반입니다. 현재 OS: "+goruntime.GOOS)
		next = append(next, "macOS에서 dispatcher를 실행하거나 별도 OCR backend를 설정하세요.")
	}
	if err := os.MkdirAll(dir, 0700); err != nil {
		problems = append(problems, "Signal 첨부 저장 디렉터리를 만들 수 없습니다: "+err.Error())
		next = append(next, dir+"의 상위 디렉터리 권한을 확인하세요.")
	} else {
		probe := filepath.Join(dir, ".doctor-write-test")
		if err := os.WriteFile(probe, []byte("ok"), 0600); err != nil {
			problems = append(problems, "Signal 첨부 저장 디렉터리에 쓸 수 없습니다: "+err.Error())
			next = append(next, dir+"의 소유자와 권한을 확인하세요.")
		} else {
			_ = os.Remove(probe)
			result["attachment_dir_writable"] = true
		}
	}
	if st, err := os.Stat("/usr/bin/swift"); err != nil || st.IsDir() {
		if err != nil {
			problems = append(problems, "Swift 런타임을 찾을 수 없습니다: "+err.Error())
		} else {
			problems = append(problems, "/usr/bin/swift가 실행 파일이 아닙니다.")
		}
		next = append(next, "Xcode Command Line Tools 또는 macOS 기본 Swift 런타임을 확인하세요.")
	} else {
		result["swift_available"] = true
	}
	script := filepath.Join(dir, "bin", "argos-vision-ocr.swift")
	if fileNonEmpty(script) {
		result["ocr_script"] = script
		result["ocr_script_ready"] = true
	} else {
		result["ocr_script_ready"] = false
		next = append(next, "첫 이미지 첨부를 받으면 OCR 스크립트가 자동 생성됩니다.")
	}
	if !vision.OK {
		problems = append(problems, vision.Problem)
		next = append(next, vision.NextAction)
	}
	if len(problems) > 0 {
		result["ok"] = false
		result["problems"] = problems
	}
	if len(next) > 0 {
		result["next_actions"] = next
	}
	return result
}

type argosSignalVisionBackendReport struct {
	Kind       string `json:"kind"`
	OK         bool   `json:"ok"`
	Configured bool   `json:"configured"`
	Source     string `json:"source,omitempty"`
	Model      string `json:"model,omitempty"`
	BaseURL    string `json:"base_url,omitempty"`
	Endpoint   string `json:"endpoint,omitempty"`
	Reachable  bool   `json:"reachable"`
	Status     string `json:"status,omitempty"`
	Problem    string `json:"problem,omitempty"`
	NextAction string `json:"next_action,omitempty"`
}

func argosSignalVisionBackendDoctor() argosSignalVisionBackendReport {
	report := argosSignalVisionBackendReport{Kind: "meshclaw_argos_signal_vision_backend"}
	model := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_MODEL"))
	baseURL := strings.TrimRight(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_BASE_URL")), "/")
	apiKey := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_API_KEY"))
	source := "environment"
	if model == "" {
		model = signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_MODEL")
		if model != "" {
			source = "signal-dispatcher-plist"
		}
	}
	if baseURL == "" {
		baseURL = strings.TrimRight(signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_BASE_URL"), "/")
		if baseURL != "" {
			source = "signal-dispatcher-plist"
		}
	}
	if apiKey == "" {
		apiKey = signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_API_KEY")
	}
	if baseURL == "" {
		if cfg, _, err := aichat.LoadConfig(); err == nil {
			baseURL = strings.TrimRight(strings.TrimSpace(cfg.BaseURL), "/")
			if apiKey == "" {
				apiKey = strings.TrimSpace(cfg.APIKey)
			}
			source = "aichat-config"
		}
	}
	if baseURL == "" {
		baseURL = strings.TrimRight(strings.TrimSpace(aichat.DefaultConfig().BaseURL), "/")
		if apiKey == "" {
			apiKey = strings.TrimSpace(aichat.DefaultConfig().APIKey)
		}
		source = "default"
	}
	report.Model = model
	report.BaseURL = baseURL
	report.Source = source
	report.Configured = model != "" && baseURL != ""
	if !report.Configured {
		report.Problem = "Signal 이미지 설명용 비전 모델이 설정되지 않아 OCR fallback만 사용할 수 있습니다."
		report.NextAction = "MESHCLAW_SIGNAL_VISION_MODEL과 MESHCLAW_SIGNAL_VISION_BASE_URL을 설정한 뒤 signal-dispatcher를 재설치/재시작하세요."
		return report
	}
	endpoint := strings.TrimRight(baseURL, "/") + "/models"
	report.Endpoint = endpoint
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, endpoint, nil)
	if err != nil {
		report.Problem = "비전 모델 endpoint 요청을 만들 수 없습니다: " + err.Error()
		report.NextAction = "MESHCLAW_SIGNAL_VISION_BASE_URL 값을 확인하세요."
		return report
	}
	if apiKey != "" {
		req.Header.Set("Authorization", "Bearer "+apiKey)
	}
	resp, err := (&http.Client{Timeout: 3 * time.Second}).Do(req)
	if err != nil {
		report.Problem = "비전 모델 endpoint에 연결할 수 없습니다: " + err.Error()
		report.NextAction = "모델 서버가 켜져 있고 signal-dispatcher Mac에서 base_url에 접근 가능한지 확인하세요."
		return report
	}
	defer resp.Body.Close()
	report.Status = resp.Status
	report.Reachable = resp.StatusCode >= 200 && resp.StatusCode < 300
	report.OK = report.Reachable
	if !report.OK {
		report.Problem = "비전 모델 endpoint가 정상 응답하지 않습니다: " + resp.Status
		report.NextAction = "OpenAI-compatible /models endpoint와 API key 설정을 확인하세요."
	}
	return report
}

func signalDispatcherPlistEnvValue(key string) string {
	key = strings.TrimSpace(key)
	if key == "" {
		return ""
	}
	path := defaultSignalDispatcherOptions().PlistPath
	data, err := os.ReadFile(path)
	if err != nil {
		return ""
	}
	text := string(data)
	marker := "<key>" + xmlEscape(key) + "</key>"
	idx := strings.Index(text, marker)
	if idx < 0 {
		return ""
	}
	rest := text[idx+len(marker):]
	start := strings.Index(rest, "<string>")
	if start < 0 {
		return ""
	}
	rest = rest[start+len("<string>"):]
	end := strings.Index(rest, "</string>")
	if end < 0 {
		return ""
	}
	return strings.TrimSpace(xmlUnescape(rest[:end]))
}

func xmlUnescape(value string) string {
	replacer := strings.NewReplacer("&apos;", "'", "&quot;", `"`, "&gt;", ">", "&lt;", "<", "&amp;", "&")
	return replacer.Replace(value)
}

func fileNonEmpty(path string) bool {
	st, err := os.Stat(path)
	return err == nil && !st.IsDir() && st.Size() > 0
}

func argosSignalAttachments(action osauto.ArgosAction) []string {
	attachments := []string{}
	if action.RecordingPath != "" && fileNonEmpty(action.RecordingPath) {
		attachments = append(attachments, signalFriendlyVideo(action.RecordingPath))
	}
	if action.OutputPath != "" && fileNonEmpty(action.OutputPath) {
		if shouldAttachArgosSourceDocument(action) {
			attachments = append(attachments, action.OutputPath)
		}
		if action.Result != nil && action.Result.Preview != "" && fileNonEmpty(action.Result.Preview) {
			attachments = append(attachments, action.Result.Preview)
		}
		if action.Result != nil && action.Result.PDF != "" && fileNonEmpty(action.Result.PDF) {
			attachments = append(attachments, action.Result.PDF)
		}
		if action.Result != nil && action.Result.DOCX != "" && fileNonEmpty(action.Result.DOCX) {
			attachments = append(attachments, action.Result.DOCX)
		}
		if action.Result != nil && action.Result.Markdown != "" && fileNonEmpty(action.Result.Markdown) {
			attachments = append(attachments, action.Result.Markdown)
		}
		if preview := signalDocumentPreviewImage(action.OutputPath); preview != "" {
			attachments = append(attachments, preview)
		}
		if attachRawArgosDocuments() || action.Action == "mac_runner_command" {
			attachments = append(attachments, action.OutputPath)
			if preview := signalReadableDocument(action.OutputPath); preview != "" {
				attachments = append(attachments, preview)
			}
		}
	}
	return uniqueStrings(attachments)
}

func shouldAttachArgosSourceDocument(action osauto.ArgosAction) bool {
	ext := strings.ToLower(filepath.Ext(action.OutputPath))
	if ext != ".md" && ext != ".markdown" && ext != ".txt" {
		return false
	}
	switch action.Action {
	case "browser_search", "visible_browser_search", "browser_fetch", "work_demo", "document_create":
		return true
	default:
		return false
	}
}

func signalFriendlyVideo(path string) string {
	ext := strings.ToLower(filepath.Ext(path))
	if ext == ".m4v" || ext == ".mp4" {
		return path
	}
	out := strings.TrimSuffix(path, filepath.Ext(path)) + ".m4v"
	if fileNonEmpty(out) {
		return out
	}
	cmd := exec.Command("avconvert", "--source", path, "--preset", "PresetAppleM4V720pHD", "--output", out, "--replace")
	if err := cmd.Run(); err == nil && fileNonEmpty(out) {
		return out
	}
	return path
}

func signalReadableDocument(path string) string {
	preview := strings.TrimSuffix(path, filepath.Ext(path)) + ".html"
	if fileNonEmpty(preview) {
		return preview
	}
	return ""
}

func signalDocumentPreviewImage(path string) string {
	return publish.DocumentPreviewImage(path)
}

func signalDocumentLink(path string) string {
	links := signalDocumentLinks(path)
	if len(links) == 0 {
		return ""
	}
	return links[0]
}

func signalDocumentLinks(path string) []string {
	return publish.DocumentLinks(path)
}

func attachRawArgosDocuments() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ARGOS_ATTACH_RAW_DOCS")))
	return value == "1" || value == "true" || value == "yes"
}

func cleanupArgosRecordingAttachments(paths []string) {
	if keepArgosRecordings() {
		return
	}
	for _, path := range paths {
		if isArgosRecordingPath(path) {
			_ = os.Remove(path)
		}
	}
}

func keepArgosRecordings() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ARGOS_KEEP_RECORDINGS")))
	return value == "1" || value == "true" || value == "yes"
}

func isArgosRecordingPath(path string) bool {
	path = strings.TrimSpace(path)
	if path == "" {
		return false
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return false
	}
	root := filepath.Join(home, ".meshclaw", "recordings")
	abs, err := filepath.Abs(path)
	if err != nil {
		return false
	}
	rootAbs, err := filepath.Abs(root)
	if err != nil {
		return false
	}
	rel, err := filepath.Rel(rootAbs, abs)
	if err != nil {
		return false
	}
	return rel != "." && rel != ".." && !strings.HasPrefix(rel, ".."+string(os.PathSeparator))
}

func formatArgosActionForMessenger(action osauto.ArgosAction) string {
	lines := []string{fmt.Sprintf("Argos/MeshClaw 작업 보고: %s", action.Action)}
	if action.App != "" {
		lines = append(lines, "앱: "+action.App)
	}
	if action.URL != "" {
		lines = append(lines, "URL: "+action.URL)
	}
	if action.Query != "" {
		lines = append(lines, "검색: "+action.Query)
	}
	if action.OutputPath != "" {
		lines = append(lines, "작업 문서: "+action.OutputPath)
		if link := signalDocumentLink(action.OutputPath); link != "" {
			if strings.EqualFold(filepath.Ext(action.OutputPath), ".pages") {
				lines = append(lines, "Pages 편집 링크: "+link)
			} else {
				lines = append(lines, "iPhone 문서 링크: "+link)
			}
		}
		if action.Result != nil && action.Result.Preview != "" {
			lines = append(lines, "문서 미리보기 이미지: "+action.Result.Preview)
			lines = append(lines, "사진 증거를 같이 보냈습니다.")
		}
		if action.Result != nil && action.Result.PDF != "" {
			lines = append(lines, "PDF 문서: "+action.Result.PDF)
			if link := signalDocumentLink(action.Result.PDF); link != "" {
				lines = append(lines, "PDF 보기 링크: "+link)
			}
		}
		if action.Result != nil && action.Result.DOCX != "" {
			lines = append(lines, "Pages/Word 편집용 문서: "+action.Result.DOCX)
			if link := signalDocumentLink(action.Result.DOCX); link != "" {
				lines = append(lines, "Pages/Word 편집 링크: "+link)
			}
		}
		if action.Result != nil && action.Result.Markdown != "" {
			lines = append(lines, "Obsidian 편집 문서: "+action.Result.Markdown)
			if link := signalDocumentLink(action.Result.Markdown); link != "" {
				lines = append(lines, "Obsidian 편집 링크: "+link)
			}
		}
		if preview := signalDocumentPreviewImage(action.OutputPath); preview != "" {
			lines = append(lines, "문서 미리보기 이미지: "+preview)
		}
	}
	if action.NoteTitle != "" {
		lines = append(lines, "메모: "+action.NoteTitle)
	}
	if action.Provider != "" {
		lines = append(lines, "프론트엔드: "+action.Provider)
	}
	if action.RecordingPath != "" && fileNonEmpty(action.RecordingPath) {
		lines = append(lines, "작업 녹화 첨부됨.")
	} else if action.RecordingPath != "" {
		lines = append(lines, "작업 녹화는 시도했지만 파일이 생성되지 않았습니다. macOS Screen Recording 권한을 확인해야 합니다.")
	}
	if action.Error != "" {
		lines = append(lines, "오류: "+action.Error)
	}
	for _, next := range action.NextActions {
		lines = append(lines, "다음 조치: "+next)
	}
	return strings.Join(lines, "\n")
}

func printArgosAction(action osauto.ArgosAction) {
	status := "planned"
	if action.Executed {
		status = "executed"
	}
	fmt.Printf("argos action=%s status=%s\n", action.Action, status)
	if action.Query != "" {
		fmt.Printf("query: %s\n", action.Query)
	}
	if action.OutputPath != "" {
		fmt.Printf("output: %s\n", action.OutputPath)
	}
	if action.URL != "" {
		fmt.Printf("url: %s\n", action.URL)
	}
	if action.App != "" {
		fmt.Printf("app: %s\n", action.App)
	}
	if action.Shortcut != "" {
		fmt.Printf("shortcut: %s\n", action.Shortcut)
	}
	if action.Provider != "" {
		fmt.Printf("provider: %s\n", action.Provider)
	}
	if action.NoteTitle != "" {
		fmt.Printf("note: %s\n", action.NoteTitle)
	}
	if action.Search != nil {
		for i, item := range action.Search.Results {
			fmt.Printf("%d. %s\n   %s\n", i+1, item.Text, item.URL)
		}
	}
	if action.Page != nil {
		fmt.Printf("title: %s\n", action.Page.Title)
		if action.Page.Text != "" {
			fmt.Println(truncateForCLI(action.Page.Text, 1200))
		}
	}
	if action.Result != nil {
		fmt.Println(browserauto.JSON(action.Result))
	}
	if action.RecordingPath != "" {
		fmt.Printf("recording: %s\n", action.RecordingPath)
	}
	if action.Recording != nil && action.Recording.Error != "" {
		fmt.Printf("recording_error: %s\n", action.Recording.Error)
	}
	for _, next := range action.NextActions {
		fmt.Printf("next: %s\n", next)
	}
}

func truncateForCLI(value string, limit int) string {
	runes := []rune(value)
	if len(runes) <= limit {
		return value
	}
	return strings.TrimSpace(string(runes[:limit])) + "..."
}

func assistantWatchCommand(args []string) error {
	jsonOut := wantsJSON(args)
	filtered := withoutJSONFlag(args)
	if len(filtered) == 0 {
		return fmt.Errorf("usage: meshclaw assistant-watch <list|check|disable> ...")
	}
	switch filtered[0] {
	case "list":
		includeDisabled := hasFlag(filtered[1:], "--all")
		for _, arg := range filtered[1:] {
			if arg != "--all" {
				return fmt.Errorf("unknown assistant-watch list option: %s", arg)
			}
		}
		watches, err := assistantwatch.ListWatches("price_alert", includeDisabled)
		if jsonOut {
			return printJSON(map[string]interface{}{"watches": watches, "error": errString(err)})
		}
		if err != nil {
			return err
		}
		if len(watches) == 0 {
			fmt.Println("assistant_watch count=0")
			return nil
		}
		fmt.Printf("assistant_watch count=%d\n", len(watches))
		for _, watch := range watches {
			fmt.Printf("- %s enabled=%t status=%s query=%s threshold=%s cadence=%s url=%s\n",
				watch.ID, watch.Enabled, watch.Status, watch.Query, firstNonEmpty(watch.ThresholdText, strconv.Itoa(watch.ThresholdAmount)), watch.Cadence, watch.URL)
		}
		return nil
	case "check":
		for _, arg := range filtered[1:] {
			return fmt.Errorf("unknown assistant-watch check option: %s", arg)
		}
		ctx, cancel := context.WithTimeout(context.Background(), 90*time.Second)
		defer cancel()
		result, err := assistantwatch.CheckDue(ctx, time.Now().UTC())
		if jsonOut {
			return printJSON(map[string]interface{}{"result": result, "error": errString(err)})
		}
		if err != nil {
			return err
		}
		fmt.Printf("assistant_watch_check total=%d due=%d matched=%d links=%d\n", result.Total, len(result.Due), len(result.Matched), len(result.Links))
		for _, observation := range result.Observations {
			fmt.Printf("- %s found=%d threshold=%d matched=%t url=%s error=%s\n",
				observation.Query, observation.FoundAmount, observation.ThresholdAmount, observation.Matched, observation.URL, observation.Error)
		}
		return nil
	case "disable", "remove", "delete":
		if len(filtered) < 2 {
			return fmt.Errorf("usage: meshclaw assistant-watch disable <query-or-id> [--json]")
		}
		query := strings.Join(filtered[1:], " ")
		watch, ok, err := assistantwatch.DisableWatch(query, time.Now().UTC())
		if jsonOut {
			return printJSON(map[string]interface{}{"watch": watch, "disabled": ok, "error": errString(err)})
		}
		if err != nil {
			return err
		}
		if !ok {
			fmt.Printf("assistant_watch disabled=false query=%s\n", query)
			return nil
		}
		fmt.Printf("assistant_watch disabled=true id=%s query=%s\n", watch.ID, watch.Query)
		return nil
	default:
		return fmt.Errorf("usage: meshclaw assistant-watch <list|check|disable> ...")
	}
}

func scheduleCommand(args []string) error {
	jsonOut := wantsJSON(args)
	filtered := withoutJSONFlag(args)
	if len(filtered) == 0 {
		return fmt.Errorf("usage: meshclaw schedule <plan|run-once|run-due> ...")
	}
	switch filtered[0] {
	case "plan", "list":
		plan := scheduler.DefaultPlan()
		if jsonOut {
			return printJSON(plan)
		}
		fmt.Printf("schedule controller=%s jobs=%d\n", plan.Controller, len(plan.Jobs))
		for _, job := range plan.Jobs {
			when := job.Interval
			if when == "" {
				when = "daily@" + job.DailyAt
			}
			fmt.Printf("- %s mode=%s kind=%s when=%s target=%s enabled=%t\n  %s\n",
				job.ID, job.Mode, job.Kind, when, job.TargetID, job.Enabled, job.Description)
		}
		return nil
	case "status":
		plan := scheduler.DefaultPlan()
		state, err := scheduler.LoadState()
		if jsonOut {
			return printJSON(scheduleStatusPayload(plan, state, err, time.Now().UTC()))
		}
		if err != nil {
			return err
		}
		now := time.Now().UTC()
		status := scheduleStatusPayload(plan, state, nil, now)
		fmt.Println(formatScheduleStatusSummary(state.Path, len(plan.Jobs), status))
		for _, job := range plan.Jobs {
			due := scheduler.Due(job, state, now)
			fmt.Printf("- %s due=%t last_run=%s next_due=%s when=%s target=%s\n", job.ID, due, formatScheduleLastRun(state.LastRun[job.ID]), formatScheduleNextDue(scheduler.NextDue(job, state, now), due), formatScheduleWhen(job), job.TargetID)
		}
		return nil
	case "run-once":
		if len(filtered) < 2 {
			return fmt.Errorf("usage: meshclaw schedule run-once <job-id> [--target messenger-target] [--dry-run|--execute] [--json]")
		}
		opts, err := parseScheduleRunOptions(filtered[2:])
		if err != nil {
			return err
		}
		opts.JobID = filtered[1]
		ctx, cancel := context.WithTimeout(context.Background(), 90*time.Second)
		defer cancel()
		result, err := scheduler.RunOnce(ctx, opts)
		if jsonOut {
			return printJSON(map[string]interface{}{"result": result, "error": errString(err)})
		}
		printScheduleRunResult(result)
		return err
	case "run-due":
		opts, err := parseScheduleRunOptions(filtered[1:])
		if err != nil {
			return err
		}
		ctx, cancel := context.WithTimeout(context.Background(), 180*time.Second)
		defer cancel()
		results, err := scheduler.RunDue(ctx, opts)
		if jsonOut {
			return printJSON(map[string]interface{}{"results": results, "error": errString(err)})
		}
		for _, result := range results {
			printScheduleRunResult(result)
		}
		return err
	default:
		return fmt.Errorf("usage: meshclaw schedule <plan|run-once|run-due> ...")
	}
}

func formatScheduleStatusSummary(statePath string, jobCount int, status map[string]interface{}) string {
	statusText, _ := status["status"].(string)
	if statusText == "" {
		statusText = "unknown"
	}
	dueCount, _ := status["due_count"].(int)
	dueJobs, _ := status["due_jobs"].([]string)
	nextDueJob, _ := status["next_due_job"].(string)
	nextDueInSeconds, _ := status["next_due_in_seconds"].(int64)
	dueSuffix := ""
	if len(dueJobs) > 0 {
		dueSuffix = " due_jobs=" + strings.Join(dueJobs, ",")
	}
	if nextDueJob == "" {
		return fmt.Sprintf("schedule_state=%s status=%s jobs=%d due=%d%s", statePath, statusText, jobCount, dueCount, dueSuffix)
	}
	return fmt.Sprintf("schedule_state=%s status=%s jobs=%d due=%d%s next=%s in=%ds", statePath, statusText, jobCount, dueCount, dueSuffix, nextDueJob, nextDueInSeconds)
}

type scheduleJobStatus struct {
	ID               string    `json:"id"`
	Kind             string    `json:"kind"`
	Mode             string    `json:"mode"`
	TargetID         string    `json:"target_id"`
	When             string    `json:"when"`
	Enabled          bool      `json:"enabled"`
	Due              bool      `json:"due"`
	LastRun          time.Time `json:"last_run,omitempty"`
	NextDue          time.Time `json:"next_due,omitempty"`
	NextDueInSeconds int64     `json:"next_due_in_seconds"`
	OverdueSeconds   int64     `json:"overdue_seconds,omitempty"`
}

func scheduleStatusPayload(plan scheduler.Plan, state scheduler.State, loadErr error, now time.Time) map[string]interface{} {
	jobs := make([]scheduleJobStatus, 0, len(plan.Jobs))
	dueByID := map[string]bool{}
	dueJobs := []string{}
	dueCount := 0
	nextDueJob := ""
	var nextDue time.Time
	for _, job := range plan.Jobs {
		due := false
		if job.Enabled {
			due = scheduler.Due(job, state, now)
		}
		dueByID[job.ID] = due
		if due {
			dueCount++
			dueJobs = append(dueJobs, job.ID)
		}
		var jobNextDue time.Time
		if job.Enabled {
			jobNextDue = scheduler.NextDue(job, state, now)
		}
		if due {
			jobNextDue = now
		}
		if !jobNextDue.IsZero() && (nextDue.IsZero() || jobNextDue.Before(nextDue)) {
			nextDueJob = job.ID
			nextDue = jobNextDue
		}
		jobNextDueInSeconds := int64(jobNextDue.Sub(now).Seconds())
		if jobNextDueInSeconds < 0 {
			jobNextDueInSeconds = 0
		}
		item := scheduleJobStatus{
			ID:               job.ID,
			Kind:             job.Kind,
			Mode:             job.Mode,
			TargetID:         job.TargetID,
			When:             formatScheduleWhen(job),
			Enabled:          job.Enabled,
			Due:              due,
			LastRun:          state.LastRun[job.ID],
			NextDue:          jobNextDue,
			NextDueInSeconds: jobNextDueInSeconds,
		}
		if due {
			item.OverdueSeconds = scheduleOverdueSeconds(job, state.LastRun[job.ID], now)
		}
		jobs = append(jobs, item)
	}
	status := "healthy"
	if loadErr != nil {
		status = "error"
	} else if dueCount > 0 {
		status = "backlog"
	}
	nextDueInSeconds := int64(0)
	if !nextDue.IsZero() {
		nextDueInSeconds = int64(nextDue.Sub(now).Seconds())
		if nextDueInSeconds < 0 {
			nextDueInSeconds = 0
		}
	}
	return map[string]interface{}{
		"kind":                "meshclaw_schedule_status",
		"status":              status,
		"now":                 now,
		"plan":                plan,
		"state":               state,
		"jobs":                jobs,
		"due":                 dueByID,
		"due_jobs":            dueJobs,
		"due_count":           dueCount,
		"next_due_job":        nextDueJob,
		"next_due":            nextDue,
		"next_due_in_seconds": nextDueInSeconds,
		"error":               errString(loadErr),
	}
}

func scheduleOverdueSeconds(job scheduler.Job, lastRun time.Time, now time.Time) int64 {
	if lastRun.IsZero() {
		return 0
	}
	if strings.TrimSpace(job.Interval) == "" {
		return 0
	}
	interval, err := time.ParseDuration(job.Interval)
	if err != nil || interval <= 0 {
		return 0
	}
	dueAt := lastRun.Add(interval)
	if dueAt.After(now) {
		return 0
	}
	seconds := int64(now.Sub(dueAt).Seconds())
	if seconds < 0 {
		return 0
	}
	return seconds
}

func formatScheduleLastRun(last time.Time) string {
	if last.IsZero() {
		return "never"
	}
	return last.Local().Format("2006-01-02 15:04:05")
}

func formatScheduleNextDue(next time.Time, due bool) string {
	if due {
		return "now"
	}
	if next.IsZero() {
		return "unknown"
	}
	return next.Local().Format("2006-01-02 15:04:05")
}

func formatScheduleWhen(job scheduler.Job) string {
	if strings.TrimSpace(job.Interval) != "" {
		return job.Interval
	}
	if strings.TrimSpace(job.DailyAt) != "" {
		return "daily@" + job.DailyAt
	}
	if strings.TrimSpace(job.HourlyAt) != "" {
		return "hourly@" + job.HourlyAt
	}
	return "manual"
}

func parseScheduleRunOptions(args []string) (scheduler.RunOptions, error) {
	opts := scheduler.RunOptions{}
	for i := 0; i < len(args); i++ {
		switch args[i] {
		case "--target":
			i++
			if i >= len(args) {
				return opts, fmt.Errorf("--target requires a value")
			}
			opts.Target = args[i]
		case "--execute":
			opts.Execute = true
		case "--dry-run":
			opts.Execute = false
		default:
			return opts, fmt.Errorf("unknown schedule option: %s", args[i])
		}
	}
	return opts, nil
}

func printScheduleRunResult(result scheduler.RunResult) {
	fmt.Printf("schedule job=%s status=%s success=%t\n", result.Job.ID, result.Status, result.Success)
	if result.Summary != "" {
		fmt.Printf("summary: %s\n", result.Summary)
	}
	if preview := formatScheduleRunMessagePreview(result); preview != "" {
		fmt.Print(preview)
	}
	printEvidenceStoreStatus(result.Evidence, nil)
	if result.Send != nil {
		fmt.Printf("send target=%s executed=%t success=%t\n", result.Send.Target.ID, result.Send.Executed, result.Send.Success)
		if result.SendError != "" {
			fmt.Printf("send_error: %s\n", result.SendError)
		}
	}
}

func formatScheduleRunMessagePreview(result scheduler.RunResult) string {
	message := strings.TrimSpace(result.Message)
	if message == "" {
		return ""
	}
	var b strings.Builder
	b.WriteString("message:\n")
	for _, line := range strings.Split(message, "\n") {
		b.WriteString("  ")
		b.WriteString(line)
		b.WriteByte('\n')
	}
	return b.String()
}

type callDoctorResult struct {
	Kind               string    `json:"kind"`
	OK                 bool      `json:"ok"`
	Host               string    `json:"host,omitempty"`
	User               string    `json:"user,omitempty"`
	SignalRunning      bool      `json:"signal_running"`
	AccessibilityOK    bool      `json:"accessibility_ok"`
	AccessibilityError string    `json:"accessibility_error,omitempty"`
	UIRunnerURL        string    `json:"ui_runner_url,omitempty"`
	UIRunnerOK         bool      `json:"ui_runner_ok"`
	UIRunnerError      string    `json:"ui_runner_error,omitempty"`
	SwitchAudioBinary  string    `json:"switch_audio_binary,omitempty"`
	BlackHoleAvailable bool      `json:"blackhole_available"`
	InputDevices       []string  `json:"input_devices,omitempty"`
	OutputDevices      []string  `json:"output_devices,omitempty"`
	CurrentInput       string    `json:"current_input,omitempty"`
	CurrentOutput      string    `json:"current_output,omitempty"`
	CurrentSystem      string    `json:"current_system,omitempty"`
	SignalLog          string    `json:"signal_log,omitempty"`
	Problems           []string  `json:"problems,omitempty"`
	NextActions        []string  `json:"next_actions,omitempty"`
	CreatedAt          time.Time `json:"created_at"`
}

type argosUIRunnerHealth struct {
	OK                   bool     `json:"ok"`
	Error                string   `json:"error,omitempty"`
	AccessibilityTrusted bool     `json:"accessibility_trusted"`
	SignalRunning        bool     `json:"signal_running"`
	Problems             []string `json:"problems,omitempty"`
	NextActions          []string `json:"next_actions,omitempty"`
}

func assistantCallDoctor() callDoctorResult {
	host, _ := os.Hostname()
	user := os.Getenv("USER")
	result := callDoctorResult{
		Kind:              "meshclaw_signal_call_doctor",
		Host:              host,
		User:              user,
		SwitchAudioBinary: switchAudioBinary(),
		CreatedAt:         time.Now().UTC(),
	}
	result.SignalRunning = commandSucceeds("pgrep", "-x", "Signal")
	result.UIRunnerURL = firstNonEmpty(os.Getenv("MESHCLAW_ARGOS_UI_RUNNER"), "http://127.0.0.1:48292")
	runnerHealth, runnerErr := checkArgosUIRunner(result.UIRunnerURL)
	result.UIRunnerOK = runnerHealth.OK
	result.UIRunnerError = runnerErr
	if runnerErr == "" {
		result.AccessibilityOK = runnerHealth.AccessibilityTrusted
		if runnerHealth.SignalRunning {
			result.SignalRunning = true
		}
		if !runnerHealth.AccessibilityTrusted {
			result.AccessibilityError = "Argos UI Runner accessibility_trusted=false"
		}
	} else {
		result.AccessibilityOK, result.AccessibilityError = checkMacAccessibility()
	}
	result.InputDevices = audioDevices("input")
	result.OutputDevices = audioDevices("output")
	result.BlackHoleAvailable = containsExactString(result.InputDevices, "BlackHole 2ch") && containsExactString(result.OutputDevices, "BlackHole 2ch")
	probe := callAudioResult{}
	result.CurrentInput, _ = currentAudio("input", &probe)
	result.CurrentOutput, _ = currentAudio("output", &probe)
	result.CurrentSystem, _ = currentAudio("system", &probe)
	if home, err := os.UserHomeDir(); err == nil {
		logPath := filepath.Join(home, "Library", "Application Support", "Signal", "logs", "app.log")
		if st, err := os.Stat(logPath); err == nil && !st.IsDir() {
			result.SignalLog = logPath
		}
	}
	if !result.SignalRunning {
		result.Problems = append(result.Problems, "Signal Desktop is not running on this Mac user session.")
		result.NextActions = append(result.NextActions, "Open Signal Desktop on the Argos Mac before starting an automated call.")
	}
	if !result.AccessibilityOK {
		result.Problems = append(result.Problems, "macOS Accessibility permission is not available for Argos UI Runner, so MeshClaw cannot safely click Signal yet.")
		result.NextActions = append(result.NextActions, "Grant Accessibility permission to Argos UI Runner.app in System Settings.")
	}
	if !result.UIRunnerOK {
		result.Problems = append(result.Problems, "Argos UI Runner is not ready; Signal phone UI automation should not run.")
		result.NextActions = append(result.NextActions, "Start Argos UI Runner.app and check http://127.0.0.1:48292/health.")
	}
	if !result.BlackHoleAvailable {
		result.Problems = append(result.Problems, "BlackHole 2ch is not available as both input and output audio device.")
		result.NextActions = append(result.NextActions, "Install BlackHole 2ch and verify it appears in input/output audio device lists.")
	}
	if result.SignalLog == "" {
		result.Problems = append(result.Problems, "Signal app log was not found; accepted-call detection cannot run.")
		result.NextActions = append(result.NextActions, "Start Signal Desktop once and retry call-doctor from the same macOS user.")
	}
	result.OK = result.SignalRunning && result.AccessibilityOK && result.UIRunnerOK && result.BlackHoleAvailable && result.SignalLog != ""
	return result
}

func checkArgosUIRunner(baseURL string) (argosUIRunnerHealth, string) {
	client := http.Client{Timeout: 600 * time.Millisecond}
	resp, err := client.Get(strings.TrimRight(baseURL, "/") + "/health")
	if err != nil {
		return argosUIRunnerHealth{}, err.Error()
	}
	defer resp.Body.Close()
	var decoded argosUIRunnerHealth
	if err := json.NewDecoder(resp.Body).Decode(&decoded); err != nil {
		return argosUIRunnerHealth{}, err.Error()
	}
	if !decoded.OK {
		if decoded.Error != "" {
			return decoded, decoded.Error
		}
		if len(decoded.Problems) > 0 {
			return decoded, strings.Join(decoded.Problems, "; ")
		}
		return decoded, "Argos UI Runner returned ok=false"
	}
	return decoded, ""
}

func checkMacAccessibility() (bool, string) {
	script := `tell application "System Events"
	if not (exists process "Signal") then return "signal-not-running"
	tell process "Signal" to count windows
end tell`
	cmd := exec.Command("osascript", "-e", script)
	if out, err := cmd.CombinedOutput(); err != nil {
		return false, strings.TrimSpace(string(out))
	}
	return true, ""
}

func audioDevices(kind string) []string {
	out, err := exec.Command(switchAudioBinary(), "-a", "-t", kind).CombinedOutput()
	if err != nil {
		return nil
	}
	devices := []string{}
	for _, line := range strings.Split(string(out), "\n") {
		line = strings.TrimSpace(line)
		if line != "" {
			devices = append(devices, line)
		}
	}
	return devices
}

func commandSucceeds(name string, args ...string) bool {
	return exec.Command(name, args...).Run() == nil
}

func containsExactString(values []string, want string) bool {
	for _, value := range values {
		if value == want {
			return true
		}
	}
	return false
}

