func localAIBriefingDaemonUsage() string {
	return `usage: meshclaw daemon install local-ai-briefing [options] [--json]

Installs a staged LaunchAgent that invokes:
  meshclaw briefing local-ai

Options:
  --minute N       Run every hour at minute N, 0-59 (default 7)
  --target NAME    Signal target used by the Python briefing pipeline
  --model NAME     Local model name used by the Python briefing pipeline
  --script PATH    Override LOCAL_AI_BRIEFING_SCRIPT in the LaunchAgent
  --plist-path P   Write a staged plist to P instead of the active path
  --log-path P     Override StandardOutPath
  --error-log-path P
                  Override StandardErrorPath
  --workdir P      Override WorkingDirectory
  --send           Set BRIEF_SEND=1
  --no-send        Set BRIEF_SEND=0 for dry-run validation
`
}

func runSignalDispatcher(opts daemonInstallOptions) error {
	if opts.TimeoutSeconds <= 0 {
		opts.TimeoutSeconds = 8
	}
	if opts.IntervalSeconds <= 0 {
		opts.IntervalSeconds = 1
	}
	if opts.MaxMessages <= 0 {
		opts.MaxMessages = 20
	}
	if opts.MaxAgeSeconds <= 0 {
		opts.MaxAgeSeconds = 600
	}
	lastWarm := time.Time{}
	for {
		started := time.Now().UTC().Format(time.RFC3339)
		if opts.WarmInterval > 0 && (lastWarm.IsZero() || time.Since(lastWarm) >= time.Duration(opts.WarmInterval)*time.Second) {
			ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
			warm, err := messenger.PrewarmChatTargets(ctx)
			cancel()
			newsCtx, newsCancel := context.WithTimeout(context.Background(), 25*time.Second)
			newsBrief := assistantbrief.PreparedNews(newsCtx, assistantbrief.Options{Location: "Seoul", NewsLimit: 10})
			newsCancel()
			var newsRecord evidence.Record
			var newsStoreErr error
			if len(newsBrief.News) > 0 {
				newsRecord, newsStoreErr = evidence.Store("assistant-news", "assistant", fmt.Sprintf("items=%d warmup=signal-dispatcher", len(newsBrief.News)), newsBrief)
			}
			warmPayload := map[string]interface{}{
				"kind":    "meshclaw_signal_dispatch_warmup",
				"results": warm,
				"error":   errString(err),
				"news": map[string]interface{}{
					"items":       len(newsBrief.News),
					"errors":      newsBrief.Errors,
					"evidence":    newsRecord,
					"store_error": errString(newsStoreErr),
				},
			}
			if data, marshalErr := json.MarshalIndent(warmPayload, "", "  "); marshalErr == nil {
				fmt.Println(string(data))
			}
			lastWarm = time.Now()
		}
		fmt.Printf("[%s] signal dispatch tick timeout=%d max=%d max_age=%d warm_interval=%d\n", started, opts.TimeoutSeconds, opts.MaxMessages, opts.MaxAgeSeconds, opts.WarmInterval)
		result, err := messenger.ListenAll(messenger.ListenOptions{
			Timeout:       opts.TimeoutSeconds,
			MaxMessages:   opts.MaxMessages,
			MaxAgeSeconds: opts.MaxAgeSeconds,
			Execute:       opts.Execute,
		})
		payload := map[string]interface{}{"result": result, "error": errString(err)}
		data, marshalErr := json.MarshalIndent(payload, "", "  ")
		if marshalErr == nil {
			fmt.Println(string(data))
		}
		if err != nil {
			fmt.Printf("[%s] signal dispatch failed: %s\n", time.Now().UTC().Format(time.RFC3339), err)
		}
		time.Sleep(time.Duration(opts.IntervalSeconds) * time.Second)
	}
}

func installSignalDispatcher(opts daemonInstallOptions) (daemonActionResult, error) {
	defaults := defaultSignalDispatcherOptions()
	if opts.Binary == "" {
		opts.Binary = defaults.Binary
	}
	opts.Label = defaults.Label
	opts.PlistPath = defaults.PlistPath
	opts.LogPath = defaults.LogPath
	opts.ErrorLogPath = defaults.ErrorLogPath
	opts.WorkingDirectory = defaults.WorkingDirectory
	result := daemonActionResult{Kind: "meshclaw_daemon_signal_dispatcher", Action: "install", Service: "signal-dispatcher", Options: opts}
	if err := os.MkdirAll(filepath.Dir(opts.PlistPath), 0700); err != nil {
		return result, err
	}
	if err := os.MkdirAll(filepath.Dir(opts.LogPath), 0700); err != nil {
		return result, err
	}
	plist := signalDispatcherPlist(opts)
	changed, err := writeFileIfChanged(opts.PlistPath, []byte(plist), 0600)
	if err != nil {
		return result, err
	}
	result.Changed = changed
	result.Installed = true
	status, _ := signalDispatcherStatus(opts)
	result.Running = status.Running
	result.PID = status.PID
	result.LastStatus = status.LastStatus
	return result, nil
}

func installAgentCollector(opts daemonInstallOptions) (daemonActionResult, error) {
	defaults := defaultAgentCollectorOptions()
	if opts.Binary == "" {
		opts.Binary = defaults.Binary
	}
	if opts.IntervalSeconds <= 0 {
		opts.IntervalSeconds = defaults.IntervalSeconds
	}
	opts.Label = defaults.Label
	opts.PlistPath = defaults.PlistPath
	opts.LogPath = defaults.LogPath
	opts.ErrorLogPath = defaults.ErrorLogPath
	opts.WorkingDirectory = defaults.WorkingDirectory
	result := daemonActionResult{Kind: "meshclaw_daemon_agent_collector", Action: "install", Service: "agent-collector", Options: opts}
	if goruntime.GOOS == "linux" {
		return installAgentCollectorSystemd(opts, result)
	}
	if goruntime.GOOS != "darwin" {
		return result, fmt.Errorf("agent-collector daemon install supports macOS launchd and Linux systemd user units; use `meshclaw agent run` directly on this OS")
	}
	if err := os.MkdirAll(filepath.Dir(opts.PlistPath), 0700); err != nil {
		return result, err
	}
	if err := os.MkdirAll(filepath.Dir(opts.LogPath), 0700); err != nil {
		return result, err
	}
	changed, err := writeFileIfChanged(opts.PlistPath, []byte(agentCollectorPlist(opts)), 0600)
	if err != nil {
		return result, err
	}
	result.Changed = changed
	result.Installed = true
	status, _ := launchdStatus(opts, "meshclaw_daemon_agent_collector", "agent-collector")
	result.Running = status.Running
	result.PID = status.PID
	result.LastStatus = status.LastStatus
	return result, nil
}

