func manageSystemdUserService(action string, opts daemonInstallOptions, result daemonActionResult) (daemonActionResult, error) {
	unit := opts.Label + ".service"
	switch action {
	case "status":
		status, err := systemdUserStatus(opts, result.Kind, result.Service)
		status.Action = action
		return status, err
	case "start":
		_ = exec.Command("systemctl", "--user", "daemon-reload").Run()
		cmd := []string{"systemctl", "--user", "enable", "--now", unit}
		result.Commands = append(result.Commands, cmd)
		err := exec.Command(cmd[0], cmd[1:]...).Run()
		status, _ := systemdUserStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	case "stop":
		cmd := []string{"systemctl", "--user", "stop", unit}
		result.Commands = append(result.Commands, cmd)
		err := exec.Command(cmd[0], cmd[1:]...).Run()
		status, _ := systemdUserStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	case "restart":
		_ = exec.Command("systemctl", "--user", "daemon-reload").Run()
		cmd := []string{"systemctl", "--user", "restart", unit}
		result.Commands = append(result.Commands, cmd)
		err := exec.Command(cmd[0], cmd[1:]...).Run()
		status, _ := systemdUserStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	case "uninstall":
		_, _ = manageSystemdUserService("stop", opts, result)
		_ = exec.Command("systemctl", "--user", "disable", unit).Run()
		err := os.Remove(opts.PlistPath)
		if os.IsNotExist(err) {
			err = nil
		}
		_ = exec.Command("systemctl", "--user", "daemon-reload").Run()
		status, _ := systemdUserStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	default:
		return result, fmt.Errorf("unsupported daemon action %q", action)
	}
}

func manageLaunchdService(action string, opts daemonInstallOptions, result daemonActionResult) (daemonActionResult, error) {
	switch action {
	case "status":
		status, err := launchdStatus(opts, result.Kind, result.Service)
		status.Action = action
		return status, err
	case "start":
		status, _ := launchdStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		if status.Running {
			return result, nil
		}
		commands := launchdStartCommands(opts, status)
		result.Commands = append(result.Commands, commands...)
		err := runLaunchdCommands(commands)
		status, _ = launchdStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	case "stop":
		cmd := []string{"launchctl", "bootout", launchdServiceFor(opts.Label)}
		result.Commands = append(result.Commands, cmd)
		err := exec.Command(cmd[0], cmd[1:]...).Run()
		status, _ := launchdStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	case "restart":
		_, _ = manageLaunchdService("stop", opts, result)
		time.Sleep(300 * time.Millisecond)
		result, err := manageLaunchdService("start", opts, result)
		result.Action = "restart"
		return result, err
	case "uninstall":
		_, _ = manageLaunchdService("stop", opts, result)
		err := os.Remove(opts.PlistPath)
		if os.IsNotExist(err) {
			err = nil
		}
		status, _ := launchdStatus(opts, result.Kind, result.Service)
		result.Installed = status.Installed
		result.Running = status.Running
		result.PID = status.PID
		result.LastStatus = status.LastStatus
		return result, err
	default:
		return result, fmt.Errorf("unsupported daemon action %q", action)
	}
}

func launchdDomain() string {
	return fmt.Sprintf("gui/%d", os.Getuid())
}

func launchdStartCommands(opts daemonInstallOptions, status daemonActionResult) [][]string {
	if status.Running {
		return nil
	}
	service := launchdServiceFor(opts.Label)
	if status.PID != "" || status.LastStatus != "" {
		return [][]string{{"launchctl", "kickstart", "-k", service}}
	}
	return [][]string{
		{"launchctl", "bootstrap", launchdDomain(), opts.PlistPath},
		{"launchctl", "kickstart", "-k", service},
	}
}

func runLaunchdCommands(commands [][]string) error {
	var err error
	for _, cmd := range commands {
		if len(cmd) == 0 {
			continue
		}
		err = exec.Command(cmd[0], cmd[1:]...).Run()
	}
	return err
}

func launchdService() string {
	return launchdServiceFor(signalDispatcherLabel)
}

func launchdServiceFor(label string) string {
	return launchdDomain() + "/" + label
}

func signalDispatcherStatus(opts daemonInstallOptions) (daemonActionResult, error) {
	return launchdStatus(opts, "meshclaw_daemon_signal_dispatcher", "signal-dispatcher")
}

func launchdStatus(opts daemonInstallOptions, kind, service string) (daemonActionResult, error) {
	result := daemonActionResult{Kind: kind, Action: "status", Service: service, Options: opts}
	if st, err := os.Stat(opts.PlistPath); err == nil && !st.IsDir() {
		result.Installed = true
	}
	out, err := exec.Command("launchctl", "list").CombinedOutput()
	if err != nil {
		return result, err
	}
	for _, line := range strings.Split(string(out), "\n") {
		fields := strings.Fields(line)
		if len(fields) >= 3 && fields[len(fields)-1] == opts.Label {
			result.PID = fields[0]
			result.LastStatus = fields[1]
			result.Running = result.PID != "-"
			return result, nil
		}
	}
	return result, nil
}

func systemdUserStatus(opts daemonInstallOptions, kind, service string) (daemonActionResult, error) {
	result := daemonActionResult{Kind: kind, Action: "status", Service: service, Options: opts}
	if st, err := os.Stat(opts.PlistPath); err == nil && !st.IsDir() {
		result.Installed = true
	}
	unit := opts.Label + ".service"
	out, err := exec.Command("systemctl", "--user", "show", unit, "--property=ActiveState,SubState,MainPID,Result", "--no-page").CombinedOutput()
	if err != nil {
		result.LastStatus = strings.TrimSpace(string(out))
		return result, err
	}
	props := map[string]string{}
	for _, line := range strings.Split(string(out), "\n") {
		key, value, ok := strings.Cut(line, "=")
		if ok {
			props[key] = value
		}
	}
	result.Running = props["ActiveState"] == "active"
	if props["MainPID"] != "" && props["MainPID"] != "0" {
		result.PID = props["MainPID"]
	}
	result.LastStatus = strings.Trim(strings.Join([]string{props["ActiveState"], props["SubState"], props["Result"]}, "/"), "/")
	return result, nil
}

func systemdEscapeExec(args []string) string {
	escaped := make([]string, 0, len(args))
	for _, arg := range args {
		if strings.ContainsAny(arg, " \t\n\"'\\") {
			arg = "'" + strings.ReplaceAll(arg, "'", "'\\''") + "'"
		}
		escaped = append(escaped, arg)
	}
	return strings.Join(escaped, " ")
}

func systemdEscapeValue(value string) string {
	return strings.ReplaceAll(value, "\n", " ")
}

