func printWorkflowInspection(inspection runtimeflow.WorkflowInspection) {
	fmt.Printf("workflow=%s steps=%d recommended=%s\n", inspection.Info.Name, inspection.Info.StepCount, inspection.Info.RecommendedMode)
	fmt.Printf("description=%s\n", inspection.Info.Description)
	fmt.Printf("adapters=%s\n", strings.Join(inspection.RequiredAdapters, ","))
	fmt.Printf("nodes=%s\n", strings.Join(inspection.RequiredNodes, ","))
	fmt.Printf("capabilities=%d\n", len(inspection.CapabilitySnapshot))
	if len(inspection.CapabilityHints) > 0 {
		fmt.Println("capability_hints:")
		keys := make([]string, 0, len(inspection.CapabilityHints))
		for step := range inspection.CapabilityHints {
			keys = append(keys, step)
		}
		sort.Strings(keys)
		for _, step := range keys {
			fmt.Printf("- %s: %s\n", step, strings.Join(inspection.CapabilityHints[step], ","))
		}
	}
	if len(inspection.ApprovalGates) > 0 {
		fmt.Println("approval_gates:")
		for _, gate := range inspection.ApprovalGates {
			strong := ""
			if gate.Strong {
				strong = " strong=true"
			}
			fmt.Printf("- %s action=%s resource=%s%s\n  reason: %s\n", gate.Step, gate.Action, gate.Resource, strong, gate.Reason)
		}
	}
	fmt.Println("steps:")
	for _, step := range inspection.Steps {
		exec := "no"
		if step.WillExecuteInExecute {
			exec = "yes"
		}
		fmt.Printf("%02d. %s transport=%s node=%s execute=%s policy=%s\n", step.Index, step.Step.ID, step.Step.Transport, step.Step.Node, exec, step.Policy.Decision)
		if step.Step.Command != "" {
			fmt.Printf("    command: %s\n", truncate(step.Step.Command, 160))
		}
	}
}

func isRuntimeWorkflow(name string) bool {
	return runtimeflow.IsKnown(name)
}

func runWorkflow(args []string) error {
	name := args[0]
	mode := runtimeflow.DryRun
	jsonOut := false
	approvalsRef := ""
	selectedSteps := []string{}
	for i := 1; i < len(args); i++ {
		switch args[i] {
		case "--dry-run":
			mode = runtimeflow.DryRun
		case "--execute":
			mode = runtimeflow.Execute
		case "--json":
			jsonOut = true
		case "--approvals":
			i++
			if i >= len(args) {
				return fmt.Errorf("--approvals requires latest, a bundle directory, or execution.json")
			}
			approvalsRef = args[i]
		case "--step":
			i++
			if i >= len(args) {
				return fmt.Errorf("--step requires a workflow step id")
			}
			selectedSteps = append(selectedSteps, args[i])
		default:
			return fmt.Errorf("usage: meshclaw run <workflow> [--dry-run|--execute] [--approvals latest|bundle|execution.json] [--step id[,id]] [--json]")
		}
	}
	result, err := runtimeflow.RunSelectedWithApprovals(name, mode, approvalsRef, selectedSteps)
	if err != nil {
		return err
	}
	if jsonOut {
		return printJSON(result)
	}
	fmt.Printf("workflow=%s mode=%s success=%t\n", result.Workflow, result.Mode, result.Success)
	fmt.Printf("bundle=%s\n", result.BundleDir)
	fmt.Printf("plan=%s\n", result.PlanPath)
	fmt.Printf("execution=%s\n", result.ExecutionPath)
	fmt.Printf("steps=%s\n", result.StepsPath)
	fmt.Printf("capabilities=%s\n", result.CapabilitiesPath)
	fmt.Printf("adapters=%s\n", result.AdaptersPath)
	fmt.Printf("approvals=%s\n", result.ApprovalsPath)
	fmt.Printf("report=%s\n", result.ReportPath)
	fmt.Printf("summary total=%d skipped=%d approval_required=%d failed=%d retryable=%d\n",
		result.Summary.Total, result.Summary.Skipped, result.Summary.ApprovalRequired, result.Summary.Failed, result.Summary.Retryable)
	for _, step := range result.Steps {
		status := "ok"
		if !step.Success {
			status = "failed"
		} else if step.Skipped {
			status = "skipped"
		}
		fmt.Printf("- %s status=%s approval=%t node=%s\n", step.Step, status, step.ApprovalRequired, step.Node)
		if step.SkipReason != "" {
			fmt.Printf("  reason: %s\n", step.SkipReason)
		}
	}
	return nil
}

func runEvidence(args []string) error {
	if len(args) < 2 {
		return fmt.Errorf("usage: meshclaw run-evidence <host> <command>")
	}
	host := args[0]
	command := strings.Join(args[1:], " ")
	if _, ok := inventory.Find(host); !ok {
		return fmt.Errorf("unknown node: %s", host)
	}
	if err := policy.CheckCommand(command); err != nil {
		return err
	}
	result := runtime.NewRunner().RunEvidence(host, command)
	record, storeErr := evidence.Store("run-evidence", host, command, result)
	data, err := json.MarshalIndent(result, "", "  ")
	if err != nil {
		return err
	}
	fmt.Println(string(data))
	if storeErr != nil {
		fmt.Fprintf(os.Stderr, "evidence_store_error=%v\n", storeErr)
	} else {
		fmt.Printf("evidence=%s\n", record.StoredAt)
	}
	if !result.Success {
		return fmt.Errorf("execution failed on %s", host)
	}
	return nil
}

func jobStart(args []string) error {
	if len(args) < 2 {
		return fmt.Errorf("usage: meshclaw job-start <host> <command>")
	}
	host := args[0]
	command := strings.Join(args[1:], " ")
	if _, ok := inventory.Find(host); !ok {
		return fmt.Errorf("unknown node: %s", host)
	}
	if err := policy.CheckCommand(command); err != nil {
		return err
	}
	result, err := runtime.NewRunner().VSSHJSON("job-start", host, command)
	record, storeErr := evidence.Store("job-start", host, command, result)
	return printResultWithEvidence(result, record, storeErr, err)
}

func jobStatus(args []string) error {
	if len(args) != 2 {
		return fmt.Errorf("usage: meshclaw job-status <host> <id>")
	}
	return jobRead(args[0], args[1], "job-status")
}

func jobLogs(args []string) error {
	if len(args) < 2 || len(args) > 3 {
		return fmt.Errorf("usage: meshclaw job-logs <host> <id> [tail-bytes]")
	}
	params := []string{"job-logs", args[0], args[1]}
	if len(args) == 3 {
		params = append(params, args[2])
	}
	decision := policy.Evaluate(policy.Request{Subject: "operator", Action: "job_logs", Resource: "server", Context: args[1]})
	if decision.Decision != policy.Allow {
		return fmt.Errorf("policy blocked: %s", decision.Reason)
	}
	result, err := runtime.NewRunner().VSSHJSON(params...)
	record, storeErr := evidence.Store("job-logs", args[0], args[1], result)
	return printResultWithEvidence(result, record, storeErr, err)
}

func jobCancel(args []string) error {
	if len(args) != 2 {
		return fmt.Errorf("usage: meshclaw job-cancel <host> <id>")
	}
	decision := policy.Evaluate(policy.Request{Subject: "operator", Action: "job_cancel", Resource: "server", Context: args[1]})
	if decision.Decision != policy.Allow {
		return fmt.Errorf("policy blocked: %s", decision.Reason)
	}
	result, err := runtime.NewRunner().VSSHJSON("job-cancel", args[0], args[1])
	record, storeErr := evidence.Store("job-cancel", args[0], args[1], result)
	return printResultWithEvidence(result, record, storeErr, err)
}

func jobRead(host, id, command string) error {
	decision := policy.Evaluate(policy.Request{Subject: "operator", Action: "job_status", Resource: "server", Context: id})
	if decision.Decision != policy.Allow {
		return fmt.Errorf("policy blocked: %s", decision.Reason)
	}
	result, err := runtime.NewRunner().VSSHJSON(command, host, id)
	record, storeErr := evidence.Store(command, host, id, result)
	return printResultWithEvidence(result, record, storeErr, err)
}

func artifactCollect(args []string) error {
	if len(args) < 2 || len(args) > 3 {
		return fmt.Errorf("usage: meshclaw artifact-collect <host> <path> [max-bytes]")
	}
	host, path := args[0], args[1]
	decision := policy.Evaluate(policy.Request{Subject: "operator", Action: "artifact_collect", Resource: "server", Context: path})
	if decision.Decision != policy.Allow {
		return fmt.Errorf("policy blocked: %s", decision.Reason)
	}
	params := []string{"artifact-collect", host, path}
	if len(args) == 3 {
		params = append(params, args[2])
	}
	result, err := runtime.NewRunner().VSSHJSON(params...)
	record, storeErr := evidence.Store("artifact-collect", host, path, result)
	return printResultWithEvidence(result, record, storeErr, err)
}

func printResultWithEvidence(result interface{}, record evidence.Record, storeErr error, err error) error {
	if printErr := printJSON(map[string]interface{}{"result": result, "evidence": record, "store_error": errString(storeErr)}); printErr != nil {
		return printErr
	}
	return err
}

func runDoctor(args []string) error {
	jsonOut := wantsJSON(args)
	args = withoutJSONFlag(args)
	if len(args) == 0 {
		report := doctor.Self()
		if jsonOut {
			return printJSON(report)
		}
		fmt.Print(doctor.FormatSelf(report))
		if report.Status == "fail" {
			return fmt.Errorf("doctor failed")
		}
		return nil
	}
	if len(args) != 1 {
		return fmt.Errorf("usage: meshclaw doctor [host] [--json]")
	}
	fmt.Print(doctor.Check(args[0]))
	return nil
}

func runSetupCheck(args []string) error {
	jsonOut := wantsJSON(args)
	args = withoutJSONFlag(args)
	if len(args) > 0 && args[0] == "assistant" {
		if len(args) != 1 {
			return fmt.Errorf("usage: meshclaw setup assistant [--json]")
		}
		report := buildAssistantSetupReport()
		if jsonOut {
			return printJSON(report)
		}
		printAssistantSetupReport(report)
		if !report.Ready {
			return fmt.Errorf("assistant setup needs attention")
		}
		return nil
	}
	if len(args) > 0 && args[0] == "argos-runner" {
		report, err := setupArgosRunner(args[1:])
		if jsonOut {
			return printJSON(map[string]interface{}{"result": report, "error": errString(err)})
		}
		fmt.Printf("argos_runner_setup ok=%t config=%s runner_ok=%t\n", report.OK, report.ConfigPath, report.RunnerOK)
		for _, problem := range report.Problems {
			fmt.Printf("- %s\n", problem)
		}
		return err
	}
	if len(args) >= 1 && args[0] == "signal" {
		repair := false
		for _, arg := range args[1:] {
			switch arg {
			case "--repair":
				repair = true
			default:
				return fmt.Errorf("usage: meshclaw setup signal [--repair] [--json]")
			}
		}
		report := buildSignalSetupReport()
		var repairResult *signalSetupRepairResult
		if repair {
			repairResult = repairSignalSetup(report)
			report = buildSignalSetupReport()
		}
		if jsonOut {
			return printJSON(map[string]interface{}{"setup": report, "repair": repairResult})
		}
		printSignalSetupReport(report)
		if repairResult != nil {
			printSignalSetupRepair(*repairResult)
		}
		if !report.OK {
			return fmt.Errorf("signal setup check failed")
		}
		return nil
	}
	if len(args) != 0 {
		return fmt.Errorf("usage: meshclaw setup-check [--json] OR meshclaw setup assistant [--json] OR meshclaw setup signal [--json] OR meshclaw setup argos-runner [--signal-start-click x,y] [--signal-hangup-click x,y] [--json]")
	}
	report := doctor.Self()
	if jsonOut {
		return printJSON(report)
	}
	fmt.Print(doctor.FormatSelf(report))
	if report.Status == "fail" {
		return fmt.Errorf("setup check failed")
	}
	return nil
}

type assistantSetupReport struct {
	Kind              string                 `json:"kind"`
	GeneratedAt       time.Time              `json:"generated_at"`
	Profile           string                 `json:"profile"`
	Ready             bool                   `json:"ready"`
	Doctor            doctor.SelfReport      `json:"doctor"`
	Signal            signalSetupReport      `json:"signal"`
	ArgosRunner       argosRunnerSetupReport `json:"argos_runner"`
	Catalog           map[string]interface{} `json:"catalog"`
	FirstSuccessTasks []assistantFirstTask   `json:"first_success_tasks"`
	InstallCommands   []string               `json:"install_commands"`
	Problems          []string               `json:"problems,omitempty"`
	Warnings          []string               `json:"warnings,omitempty"`
	NextActions       []string               `json:"next_actions,omitempty"`
}

type assistantFirstTask struct {
	ID       string `json:"id"`
	Request  string `json:"request"`
	Expected string `json:"expected"`
	Surface  string `json:"surface"`
}

func buildAssistantSetupReport() assistantSetupReport {
	setup := doctor.Self()
	signal := buildSignalSetupReport()
	runner := signal.CallRunner
	if runner.Kind == "" {
		runner, _ = setupArgosRunner(nil)
	}
	report := assistantSetupReport{
		Kind:        "meshclaw_assistant_setup",
		GeneratedAt: time.Now().UTC(),
		Profile:     "one-machine-assistant",
		Doctor:      setup,
		Signal:      signal,
		ArgosRunner: runner,
		Catalog:     mcpCatalog("one-machine-assistant"),
		InstallCommands: []string{
			"meshclaw init",
			"meshclaw setup assistant --json",
			"meshclaw setup signal --json",
			"meshclaw setup argos-runner --json",
			"meshclaw mcp",
		},
		FirstSuccessTasks: []assistantFirstTask{
			{ID: "briefing", Request: "오늘 브리핑", Expected: "짧은 브리핑 또는 저장된 뉴스 문서", Surface: "Signal Argos"},
			{ID: "fleet", Request: "노드들 상태 확인해봐", Expected: "실제 MeshClaw inventory/monitor 기반 노드별 상태", Surface: "Signal Argos or MCP"},
			{ID: "research", Request: "브라우저로 이순신 검색해서 요약 리포트를 써줘", Expected: "검색 리포트 문서와 링크", Surface: "Signal Argos / meshclaw_argos_research"},
			{ID: "presentation", Request: "간단한 발표자료 만들어줘", Expected: "pptx, outline markdown, preview html, validation", Surface: "MCP"},
			{ID: "reminder", Request: "내일 오전 9시 리마인더 추가해줘", Expected: "승인 전 plan, 승인 후 실제 리마인더", Surface: "Signal Argos or MCP"},
		},
	}
	if setup.Status == "fail" {
		report.Problems = append(report.Problems, "MeshClaw doctor failed.")
		report.NextActions = append(report.NextActions, "Run `meshclaw doctor --json` and fix failed local prerequisites.")
	}
	if !signal.OK {
		report.Problems = append(report.Problems, signal.Problems...)
		report.NextActions = append(report.NextActions, signal.NextActions...)
		report.NextActions = append(report.NextActions, "Run `meshclaw setup signal --repair --json` only when you are ready to install/start local daemons.")
	}
	for _, warning := range signal.Warnings {
		text := warning.Message
		if warning.Next != "" {
			text += " Next: " + warning.Next
		}
		report.Warnings = append(report.Warnings, text)
	}
	if !runner.OK {
		report.Warnings = append(report.Warnings, "Argos UI Runner is not ready; macOS UI automation and Signal calls may need Accessibility setup.")
		report.NextActions = append(report.NextActions, "Run `meshclaw setup argos-runner --json` and grant macOS Accessibility permission if prompted.")
	}
	report.NextActions = dedupeStrings(report.NextActions)
	report.Warnings = dedupeStrings(report.Warnings)
	report.Problems = dedupeStrings(report.Problems)
	report.Ready = setup.Status != "fail" && signal.OK
	return report
}

func printAssistantSetupReport(report assistantSetupReport) {
	fmt.Printf("assistant_setup ready=%t profile=%s signal_ok=%t argos_runner_ok=%t doctor=%s\n", report.Ready, report.Profile, report.Signal.OK, report.ArgosRunner.OK, report.Doctor.Status)
	fmt.Println("first_success_tasks:")
	for _, task := range report.FirstSuccessTasks {
		fmt.Printf("- %s: %s -> %s (%s)\n", task.ID, task.Request, task.Expected, task.Surface)
	}
	if len(report.Problems) > 0 {
		fmt.Println("problems:")
		for _, problem := range report.Problems {
			fmt.Println("- " + problem)
		}
	}
	if len(report.Warnings) > 0 {
		fmt.Println("warnings:")
		for _, warning := range report.Warnings {
			fmt.Println("- " + warning)
		}
	}
	if len(report.NextActions) > 0 {
		fmt.Println("next_actions:")
		for _, action := range report.NextActions {
			fmt.Println("- " + action)
		}
	}
}

func dedupeStrings(values []string) []string {
	out := []string{}
	seen := map[string]bool{}
	for _, value := range values {
		value = strings.TrimSpace(value)
		if value == "" || seen[value] {
			continue
		}
		seen[value] = true
		out = append(out, value)
	}
	return out
}

type argosRunnerSetupReport struct {
	Kind              string      `json:"kind"`
	OK                bool        `json:"ok"`
	ConfigPath        string      `json:"config_path"`
	SignalStartClick  string      `json:"signal_start_click,omitempty"`
	SignalHangupClick string      `json:"signal_hangup_click,omitempty"`
	WroteConfig       bool        `json:"wrote_config"`
	RunnerURL         string      `json:"runner_url"`
	RunnerOK          bool        `json:"runner_ok"`
	RunnerHealth      interface{} `json:"runner_health,omitempty"`
	Problems          []string    `json:"problems,omitempty"`
	NextActions       []string    `json:"next_actions,omitempty"`
}

func setupArgosRunner(args []string) (argosRunnerSetupReport, error) {
	report := argosRunnerSetupReport{
		Kind:       "meshclaw_argos_runner_setup",
		ConfigPath: argosRunnerConfigPath(),
		RunnerURL:  firstNonEmpty(os.Getenv("MESHCLAW_ARGOS_UI_RUNNER"), "http://127.0.0.1:48292"),
	}
	for i := 0; i < len(args); i++ {
		switch args[i] {
		case "--signal-start-click":
			i++
			if i >= len(args) {
				return report, fmt.Errorf("--signal-start-click requires x,y")
			}
			if _, err := parseSignalClick(args[i]); err != nil {
				return report, err
			}
			report.SignalStartClick = strings.TrimSpace(args[i])
		case "--signal-hangup-click":
			i++
			if i >= len(args) {
				return report, fmt.Errorf("--signal-hangup-click requires x,y")
			}
			if _, err := parseSignalClick(args[i]); err != nil {
				return report, err
			}
			report.SignalHangupClick = strings.TrimSpace(args[i])
		case "--ui-runner":
			i++
			if i >= len(args) {
				return report, fmt.Errorf("--ui-runner requires a URL")
			}
			report.RunnerURL = strings.TrimRight(args[i], "/")
		default:
			return report, fmt.Errorf("unknown argos-runner setup option: %s", args[i])
		}
	}
	if report.SignalStartClick != "" || report.SignalHangupClick != "" {
		current := map[string]string{}
		if data, err := os.ReadFile(report.ConfigPath); err == nil {
			_ = json.Unmarshal(data, &current)
		}
		if report.SignalStartClick != "" {
			current["signal_start_click"] = report.SignalStartClick
		}
		if report.SignalHangupClick != "" {
			current["signal_hangup_click"] = report.SignalHangupClick
		}
		if err := os.MkdirAll(filepath.Dir(report.ConfigPath), 0700); err != nil {
			return report, err
		}
		data, err := json.MarshalIndent(current, "", "  ")
		if err != nil {
			return report, err
		}
		if err := os.WriteFile(report.ConfigPath, append(data, '\n'), 0600); err != nil {
			return report, err
		}
		report.WroteConfig = true
	}
	health, err := getArgosRunnerHealth(report.RunnerURL)
	report.RunnerHealth = health
	if err != nil {
		report.Problems = append(report.Problems, "Argos UI Runner health check failed: "+err.Error())
		report.NextActions = append(report.NextActions, "Open Argos UI Runner.app and grant Accessibility permission once.")
	} else if ok, _ := health["ok"].(bool); !ok {
		report.Problems = append(report.Problems, "Argos UI Runner is reachable but not ready.")
		report.NextActions = append(report.NextActions, "Check Accessibility permission and Signal Desktop state in the health payload.")
	} else {
		report.RunnerOK = true
	}
	report.OK = len(report.Problems) == 0
	if len(report.Problems) > 0 {
		return report, fmt.Errorf(strings.Join(report.Problems, "; "))
	}
	return report, nil
}

func argosRunnerConfigPath() string {
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return filepath.Join(".meshclaw", "argos-ui-runner.json")
	}
	return filepath.Join(home, ".meshclaw", "argos-ui-runner.json")
}

func getArgosRunnerHealth(baseURL string) (map[string]interface{}, error) {
	client := http.Client{Timeout: 2 * time.Second}
	resp, err := client.Get(strings.TrimRight(baseURL, "/") + "/health")
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	var decoded map[string]interface{}
	if err := json.NewDecoder(resp.Body).Decode(&decoded); err != nil {
		return decoded, err
	}
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return decoded, fmt.Errorf("health returned %s", resp.Status)
	}
	return decoded, nil
}

