var (
	installSignalDispatcherForSetup = installSignalDispatcher
	manageSignalDispatcherForSetup  = manageSignalDispatcher
	installScheduleRunnerForSetup   = installScheduleRunner
	manageScheduleRunnerForSetup    = manageScheduleRunner
	pauseSignalDispatcherForSetup   = pauseSignalDispatcherForRoomCheck
	signalSetupRoomsDoctor          = messenger.RoomsDoctor
)

func repairSignalSetup(report signalSetupReport) *signalSetupRepairResult {
	result := &signalSetupRepairResult{Kind: "meshclaw_signal_setup_repair", GeneratedAt: time.Now().UTC()}
	if !report.Daemon.Installed {
		action, err := installSignalDispatcherForSetup(defaultSignalDispatcherOptions())
		result.Actions = append(result.Actions, action)
		if err != nil {
			result.Problems = append(result.Problems, "failed to install Signal dispatcher: "+err.Error())
		} else {
			report.Daemon = action
		}
	}
	if report.Daemon.Installed && !report.Daemon.Running {
		action, err := manageSignalDispatcherForSetup("start")
		result.Actions = append(result.Actions, action)
		if err != nil {
			result.Problems = append(result.Problems, "failed to start Signal dispatcher: "+err.Error())
		}
	}
	if !report.ScheduleRunner.Installed {
		action, err := installScheduleRunnerForSetup(defaultScheduleRunnerOptions())
		result.Actions = append(result.Actions, action)
		if err != nil {
			result.Problems = append(result.Problems, "failed to install schedule runner: "+err.Error())
		} else {
			report.ScheduleRunner = action
		}
	}
	if report.ScheduleRunner.Installed && !report.ScheduleRunner.Running {
		action, err := manageScheduleRunnerForSetup("start")
		result.Actions = append(result.Actions, action)
		if err != nil {
			result.Problems = append(result.Problems, "failed to start schedule runner: "+err.Error())
		}
	}
	if !report.CallRunner.OK {
		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
		result.RunnerOpen = osauto.OpenUIRunnerApp(ctx)
		cancel()
		if !result.RunnerOpen.OK {
			result.Problems = append(result.Problems, "failed to open Argos UI Runner: "+firstNonEmpty(result.RunnerOpen.Error, result.RunnerOpen.Stderr, "unknown error"))
		} else {
			time.Sleep(1500 * time.Millisecond)
			runner, err := setupArgosRunner(nil)
			result.Runner = runner
			if err != nil {
				result.Problems = append(result.Problems, "Argos UI Runner still not ready after open: "+err.Error())
			}
		}
	}
	pause, resume := pauseSignalDispatcherForSetup(true)
	rooms, err := signalSetupRoomsDoctor(messenger.RoomDoctorOptions{Timeout: 25 * time.Second})
	resume()
	rooms.Dispatcher = pause
	result.Rooms = rooms
	if err != nil {
		result.Problems = append(result.Problems, "Signal room doctor failed: "+err.Error())
		result.NextActions = append(result.NextActions, "Stop the dispatcher manually and rerun meshclaw messenger rooms doctor --timeout 25 --json")
	}
	return result
}

func buildSignalSetupReport() signalSetupReport {
	store, targetErr := messenger.ListTargets()
	daemon, daemonErr := manageSignalDispatcher("status")
	scheduleRunner, scheduleErr := manageScheduleRunner("status")
	scheduleStatus := signalSetupScheduleStatus(time.Now().UTC())
	dataDoctor := signalSetupDataDoctorStatus(time.Now().UTC())
	report := signalSetupReport{
		Kind:           "meshclaw_signal_setup",
		SignalCLI:      signalCLIBinaryForSetup(),
		TargetsPath:    store.Path,
		Targets:        store.Targets,
		Daemon:         daemon,
		ScheduleRunner: scheduleRunner,
		ScheduleStatus: scheduleStatus,
		DataDoctor:     dataDoctor,
	}
	if report.SignalCLI == "" {
		report.Problems = append(report.Problems, "signal-cli was not found in PATH or common Homebrew locations.")
		report.NextActions = append(report.NextActions, "Install signal-cli, then link a Signal account on the controller Mac.")
	} else {
		if out, err := exec.Command(report.SignalCLI, "--version").CombinedOutput(); err == nil {
			report.SignalVersion = strings.TrimSpace(string(out))
		} else {
			report.Problems = append(report.Problems, "signal-cli exists but version check failed: "+strings.TrimSpace(string(out)))
		}
		report.Accounts = signalCLIAccounts(report.SignalCLI)
		if len(report.Accounts) == 0 {
			report.Problems = append(report.Problems, "no signal-cli account is linked for this macOS user.")
			report.NextActions = append(report.NextActions, "Run signal-cli account linking for the Argos/controller number.")
		}
	}
	if targetErr != nil {
		report.Problems = append(report.Problems, "messenger target config could not be read: "+targetErr.Error())
	}
	if len(store.Targets) == 0 {
		report.Problems = append(report.Problems, "no messenger targets are configured.")
		report.NextActions = append(report.NextActions, "Add targets with meshclaw messenger target-add, or import known Signal group IDs.")
	}
	if missing := missingScheduleTargets(store.Targets); len(missing) > 0 {
		report.Problems = append(report.Problems, "scheduled messenger targets are missing: "+strings.Join(missing, ", "))
		report.NextActions = append(report.NextActions, "Bind or add the missing schedule targets before enabling unattended delivery.")
	}
	if daemonErr != nil {
		report.Problems = append(report.Problems, "daemon status failed: "+daemonErr.Error())
	}
	if scheduleErr != nil {
		report.Problems = append(report.Problems, "schedule-runner status failed: "+scheduleErr.Error())
	}
	if scheduleStatus.Error != "" {
		report.Problems = append(report.Problems, "schedule state could not be read: "+scheduleStatus.Error)
	}
	if dataDoctor.Error != "" {
		report.Warnings = append(report.Warnings, signalSetupWarning{
			ID:        "data_doctor_unavailable",
			Severity:  "warning",
			AppliesTo: "data-doctor",
			Message:   "MeshClaw data doctor could not inspect local data growth.",
			Next:      "Run `meshclaw data doctor --json` and check the error.",
		})
	} else if !dataDoctor.OK {
		report.Warnings = append(report.Warnings, signalSetupWarning{
			ID:        "data_doctor_warnings",
			Severity:  "warning",
			AppliesTo: "data-doctor",
			Message:   fmt.Sprintf("MeshClaw data doctor found %d storage/retention warning(s).", len(dataDoctor.Warnings)),
			Next:      "Run `meshclaw data doctor` for details. Scheduled local-hygiene handles bounded temporary cleanup; evidence is archived, not blindly deleted.",
		})
	}
	if !daemon.Installed {
		report.Problems = append(report.Problems, "Signal dispatcher daemon is not installed.")
		report.NextActions = append(report.NextActions, "Run: meshclaw daemon install signal-dispatcher --execute")
	}
	if !daemon.Running {
		report.Problems = append(report.Problems, "Signal dispatcher daemon is not running.")
		report.NextActions = append(report.NextActions, "Run: meshclaw daemon start signal-dispatcher")
	}
	if !scheduleRunner.Installed {
		report.Problems = append(report.Problems, "schedule-runner daemon is not installed.")
		report.NextActions = append(report.NextActions, "Run: meshclaw daemon install schedule-runner --interval 900 --execute")
	}
	if warning, ok := scheduleRunnerFailureWarning(scheduleRunner); ok {
		report.Warnings = append(report.Warnings, warning)
	} else if warning, ok := scheduleRunnerIdleWarning(scheduleRunner); ok {
		report.Warnings = append(report.Warnings, warning)
	}
	if warning, ok := scheduleDueWarning(scheduleStatus); ok {
		report.Warnings = append(report.Warnings, warning)
	}
	for _, target := range store.Targets {
		if signalTargetNeedsModelCheck(target.Mode) && target.BaseURL != "" {
			report.ModelChecks = append(report.ModelChecks, checkSignalTargetModel(target))
		}
	}
	for _, check := range report.ModelChecks {
		if !check.OK {
			report.Problems = append(report.Problems, fmt.Sprintf("chat target %s model endpoint is not ready: %s", check.Target, check.Error))
		}
	}
	report.Warnings = append(report.Warnings, signalSetupUXWarnings(store.Targets)...)
	callRunner, _ := setupArgosRunner(nil)
	report.CallRunner = callRunner
	if !callRunner.OK {
		report.NextActions = append(report.NextActions, "Signal call automation is not ready; run meshclaw setup argos-runner --json for details.")
	}
	report.OK = len(report.Problems) == 0
	return report
}

func signalSetupDataDoctorStatus(now time.Time) signalSetupDataDoctor {
	report, err := datadoctor.Check(now)
	status := signalSetupDataDoctor{
		OK:       report.OK,
		Warnings: append([]string(nil), report.Warnings...),
	}
	if err != nil {
		status.OK = false
		status.Error = err.Error()
		return status
	}
	for _, loc := range report.Locations {
		switch loc.ID {
		case "public_argos":
			status.PublicFiles = loc.Files
		case "doctor":
			status.DoctorFiles = loc.Files
		case "logs":
			status.LogFiles = loc.Files
			status.LogBytes = loc.Bytes
		}
	}
	status.EvidenceFiles = report.Evidence.Files
	status.EvidenceBytes = report.Evidence.Bytes
	status.StateFilesChecked = len(report.StateFiles)
	for _, file := range report.StateFiles {
		if file.Exists && !file.OK {
			status.StateFilesInvalid++
			status.InvalidStateFiles = append(status.InvalidStateFiles, file.ID)
		}
	}
	return status
}

func signalSetupScheduleStatus(now time.Time) signalSetupSchedule {
	plan := scheduler.DefaultPlan()
	state, err := scheduler.LoadState()
	enabledJobs := 0
	for _, job := range plan.Jobs {
		if job.Enabled {
			enabledJobs++
		}
	}
	status := signalSetupSchedule{Status: "healthy", Jobs: enabledJobs, StatePath: state.Path, Error: errString(err)}
	if err != nil {
		status.Status = "error"
		return status
	}
	for _, job := range plan.Jobs {
		if !job.Enabled {
			continue
		}
		if scheduler.Due(job, state, now) {
			status.DueCount++
			status.DueJobs = append(status.DueJobs, job.ID)
			if status.NextDueJob == "" {
				status.NextDueJob = job.ID
				status.NextDue = now
			}
			continue
		}
		nextDue := scheduler.NextDue(job, state, now)
		if nextDue.IsZero() {
			continue
		}
		if status.NextDue.IsZero() || nextDue.Before(status.NextDue) {
			status.NextDueJob = job.ID
			status.NextDue = nextDue
		}
	}
	if status.DueCount > 0 {
		status.Status = "backlog"
	}
	if !status.NextDue.IsZero() {
		status.NextDueInSeconds = int64(status.NextDue.Sub(now).Seconds())
		if status.NextDueInSeconds < 0 {
			status.NextDueInSeconds = 0
		}
	}
	return status
}

func missingScheduleTargets(targets []messenger.Target) []string {
	known := map[string]bool{}
	for _, target := range targets {
		if strings.TrimSpace(target.ID) != "" {
			known[target.ID] = true
		}
	}
	missingSet := map[string]bool{}
	for _, job := range scheduler.DefaultPlan().Jobs {
		if !job.Enabled || strings.TrimSpace(job.TargetID) == "" {
			continue
		}
		if !known[job.TargetID] {
			missingSet[job.TargetID] = true
		}
	}
	missing := make([]string, 0, len(missingSet))
	for target := range missingSet {
		missing = append(missing, target)
	}
	sort.Strings(missing)
	return missing
}

func scheduleDueWarning(status signalSetupSchedule) (signalSetupWarning, bool) {
	if status.Error != "" || status.DueCount <= 0 {
		return signalSetupWarning{}, false
	}
	return signalSetupWarning{
		ID:        "schedule_due",
		Severity:  "warning",
		AppliesTo: "schedule-runner",
		Message:   fmt.Sprintf("%d scheduled job(s) are due. The schedule-runner should clear this on its next launchd run.", status.DueCount),
		Next:      "Run `meshclaw schedule run-due --execute` for an immediate catch-up, or check schedule-runner logs if due_count stays above 0.",
	}, true
}

func scheduleRunnerFailureWarning(scheduleRunner daemonActionResult) (signalSetupWarning, bool) {
	lastStatus := strings.TrimSpace(scheduleRunner.LastStatus)
	if !scheduleRunner.Installed || scheduleRunner.Running || lastStatus == "" || lastStatus == "-" || lastStatus == "0" {
		return signalSetupWarning{}, false
	}
	return signalSetupWarning{
		ID:        "schedule_runner_last_failed",
		Severity:  "warning",
		AppliesTo: "schedule-runner",
		Message:   fmt.Sprintf("schedule-runner is not running and its last launchd exit status was %s.", lastStatus),
		Next:      "Check ~/.meshclaw/logs/schedule-runner.err.log, then run `meshclaw daemon restart schedule-runner` or `meshclaw schedule run-due --execute`.",
	}, true
}

func scheduleRunnerIdleWarning(scheduleRunner daemonActionResult) (signalSetupWarning, bool) {
	if !scheduleRunner.Installed || scheduleRunner.Running {
		return signalSetupWarning{}, false
	}
	return signalSetupWarning{
		ID:        "schedule_runner_idle",
		Severity:  "info",
		AppliesTo: "schedule-runner",
		Message:   "schedule-runner is installed but not currently running. This is normal between 15-minute launchd runs.",
		Next:      "Use `meshclaw schedule status` to confirm due_count returns to 0 after launchd runs.",
	}, true
}

func signalTargetNeedsModelCheck(mode string) bool {
	switch mode {
	case "chat", "briefing", "assistant":
		return true
	default:
		return false
	}
}

func signalSetupUXWarnings(targets []messenger.Target) []signalSetupWarning {
	if len(targets) == 0 {
		return nil
	}
	warnings := []signalSetupWarning{{
		ID:        "signal_name_not_verified_ui",
		Severity:  "info",
		AppliesTo: "signal",
		Message:   "Signal may show 'name not verified' for phone-number or group-name identity even when the safety number is verified. This is a Signal contact/name trust UI state, not a MeshClaw target or encryption failure.",
		Next:      "For clean UI, add only the Argos contact to the device address book or use Signal's contact/profile trust flow. For Guard rooms, verify the Argos safety number before entering secrets.",
	}}
	for _, target := range targets {
		if target.Mode == "guard" {
			warnings = append(warnings, signalSetupWarning{
				ID:        "guard_requires_safety_number",
				Severity:  "warning",
				AppliesTo: target.ID,
				Message:   "Guard targets can receive raw secret ingress before storage. The human should verify the Argos safety number before using this room for passwords or tokens.",
				Next:      "Open the Signal room, inspect Argos safety number, compare or scan it, and confirm the room shows the verified safety-number state.",
			})
			break
		}
	}
	return warnings
}

func signalDispatchHealth(globalMode string, runtimeRequired bool, now time.Time) (signalDispatchHealthResult, error) {
	if strings.TrimSpace(globalMode) == "" {
		globalMode = "assistant"
	}
	dispatcherOpts := defaultSignalDispatcherOptions()
	dispatcher, dispatcherErr := signalDispatcherStatus(dispatcherOpts)
	scheduleRunner, scheduleErr := manageScheduleRunner("status")
	scheduleStatus := signalSetupScheduleStatus(now)
	selfTest, selfTestErr := messenger.DispatchSelfTest(globalMode)
	logs := readSignalDispatchLogHealth(dispatcherOpts.LogPath, dispatcherOpts.ErrorLogPath, now)
	binary := currentExecutablePath()
	result := signalDispatchHealthResult{
		Kind:             "meshclaw_signal_dispatch_health",
		GeneratedAt:      now,
		GlobalMode:       globalMode,
		RuntimeRequired:  runtimeRequired,
		Binary:           binary,
		BinarySHA256:     fileSHA256Hex(binary),
		Dispatcher:       dispatcher,
		ScheduleRunner:   scheduleRunner,
		ScheduleStatus:   scheduleStatus,
		DispatchSelfTest: selfTest,
		Logs:             logs,
	}
	if dispatcherErr != nil {
		result.Problems = append(result.Problems, "Signal dispatcher status failed: "+dispatcherErr.Error())
	}
	if !dispatcher.Installed {
		message := "Signal dispatcher LaunchAgent is not installed on this Mac."
		if runtimeRequired {
			result.Problems = append(result.Problems, message)
			result.NextActions = append(result.NextActions, "Run `meshclaw daemon install signal-dispatcher --execute` on the Signal runtime Mac.")
		} else {
			result.Warnings = append(result.Warnings, message+" This is expected on non-runtime Macs; Mac mini remains the Signal sender.")
			result.NextActions = append(result.NextActions, "For runtime validation, run this command on Mac mini with `--runtime-required`.")
		}
	}
	if dispatcher.Installed && !dispatcher.Running {
		result.Problems = append(result.Problems, "Signal dispatcher LaunchAgent is installed but not running.")
		result.NextActions = append(result.NextActions, "Run `meshclaw daemon restart signal-dispatcher` on the Signal runtime Mac.")
	}
	if scheduleErr != nil {
		result.Warnings = append(result.Warnings, "schedule-runner status failed: "+scheduleErr.Error())
	}
	if !scheduleRunner.Installed {
		result.Warnings = append(result.Warnings, "schedule-runner LaunchAgent is not installed.")
		result.NextActions = append(result.NextActions, "Run `meshclaw daemon install schedule-runner --interval 900 --execute` if scheduled reports should run on this Mac.")
	}
	if warning, ok := scheduleRunnerFailureWarning(scheduleRunner); ok {
		result.Warnings = append(result.Warnings, warning.Message)
		result.NextActions = append(result.NextActions, warning.Next)
	}
	if scheduleStatus.Error != "" {
		result.Problems = append(result.Problems, "schedule state could not be read: "+scheduleStatus.Error)
	} else if warning, ok := scheduleDueWarning(scheduleStatus); ok {
		result.Warnings = append(result.Warnings, warning.Message)
		result.NextActions = append(result.NextActions, warning.Next)
	}
	if selfTestErr != nil {
		result.Problems = append(result.Problems, "Signal dispatch self-test failed: "+selfTestErr.Error())
	}
	if !selfTest.OK {
		result.Problems = append(result.Problems, selfTest.Problems...)
		result.NextActions = append(result.NextActions, selfTest.NextActions...)
	}
	result.Warnings = append(result.Warnings, selfTest.Warnings...)
	if logs.Error != "" {
		result.Warnings = append(result.Warnings, "Signal dispatcher logs could not be inspected: "+logs.Error)
	}
	if len(logs.RecentSuspiciousLines) > 0 {
		result.Warnings = append(result.Warnings, fmt.Sprintf("Signal dispatcher error log has %d recent suspicious line(s).", len(logs.RecentSuspiciousLines)))
		result.NextActions = append(result.NextActions, "Check "+logs.ErrorLogPath+" before assuming the dispatcher is stable.")
	}
	result.Warnings = compactUniqueStrings(result.Warnings)
	result.Problems = compactUniqueStrings(result.Problems)
	result.NextActions = compactUniqueStrings(result.NextActions)
	result.OK = len(result.Problems) == 0
	if result.OK && len(result.Warnings) == 0 {
		result.Status = "healthy"
	} else if result.OK {
		result.Status = "warning"
	} else {
		result.Status = "problem"
	}
	if selfTestErr != nil {
		return result, selfTestErr
	}
	return result, dispatcherErr
}

func readSignalDispatchLogHealth(logPath, errorLogPath string, now time.Time) signalDispatchLogHealth {
	health := signalDispatchLogHealth{LogPath: logPath, ErrorLogPath: errorLogPath}
	info, err := os.Stat(errorLogPath)
	if os.IsNotExist(err) {
		return health
	}
	if err != nil {
		health.Error = err.Error()
		return health
	}
	health.ErrorLogModified = info.ModTime().UTC()
	health.ErrorLogAgeSeconds = int64(now.Sub(info.ModTime()).Seconds())
	if health.ErrorLogAgeSeconds < 0 {
		health.ErrorLogAgeSeconds = 0
	}
	if now.Sub(info.ModTime()) > time.Hour {
		return health
	}
	data, err := readTailBytes(errorLogPath, 64*1024)
	if err != nil {
		health.Error = err.Error()
		return health
	}
	for _, line := range strings.Split(string(data), "\n") {
		line = strings.TrimSpace(line)
		if line == "" || !signalDispatchLogLineSuspicious(line) {
			continue
		}
		health.RecentSuspiciousLines = append(health.RecentSuspiciousLines, compactLogLine(line, 220))
		if len(health.RecentSuspiciousLines) >= 8 {
			break
		}
	}
	return health
}

func readTailBytes(path string, maxBytes int64) ([]byte, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	info, err := file.Stat()
	if err != nil {
		return nil, err
	}
	offset := int64(0)
	if info.Size() > maxBytes {
		offset = info.Size() - maxBytes
	}
	if _, err := file.Seek(offset, io.SeekStart); err != nil {
		return nil, err
	}
	return io.ReadAll(file)
}

func signalDispatchLogLineSuspicious(line string) bool {
	lower := strings.ToLower(line)
	for _, needle := range []string{"error", "failed", "failure", "panic", "unknown token", "disconnect", "refused", "denied", "timeout", "timed out"} {
		if strings.Contains(lower, needle) {
			return true
		}
	}
	return false
}

func compactLogLine(line string, maxRunes int) string {
	line = strings.Join(strings.Fields(line), " ")
	runes := []rune(line)
	if len(runes) <= maxRunes {
		return line
	}
	return string(runes[:maxRunes]) + "..."
}

func fileSHA256Hex(path string) string {
	if strings.TrimSpace(path) == "" {
		return ""
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return ""
	}
	sum := sha256.Sum256(data)
	return fmt.Sprintf("%x", sum[:])
}

func compactUniqueStrings(values []string) []string {
	seen := map[string]bool{}
	out := []string{}
	for _, value := range values {
		value = strings.TrimSpace(value)
		if value == "" || seen[value] {
			continue
		}
		seen[value] = true
		out = append(out, value)
	}
	return out
}

func signalCLIBinaryForSetup() string {
	for _, path := range []string{strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_CLI")), "/opt/homebrew/bin/signal-cli", "/usr/local/bin/signal-cli", "signal-cli"} {
		if path == "" {
			continue
		}
		if strings.Contains(path, "/") {
			if st, err := os.Stat(path); err == nil && !st.IsDir() {
				return path
			}
			continue
		}
		if found, err := exec.LookPath(path); err == nil {
			return found
		}
	}
	return ""
}

func signalCLIAccounts(binary string) []string {
	out, err := exec.Command(binary, "listAccounts").CombinedOutput()
	if err != nil {
		return nil
	}
	accounts := []string{}
	for _, line := range strings.Split(string(out), "\n") {
		line = strings.TrimSpace(line)
		if strings.HasPrefix(line, "Number:") {
			accounts = append(accounts, line)
		}
	}
	return accounts
}

func checkSignalTargetModel(target messenger.Target) signalSetupModelCheck {
	check := signalSetupModelCheck{Target: target.ID, Model: target.Model, BaseURL: target.BaseURL}
	client := http.Client{Timeout: 2 * time.Second}
	u := strings.TrimRight(target.BaseURL, "/")
	if strings.HasSuffix(u, "/v1") {
		u = strings.TrimSuffix(u, "/v1") + "/api/tags"
	} else {
		u += "/api/tags"
	}
	resp, err := client.Get(u)
	if err != nil {
		check.Error = err.Error()
		return check
	}
	defer resp.Body.Close()
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		check.Error = resp.Status
		return check
	}
	check.OK = true
	return check
}

func printSignalSetupReport(report signalSetupReport) {
	fmt.Printf("signal_setup ok=%t signal_cli=%s version=%s accounts=%d targets=%d daemon_running=%t schedule_runner_installed=%t schedule_runner_running=%t schedule_due=%d call_runner_ok=%t\n",
		report.OK, report.SignalCLI, report.SignalVersion, len(report.Accounts), len(report.Targets), report.Daemon.Running, report.ScheduleRunner.Installed, report.ScheduleRunner.Running, report.ScheduleStatus.DueCount, report.CallRunner.OK)
	if report.ScheduleStatus.StatePath != "" {
		fmt.Printf("schedule_state=%s status=%s jobs=%d due=%d\n", report.ScheduleStatus.StatePath, report.ScheduleStatus.Status, report.ScheduleStatus.Jobs, report.ScheduleStatus.DueCount)
		if len(report.ScheduleStatus.DueJobs) > 0 {
			fmt.Printf("schedule_due_jobs=%s\n", strings.Join(report.ScheduleStatus.DueJobs, ","))
		}
		if report.ScheduleStatus.NextDueJob != "" {
			fmt.Printf("schedule_next_due=%s job=%s in=%ds\n", formatScheduleNextDue(report.ScheduleStatus.NextDue, report.ScheduleStatus.NextDueInSeconds == 0), report.ScheduleStatus.NextDueJob, report.ScheduleStatus.NextDueInSeconds)
		}
	}
	if report.DataDoctor.Error != "" {
		fmt.Printf("data_doctor=error %s\n", report.DataDoctor.Error)
	} else {
		fmt.Printf("data_doctor=ok:%t public=%d doctor=%d evidence=%d logs=%s state_files=%d invalid_state=%d warnings=%d\n",
			report.DataDoctor.OK,
			report.DataDoctor.PublicFiles,
			report.DataDoctor.DoctorFiles,
			report.DataDoctor.EvidenceFiles,
			humanBytes(report.DataDoctor.LogBytes),
			report.DataDoctor.StateFilesChecked,
			report.DataDoctor.StateFilesInvalid,
			len(report.DataDoctor.Warnings),
		)
	}
	fmt.Printf("targets=%s\n", report.TargetsPath)
	for _, target := range report.Targets {
		destination := target.Recipient
		if destination == "" {
			destination = "group:" + target.GroupID
		}
		fmt.Printf("- %s mode=%s destination=%s model=%s base_url=%s\n", target.ID, target.Mode, destination, target.Model, target.BaseURL)
	}
	for _, check := range report.ModelChecks {
		status := "ok"
		if !check.OK {
			status = "fail: " + check.Error
		}
		fmt.Printf("- model target=%s model=%s base_url=%s status=%s\n", check.Target, check.Model, check.BaseURL, status)
	}
	if len(report.Warnings) > 0 {
		fmt.Println("warnings:")
		for _, warning := range report.Warnings {
			appliesTo := warning.AppliesTo
			if appliesTo == "" {
				appliesTo = "setup"
			}
			fmt.Printf("- [%s] %s: %s", warning.Severity, appliesTo, warning.Message)
			if warning.Next != "" {
				fmt.Printf(" next=%s", warning.Next)
			}
			fmt.Println()
		}
	}
	if len(report.Problems) > 0 {
		fmt.Println("problems:")
		for _, problem := range report.Problems {
			fmt.Printf("- %s\n", problem)
		}
	}
	if len(report.NextActions) > 0 {
		fmt.Println("next_actions:")
		for _, action := range report.NextActions {
			fmt.Printf("- %s\n", action)
		}
	}
}

func printSignalSetupRepair(result signalSetupRepairResult) {
	fmt.Printf("signal_setup_repair actions=%d problems=%d\n", len(result.Actions), len(result.Problems))
	for _, action := range result.Actions {
		fmt.Printf("- daemon action=%s running=%t pid=%s\n", action.Action, action.Running, action.PID)
	}
	if result.RunnerOpen.Kind != "" {
		fmt.Printf("- runner open ok=%t app=%s\n", result.RunnerOpen.OK, result.RunnerOpen.App)
	}
	if result.Runner.Kind != "" {
		fmt.Printf("- runner health ok=%t url=%s\n", result.Runner.OK, result.Runner.RunnerURL)
	}
	printStringList("repair_problems", result.Problems)
	printStringList("repair_next_actions", result.NextActions)
}

