func guardVaultPut(args []string) error {
	jsonOut := wantsJSON(args)
	args = withoutJSONFlag(args)
	if len(args) < 2 {
		return fmt.Errorf("usage: meshclaw guard-vault-put <scope> <name> [kind] [description] [--backend local|keychain|pass] < secret.txt [--json]")
	}
	backend := ""
	clean := make([]string, 0, len(args))
	for i := 0; i < len(args); i++ {
		if args[i] == "--backend" {
			i++
			if i >= len(args) {
				return fmt.Errorf("--backend requires a value")
			}
			backend = args[i]
			continue
		}
		clean = append(clean, args[i])
	}
	args = clean
	if len(args) < 2 {
		return fmt.Errorf("usage: meshclaw guard-vault-put <scope> <name> [kind] [description] [--backend local|keychain|pass] < secret.txt [--json]")
	}
	value, err := io.ReadAll(os.Stdin)
	if err != nil {
		return err
	}
	kind := ""
	description := ""
	if len(args) >= 3 {
		kind = args[2]
	}
	if len(args) >= 4 {
		description = strings.Join(args[3:], " ")
	}
	entry, err := guardvault.Put(guardvault.PutOptions{
		Scope:       args[0],
		Name:        args[1],
		Kind:        kind,
		Description: description,
		Backend:     backend,
		Value:       value,
	})
	if err != nil {
		return err
	}
	record, storeErr := evidence.Store("guard-vault-put", entry.Scope, "stored "+entry.Handle, entry)
	if jsonOut {
		return printJSON(map[string]interface{}{"entry": entry, "evidence": record, "store_error": errString(storeErr)})
	}
	fmt.Printf("stored %s fingerprint=%s\n", entry.Handle, entry.Fingerprint)
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

func guardVaultLinkKeychain(args []string) error {
	jsonOut := wantsJSON(args)
	filtered := withoutJSONFlag(args)
	if len(filtered) < 2 {
		return fmt.Errorf("usage: meshclaw guard-vault-link-keychain <scope> <name> --service service --account account [kind] [description] [--json]")
	}
	req := guardvault.LinkKeychainOptions{Scope: filtered[0], Name: filtered[1], Kind: "secret", Description: "Linked Apple Keychain item"}
	positional := []string{}
	for i := 2; i < len(filtered); i++ {
		switch filtered[i] {
		case "--service":
			i++
			if i >= len(filtered) {
				return fmt.Errorf("--service requires a value")
			}
			req.Service = filtered[i]
		case "--account":
			i++
			if i >= len(filtered) {
				return fmt.Errorf("--account requires a value")
			}
			req.Account = filtered[i]
		default:
			positional = append(positional, filtered[i])
		}
	}
	if len(positional) > 0 {
		req.Kind = positional[0]
	}
	if len(positional) > 1 {
		req.Description = strings.Join(positional[1:], " ")
	}
	entry, err := guardvault.LinkKeychain(req)
	record, storeErr := evidence.Store("guard-vault-link-keychain", entry.Scope, "linked "+entry.Handle, entry)
	if jsonOut {
		return printJSON(map[string]interface{}{"entry": entry, "evidence": record, "store_error": errString(storeErr), "error": errString(err)})
	}
	if err != nil {
		return err
	}
	fmt.Printf("guard_vault_linked handle=%s backend=%s service=%s account=%s\n", entry.Handle, entry.Backend, entry.KeychainService, entry.KeychainAccount)
	printEvidenceStoreStatus(record, storeErr)
	return nil
}

